    def compute_dynamic_tops(page_size: int, num_levels: int) -> list[int]:
        """Distribute ``page_size`` budget across ``num_levels`` levels of
        nested ``$expand`` ``$top`` values so the cross-product
        ``$top_0 × $top_1 × … × $top_{N-1}`` stays within ``page_size`` —
        the maximum number of leaf rows a single HTTP response can carry.

        Triangular-weighted distribution: level ``i`` (0-indexed from
        the top) gets weight ``N - i`` out of ``N(N+1)/2`` total weight.
        The top URL gets the largest share since it's the outermost
        multiplier; deeper levels get progressively less. Each level is
        raised to ``MIN_DYNAMIC_TOP`` (5) so the page is never smaller
        than a useful chunk.

        When the geometric distribution would put a deep level below the
        minimum, that level is clamped to ``MIN_DYNAMIC_TOP`` and the
        *remaining* budget for upper levels is divided down accordingly,
        so the cross-product stays at-or-under ``page_size`` whenever
        that's mathematically possible.

        Examples with ``page_size = 1000``:

        * ``N=1`` (flat read): ``[1000]``
        * ``N=2`` (e.g. ``Parents__Children``): ``[100, 10]``
          → ``100 × 10 = 1000``
        * ``N=3``: ``[34, 5, 5]`` → ``850`` (under budget; bottom clamped)
        * ``N=4``: ``[8, 5, 5, 5]`` → ``1000`` exactly

        If the chain is so deep that ``MIN_DYNAMIC_TOP ** num_levels``
        already exceeds ``page_size`` (e.g. ``5**5 = 3125`` for
        ``page_size=1000``, ``N=5``), every level falls to the minimum and
        the cross-product unavoidably exceeds the budget — raise
        ``page_size`` to restore the cap, or use ``expand_contained=false``
        so the chain becomes N+1 fetches instead of a single big request.
        """
        if num_levels <= 0:
            return []
        tops = [MIN_DYNAMIC_TOP] * num_levels
        # ``remaining`` counts the *upper* levels still being distributed.
        # Anything at index ``>= remaining`` is already pinned to the minimum.
        remaining = num_levels
        budget = page_size
        while remaining > 0:
            if remaining == 1:
                tops[0] = max(MIN_DYNAMIC_TOP, int(budget))
                break
            total_weight = remaining * (remaining + 1) // 2
            candidate: list[int] = []
            any_below_min = False
            for i in range(remaining):
                weight = remaining - i
                exact = budget ** (weight / total_weight)
                # Floating-point quirk: ``1000 ** (2/3)`` is ``99.999…`` in
                # IEEE-754. Snap to the rounded integer when it's effectively
                # exact, otherwise floor so we never overshoot the budget.
                rounded = round(exact)
                value = rounded if math.isclose(exact, rounded, rel_tol=1e-9) else math.floor(exact)
                if value < MIN_DYNAMIC_TOP:
                    any_below_min = True
                candidate.append(int(value))
            if not any_below_min:
                for i, v in enumerate(candidate):
                    tops[i] = max(MIN_DYNAMIC_TOP, v)
                break
            # Bottom of the active range can't honour the geometric share
            # without dropping below ``MIN_DYNAMIC_TOP``. Pin it to the minimum
            # and redistribute what's left of the budget across the upper levels.
            tops[remaining - 1] = MIN_DYNAMIC_TOP
            budget = max(1, budget // MIN_DYNAMIC_TOP)
            remaining -= 1
        return tops


    def compute_expand_tops_for_root(page_size: int, num_segments: int, root_level: int) -> list[int]:
        """Per-level ``$top`` for an ``$expand`` request rooted at ``root_level``.

        Only the levels from ``root_level`` to the leaf are collections that
        multiply into the response cross-product; the ancestors ``0..root_level-1``
        are addressed by key in the request path (e.g. ``Instances(6)/Projects(7)/
        WorkPackageDetails?...``), so they carry no ``$top`` and must NOT eat into
        the ``page_size`` budget. Distributing across only the collection levels is
        what lets a continuation rooted deep in the chain use a sensible ``$top``
        (e.g. ``[100, 10]`` for the last two levels) instead of the whole-chain
        floor (``[…, 5, 5]``).

        Returns a full-length list so callers keep indexing by absolute segment
        level; entries below ``root_level`` are placeholders that are never read
        (those levels carry a key, not a ``$top``)."""
        return [0] * root_level + compute_dynamic_tops(page_size, num_segments - root_level)


    def join_url(base: str, suffix: str) -> str:
        """Append ``suffix`` to ``base`` with at most one slash."""
        return f"{base}{suffix}" if base.endswith("/") else f"{base}/{suffix}"


    def looks_like_iso8601(s: str) -> bool:
        """Cheap ISO-8601 sniff used by ``odata_literal`` to render bare timestamps."""
        if len(s) < 10 or s[4] != "-" or s[7] != "-":
            return False
        try:
            datetime.fromisoformat(s.replace("Z", "+00:00"))
            return True
        except ValueError:
            return False


    def odata_literal(value: Any) -> str:
        """Render a Python value as an OData v4 literal for $filter."""
        if isinstance(value, datetime):
            return value.isoformat().replace("+00:00", "Z")
        if isinstance(value, date):
            return value.isoformat()
        if isinstance(value, bool):
            return "true" if value else "false"
        if isinstance(value, int | float | Decimal):
            return str(value)
        s = str(value)
        if looks_like_iso8601(s):
            return s
        return "'" + s.replace("'", "''") + "'"


    # --- client-side pagination URL helpers -----------------------------------
    # These manipulate the connector's own generated URLs, where query options
    # (``$top``/``$filter``/``$orderby``/``$skip``) are stored raw (un-encoded),
    # one per ``&``-separated segment, and no generated value contains a literal
    # ``&``. So splitting on ``&`` and matching on a ``$name=`` prefix is safe —
    # the same convention ``rewrite_top_in_url`` relies on. requests url-encodes
    # the values when the request is actually sent. They live here (rather than in
    # ``odata.py``) so both the flat pager (``_client_paginate_pages``) and the
    # inner-``$expand`` continuation builder can use them without an import cycle;
    # ``odata.py`` re-exports them for callers that still import from there.


    def _pg_get_query(url: str, name: str) -> str | None:
        """Return the raw value of query option ``name`` (e.g. ``$filter``), or
        ``None`` when absent."""
        _, _, query = url.partition("?")
        pref = name + "="
        for part in query.split("&") if query else []:
            if part.startswith(pref):
                return part[len(pref) :]
        return None


    def _pg_set_query(url: str, name: str, value: str) -> str:
        """Set/replace/append query option ``name`` to ``value``; preserves the
        order of existing options."""
        head, sep, query = url.partition("?")
        pref = name + "="
        parts = query.split("&") if query else []
        out, found = [], False
        for part in parts:
            if part.startswith(pref):
                out.append(f"{name}={value}")
                found = True
            else:
                out.append(part)
        if not found:
            out.append(f"{name}={value}")
        return f"{head}?{'&'.join(out)}" if (sep or out) else head


    def _pg_parse_top(url: str) -> int | None:
        """Parse ``$top`` (or ``%24top``) as an int; ``None`` when absent/bad."""
        raw = _pg_get_query(url, "$top") or _pg_get_query(url, "%24top")
        return int(raw) if raw and raw.isdigit() else None


    def _pg_orderby_keys(url: str) -> list[str]:
        """Column names from the URL's ``$orderby``, in order. Returns ``[]``
        when there's no ``$orderby`` or any term is ``desc`` (a ``gt`` seek
        only walks ascending order; the connector only ever emits ``asc``)."""
        raw = _pg_get_query(url, "$orderby") or _pg_get_query(url, "%24orderby")
        if not raw:
            return []
        keys = []
        for term in raw.replace("%20", " ").split(","):
            term = term.strip()
            if term.endswith(" desc"):
                return []
            keys.append(term[:-4].strip() if term.endswith(" asc") else term)
        return [k for k in keys if k]


    def _pg_keyset_filter(order_keys: list[str], row: dict) -> str | None:
        """Build the ascending seek predicate placing the cursor strictly after
        ``row`` in ``order_keys`` order::

            (k1 gt v1) or (k1 eq v1 and k2 gt v2) or …

        Returns ``None`` if any key's value is null (no comparable boundary —
        the caller falls back to ``$skip``)."""
        vals = []
        for k in order_keys:
            v = row.get(k)
            if v is None:
                return None
            vals.append((k, v))
        clauses = []
        for i, (k, v) in enumerate(vals):
            terms = [f"{vals[j][0]} eq {odata_literal(vals[j][1])}" for j in range(i)]
            terms.append(f"{k} gt {odata_literal(v)}")
            clauses.append(" and ".join(terms))
        if len(clauses) == 1:
            return clauses[0]
        return " or ".join(f"({c})" for c in clauses)


    def _pg_with_extra_filter(url: str, clause: str) -> str:
        """AND ``clause`` into the URL's ``$filter`` (replacing any prior seek —
        the caller always rebuilds from the original base URL, so seeks never
        accumulate)."""
        existing = _pg_get_query(url, "$filter")
        combined = f"({existing}) and ({clause})" if existing else clause
        return _pg_set_query(url, "$filter", combined)


    # Connector-private query option carrying the stable base ``$filter`` across
    # cap-resume batches of a keyset walk. Stripped before any request is sent
    # (see ``_fetch_page_payload``), so the server never sees it.
    _PG_BASE = "__pgbase"


    def _pg_strip_query(url: str, name: str) -> str:
        """Remove query option ``name`` from ``url`` (no-op if absent)."""
        head, _sep, query = url.partition("?")
        if not query:
            return url
        pref = name + "="
        kept = [p for p in query.split("&") if not p.startswith(pref)]
        return f"{head}?{'&'.join(kept)}" if kept else head


    def _pg_base_filter(url: str) -> str | None:
        """The stable base ``$filter`` for a keyset walk: the stashed ``__pgbase``
        if present (a resumed walk), else the URL's current ``$filter`` (the first
        page, before any seek). An empty ``__pgbase`` marker means 'no base'."""
        marker = _pg_get_query(url, _PG_BASE)
        if marker is not None:
            return marker or None
        return _pg_get_query(url, "$filter")


    def _pg_keyset_seek_url(url: str, base_filter: str | None, seek: str) -> str:
        """Build the next keyset page URL: ``$filter`` becomes
        ``base_filter AND seek`` (or just ``seek`` when there's no base), with
        ``base_filter`` stashed in the private ``__pgbase`` option.

        Carrying the base separately lets a resumed walk REPLACE the seek instead
        of AND-ing a fresh lower bound onto the previous one every cap-resume
        batch — otherwise the ``$filter`` grows one keyset clause per batch and
        eventually overflows the server's URL-length limit. The seeks are
        monotonic so the accumulated form is merely redundant, never wrong, but it
        is unbounded. ``__pgbase`` is stripped before the request is sent."""
        combined = f"({base_filter}) and ({seek})" if base_filter else seek
        out = _pg_set_query(url, "$filter", combined)
        return _pg_set_query(out, _PG_BASE, base_filter or "")


    def _pg_page_fingerprint(page_rows: list[dict]) -> int:
        """Order-sensitive fingerprint of a page's rows for the no-progress
        guard. ``hash(repr(...))`` is process-stable — only ever compared within
        a single walk — and costs one page's worth of work. Two consecutive
        non-empty pages with the same fingerprint mean the server returned the
        same data twice (it ignored our seek/``$skip`` or handed back a cyclic
        ``@odata.nextLink``), so the walk has stalled."""
        return hash(repr(page_rows))


    # Re-export of the EDM namespace prefix used by the main module.
    _NS_EDM = "{http://docs.oasis-open.org/odata/ns/edm}"


    def parse_contained_path(table_name: str) -> list[str] | None:
        """Split double-underscore-delimited path; ``None`` for flat names."""
        if _URL_SEGMENT_SEP in table_name:
            # OData entity-set names cannot contain ``/`` (CSDL allows only
            # letters/digits/underscores), so a slash here always means the
            # caller used the wrong separator. Spell out the fix — the
            # generic "not found" error otherwise buries the cause under a
            # 200-entry "Available:" list.
            suggested = table_name.replace(_URL_SEGMENT_SEP, CONTAINED_PATH_SEP)
            raise ValueError(
                f"Contained-collection table names use {CONTAINED_PATH_SEP!r} "
                f"(double underscore) as the segment separator, not "
                f"{_URL_SEGMENT_SEP!r} — slashes aren't valid in Spark SQL "
                f"identifiers, which the SDP framework uses for view names. "
                f"Rename {table_name!r} to {suggested!r} in the pipeline "
                f"config."
            )
        if CONTAINED_PATH_SEP not in table_name:
            return None
        segments = table_name.split(CONTAINED_PATH_SEP)
        if any(not s for s in segments):
            raise ValueError(
                f"Empty path segment in contained table name {table_name!r}; "
                "expected 'Parent__Child' or 'Parent__Child__Grandchild' form."
            )
        if len(segments) > MAX_CONTAINED_DEPTH:
            raise ValueError(
                f"Contained path {table_name!r} exceeds max depth "
                f"{MAX_CONTAINED_DEPTH} (got {len(segments)})."
            )
        return segments


    def resolve_segment_filters(
        table_options: dict[str, str] | None,
        segments: list[str],
    ) -> dict[int, str]:
        """Parse ``filter_at_<segment>`` and ``filter_at_<idx>`` table-option
        keys into a ``{level: filter_string}`` mapping.

        Per-segment filters let the user push a ``$filter`` to the exact
        walk level (or ``$expand`` clause) that owns the property. Without
        this, the table's single ``filter`` option lands at one URL only
        (leaf for N+1 mode, top for expand mode), leaving intermediate
        levels unfiltered and forcing a full fan-out.

        Two equivalent key forms are accepted:

        * **By segment name** — ``filter_at_Instances=Id eq 5`` matches the
          segment literally as it appears in the contained path / URL.
        * **By zero-based index** — ``filter_at_0=Id eq 5`` matches the
          level positionally. Useful when nav-property names repeat at
          different depths.

        Both forms may be set; the **index form wins on conflict**, since
        it's the more explicit of the two. Unknown segment names and
        out-of-range indices raise ``ValueError`` immediately so typos
        don't silently produce a full-fan-out walk.
        """
        if not table_options:
            return {}
        out: dict[int, str] = {}
        # Lakeflow Connect lowercases option keys before forwarding them
        # to ``read_table``, so a pipeline-config ``filter_at_Instances``
        # arrives here as ``filter_at_instances``. Match the segment-name
        # suffix case-insensitively against the discovered path so the
        # pipeline config doesn't have to special-case the framework's
        # normalisation rules. Values aren't normalised — only keys — so
        # the filter expression itself is preserved verbatim.
        seg_to_idx = {s.lower(): i for i, s in enumerate(segments)}
        # Pass 1: name-keyed. Index-keyed entries override these on
        # conflict, so process them after.
        for key, value in table_options.items():
            if not key.startswith("filter_at_"):
                continue
            suffix = key[len("filter_at_") :]
            if suffix.isdigit():
                continue
            idx = seg_to_idx.get(suffix.lower())
            if idx is None:
                raise ValueError(
                    f"Invalid table option {key}={value!r}: segment "
                    f"{suffix!r} not in path {segments!r}. Valid "
                    f"segments (case-insensitive): {segments}."
                )
            out[idx] = value
        # Pass 2: index-keyed (overrides name form when both target the
        # same level).
        for key, value in table_options.items():
            if not key.startswith("filter_at_"):
                continue
            suffix = key[len("filter_at_") :]
            if not suffix.isdigit():
                continue
            idx = int(suffix)
            if not 0 <= idx < len(segments):
                raise ValueError(
                    f"Invalid table option {key}={value!r}: index {idx} "
                    f"out of range for path with {len(segments)} segments "
                    f"(valid: 0..{len(segments) - 1})."
                )
            out[idx] = value
        return out


    def combine_filters(*clauses: str | None) -> str | None:
        """``AND`` non-empty OData ``$filter`` clauses, wrapping each in
        parens to preserve precedence. Returns ``None`` when nothing is
        non-empty so callers can omit ``$filter`` entirely."""
        nonempty = [c for c in clauses if c]
        if not nonempty:
            return None
        if len(nonempty) == 1:
            return nonempty[0]
        return " and ".join(f"({c})" for c in nonempty)


    def contained_nav_props(entity_type: ET.Element) -> list[tuple[str, str]]:
        """``[(nav_name, target_type_ref), ...]`` for ContainsTarget collection
        nav props declared directly on this type; singletons skipped."""
        out: list[tuple[str, str]] = []
        for np in entity_type.findall(f"{_NS_EDM}NavigationProperty"):
            if (np.get("ContainsTarget") or "").lower() != "true":
                continue
            type_ref = np.get("Type", "")
            if not (type_ref.startswith("Collection(") and type_ref.endswith(")")):
                continue
            out.append((np.get("Name"), type_ref[len("Collection(") : -1]))
        return out


    def fk_column_name(segment: str, pk_name: str) -> str:
        """Default ancestor-FK column name: ``<segment>_<pkname>``.

        The actual column the connector writes may be further disambiguated
        (prefixed with leading underscores) if it collides with a leaf
        property or another FK column. See ``ContainedNavMixin._resolve_fk_columns``.
        """
        return f"{segment}_{pk_name}"


    def _ancestor_pk_order_by(ancestor_pks: list[str]) -> str:
        """Build a stable PK-only ``$orderby`` clause for ancestor key
        enumeration. OData v4 §11.2.5.7 (server-driven paging) doesn't
        promise stable default ordering across pages without an explicit
        ``$orderby`` over a unique key set, so server skiptokens can
        silently drop or duplicate ancestor rows — every leaf row under a
        skipped ancestor would then be lost. The leaf-cursor path already
        composes ``cursor asc, pk asc`` for the same reason
        (``_leaf_cursor_order_by``); ancestor key fetches need the
        PK-only variant of the same guarantee.
        """
        return ",".join(f"{pk} asc" for pk in ancestor_pks)


    class ContainedNavMixin:
        """Mixin providing contained-collection support for the OData connector.

        Plug in via ``class ODataLakeflowConnect(LakeflowConnect,
        SupportsNamespaces, ContainedNavMixin):``. All methods duck-type
        against the concrete class for HTTP/URL/metadata helpers.
        """

        def _all_contained_nav_props(self, entity_type: ET.Element) -> list[tuple[str, str]]:
            """Contained nav props on the type and its base chain (closest-
            descendant wins on name collision)."""
            out: dict[str, str] = {}
            for type_el in self._resolve_base_chain(entity_type):
                for name, ref in contained_nav_props(type_el):
                    out.setdefault(name, ref)
            return list(out.items())

        def _enumerate_contained_paths(self, top_level_set: str, namespace: str | None) -> list[str]:
            """BFS contained nav-property graph; cap at MAX_CONTAINED_DEPTH;
            break cycles via target-type set."""
            try:
                root_et = self._flat_entity_type_for(top_level_set, namespace)
            except ValueError:
                return []
            paths: list[str] = []
            # Cycle detection: start with an empty ``seen`` so the very first
            # self-reference (e.g. ``Node.Self → Node``) still emits a depth-1
            # path. Recursion is bounded by adding each traversed type to
            # ``seen`` before recursing.
            queue: list[tuple[list[str], ET.Element, set[str]]] = [([top_level_set], root_et, set())]
            while queue:
                segments, et, seen = queue.pop(0)
                if len(segments) >= MAX_CONTAINED_DEPTH:
                    continue
                for nav_name, target_ref in self._all_contained_nav_props(et):
                    if target_ref in seen:
                        continue
                    target_et = self._resolve_type_ref(target_ref)
                    if target_et is None:
                        continue
                    new_segments = segments + [nav_name]
                    paths.append(CONTAINED_PATH_SEP.join(new_segments))
                    queue.append((new_segments, target_et, seen | {target_ref}))
            return paths

        # --- option parsing ----------------------------------------------------

        def _expand_contained_active(self, table_options: dict[str, str] | None) -> bool:
            """Parse the boolean ``expand_contained`` table option."""
            raw = ((table_options or {}).get("expand_contained") or "false").strip().lower()
            if raw not in {"true", "false"}:
                raise ValueError(f"Invalid expand_contained={raw!r}. Expected one of: true, false.")
            return raw == "true"

        def _cursor_probe_mode(self, table_options: dict[str, str] | None) -> str:
            """Parse the ``cursor_probe`` table option into a leaf-cursor read
            acceleration mode. One of:

            * ``auto`` (**default**, when the option is unset) — best-effort
              cascade. Use the nested-``$expand`` change-probe where it can pay off
              *and* the server is verified to honour ``$orderby``/``$top`` inside
              ``$expand``; otherwise fall back to an OData ``$batch`` hydrate (when
              the server supports ``$batch``); otherwise the plain N+1 walk. Never
              raises on a server-capability shortfall — it degrades to a correct,
              slower strategy.
            * ``nested-expand`` → ``probe`` — strict nested-``$expand`` probe.
              **Raises** if the path can't use it or the server mis-orders inner
              ``$expand`` (the original fail-fast semantics): "I require the probe."
            * ``batch`` — skip the probe; hydrate the changed leaves via OData
              ``$batch`` (server-driven paging, no ``$top``, ``@odata.nextLink``
              follow-up, chunked to :data:`_BATCH_MAX_OPS` ops/request), falling
              back to the plain N+1 walk if the server doesn't support ``$batch``.
            * ``false`` → ``off`` — force the plain N+1 walk.

            The change-probe issues one shallow
            ``$expand(<leaf>($orderby=cursor desc;$top=1;$select=cursor))`` per
            leaf-grandparent to find each leaf-parent's newest leaf, marks it dirty
            when that cursor is ``> since`` (client-side), then runs the normal N+1
            walk over only the dirty leaf-parents. The ``$batch`` hydrate skips the
            identify step entirely: it issues the plain per-leaf-parent
            ``cursor gt since`` reads, but packs them into ``$batch`` requests so M
            leaf-parent round-trips collapse to ``ceil(M / _BATCH_MAX_OPS)``. Both
            emit rows identical to ``off`` (the plain walk) — the probe relies on
            inner-``$expand`` ordering (hence the capability check), while ``$batch``
            relies only on top-level single-column ``cursor gt`` filters, so it is
            safe on servers (e.g. Hexagon Smart API) that reject nested ``$expand``
            options. See :meth:`_cursor_probe_applicable` and
            :meth:`_verify_batch_support`."""
            raw = ((table_options or {}).get("cursor_probe") or "auto").strip().lower()
            aliases = {"nested-expand": "probe", "false": "off", "batch": "batch", "auto": "auto"}
            if raw not in aliases:
                raise ValueError(
                    f"Invalid cursor_probe={raw!r}. Expected one of: "
                    "nested-expand, batch, auto, false."
                )
            return aliases[raw]

        def _cursor_probe_applicable(
            self,
            segments: list[str],
            namespace: str | None,
            cursor_field: str,
            cursor_level: int,
        ) -> bool:
            """Whether the probe can actually save work on this path.

            Two conditions:

            1. The cursor lives on the **leaf** (``cursor_level`` is the last
               segment). An ancestor cursor already filters whole subtrees, so
               there's nothing to probe.
            2. The **distance from the leaf to the nearest batch-snapshot
               ancestor is > 1** — i.e. the leaf's *parent* collection is
               itself a cursor-bearing (incremental, typically high-fan-out)
               entity. The savings come from skipping leaf hydrates for *clean*
               leaf-parents; when the leaf-parent is a snapshot structural level
               (e.g. ``.../Projects/WorkPackageDetails`` where only the leaf
               carries the cursor), it has few rows that all read as dirty, so
               the probe only adds ``$expand`` payload with nothing to skip.

            A "snapshot ancestor" is one whose entity type does not declare
            ``cursor_field``. ``snapshot_idx`` is the deepest such ancestor
            (``-1`` if every ancestor declares it); the probe engages when
            ``leaf_idx - snapshot_idx > 1``.
            """
            leaf_idx = len(segments) - 1
            if cursor_level != leaf_idx:
                return False
            snapshot_idx = -1
            for idx in range(leaf_idx):  # ancestors only, leaf excluded
                ancestor_et = self._entity_type_for(
                    CONTAINED_PATH_SEP.join(segments[: idx + 1]), namespace
                )
                if not any(f.name == cursor_field for f in self._own_fields_for_et(ancestor_et)):
                    snapshot_idx = idx
            return (leaf_idx - snapshot_idx) > 1

        # --- URL construction --------------------------------------------------

        def _format_key_predicate(self, pk_values: dict[str, Any]) -> str:
            """``(value)`` for single key; ``(K1=v1,K2=v2)`` for composite."""
            if len(pk_values) == 1:
                return f"({odata_literal(next(iter(pk_values.values())))})"
            return "(" + ",".join(f"{k}={odata_literal(v)}" for k, v in pk_values.items()) + ")"

        def _build_contained_path(self, segments: list[str], key_chain: list[dict[str, Any]]) -> str:
            """``A(1)/B('x')/C`` — leaf segment has no key; ``key_chain`` len = N-1."""
            if len(key_chain) != len(segments) - 1:
                raise ValueError(
                    f"key_chain length {len(key_chain)} does not match "
                    f"non-leaf segment count {len(segments) - 1}"
                )
            return _URL_SEGMENT_SEP.join(
                f"{seg}{self._format_key_predicate(key_chain[i])}" if i < len(key_chain) else seg
                for i, seg in enumerate(segments)
            )

        # pylint: disable=too-many-arguments,too-many-positional-arguments
        def _build_contained_url(
            self,
            segments: list[str],
            key_chain: list[dict[str, Any]],
            table_options: dict[str, str],
            extra_filter: str | None = None,
            order_by: str | None = None,
        ) -> str:
            """Full URL for a contained-collection read at one parent tuple."""
            base = join_url(self.service_url, self._build_contained_path(segments, key_chain))
            return f"{base}?{self._format_query_params(table_options, extra_filter, order_by)}"

        # pylint: disable=too-many-arguments,too-many-positional-arguments
        def _build_expand_url(
            self,
            segments: list[str],
            table_options: dict[str, str],
            cursor_level: int | None = None,
            cursor_filter: str | None = None,
            cursor_order: str | None = None,
            cursor_select: str | None = None,
        ) -> str:
            """``A?...&$expand=B($top=N;$expand=C($top=N;$expand=D($top=N)))`` for the full chain.

            When ``cursor_level`` is set, ``cursor_filter``/``cursor_order``/
            ``cursor_select`` are injected at the segment that owns the
            cursor — at the top-level URL when ``cursor_level == 0``, or
            inside the corresponding ``$expand`` clause otherwise. The
            ``$select`` is necessary because some OData servers omit
            properties from ``$expand`` responses by default; explicitly
            requesting the cursor guarantees the server projects it onto
            the ancestor rows so it can be stamped onto leaf rows. OData
            v4 §5.1.1.13: inner ``$expand`` options are separated by ``;``.

            ``$top`` is emitted at every nested ``$expand`` level so the
            server's default doesn't surprise us (Hexagon SCApi for example
            caps inner expansions at 100 regardless of the request) and so
            the connector controls the per-response row count.

            Per-level ``$top`` values are computed dynamically by
            :func:`compute_dynamic_tops`: the ``page_size`` budget is
            distributed across all ``$top`` points with triangular weights
            — the top URL gets the largest share, each deeper level
            proportionally less — so the worst-case cross-product stays
            within ``page_size``. ``$top=1000`` at every level of a
            3-segment expand would ask for up to 1B rows in one response
            and times out every real server; the dynamic distribution
            keeps it bounded (e.g. ``[31, 10, 5]`` for depth 3 with
            ``page_size=1000``). Servers that don't honour ``$top`` inside
            ``$expand`` ignore it — the wire format stays valid OData v4.
            """
            segment_filters = resolve_segment_filters(table_options, segments)
            base = join_url(self.service_url, segments[0])
            opts = table_options or {}
            # ``$top`` is emitted across the expand levels only when the user
            # set ``page_size``; with none, no ``$top`` is sent at any level
            # and the server picks its own page size (see
            # ``_format_query_params``). ``per_level_tops`` is ``None`` then.
            per_level_tops = (
                compute_dynamic_tops(int(opts["page_size"]), len(segments))
                if opts.get("page_size")
                else None
            )
            return self._assemble_expand_url(
                base,
                segments,
                0,
                table_options,
                segment_filters,
                cursor_level,
                cursor_filter,
                cursor_order,
                cursor_select,
                per_level_tops,
            )

        # pylint: disable=too-many-arguments,too-many-positional-arguments
        def _expand_level_order_by(
            self,
            segments: list[str],
            level: int,
            namespace: str | None,
            cursor_level: int | None,
            cursor_order: str | None,
        ) -> str | None:
            """``$orderby`` for one expand level so server skiptoken paging is
            stable — for the top collection AND each expanded sub-collection.
            OData v4 §11.2.5.7 promises no stable default order across pages, so
            without a unique sort a value-based skiptoken can drop or duplicate
            rows (the same failure the N+1 path guards against via
            ``_ancestor_pk_order_by`` / ``_leaf_pk_order_by``). The cursor-owning
            level keeps its cursor-first composite (``cursor_order``); every
            other level falls back to PK-only. Servers that ignore ``$orderby``
            inside ``$expand`` leave the wire format valid OData v4 — same
            contract as ``$top``. The server-generated
            ``<NavProp>@odata.nextLink`` continuations preserve these options per
            §11.2.6.1, so paging stays ordered.

            Returns ``None`` when the segment isn't resolvable in ``$metadata``
            (only fires for synthetic paths; a real expand path is validated
            upstream) — degrade to the server default rather than crash the URL
            build.
            """
            if level == cursor_level and cursor_order:
                return cursor_order
            try:
                et = self._entity_type_for(CONTAINED_PATH_SEP.join(segments[: level + 1]), namespace)
            except ValueError:
                return None
            return _ancestor_pk_order_by(self._own_primary_keys_for_et(et)) or None

        # pylint: disable=too-many-arguments,too-many-positional-arguments,too-many-locals
        def _assemble_expand_url(
            self,
            base: str,
            segments: list[str],
            start_level: int,
            table_options: dict[str, str],
            segment_filters: dict[int, str],
            cursor_level: int | None,
            cursor_filter: str | None,
            cursor_order: str | None,
            cursor_select: str | None,
            per_level_tops: list[int] | None,
        ) -> str:
            """Render an expand URL rooted at ``base`` whose top collection is
            ``segments[start_level]`` and whose nested ``$expand`` chain covers
            ``segments[start_level + 1:]``.

            ``start_level == 0`` reproduces the full top-level request (used by
            :meth:`_build_expand_url`). ``start_level > 0`` roots the request at
            a contained path — ``base`` already carries the ancestor keys — and
            is used by :meth:`_build_expand_continuation_url` to page a single
            parent's inner collection client-side when the server omits its
            ``<NavProp>@odata.nextLink``.

            Filters, ``$top``, ``$orderby`` and the cursor injection are all
            keyed by ABSOLUTE segment level, so the same ``segment_filters`` /
            ``cursor_level`` resolved against the full path stay correct for any
            ``start_level``.
            """
            namespace = (table_options or {}).get("namespace")
            opts = table_options or {}
            has_children = start_level < len(segments) - 1
            # The table's ``filter`` option is the leaf filter — same as N+1
            # mode, where it lands at the leaf URL — so strip it from the
            # start-level query params when there are deeper levels. It re-enters
            # at the innermost ``$expand(...)`` clause below. Without this split,
            # ``filter="Id eq 3"`` on a ``Instances__Projects`` table would land
            # at Instances (wrong segment) and 400 the server.
            top_opts = {k: v for k, v in opts.items() if k != "filter"} if has_children else dict(opts)
            if per_level_tops is not None:
                # Override page_size in the opts dict ``_format_query_params``
                # reads from, so the start-level ``$top`` reflects the dynamic
                # allocation instead of the unscaled budget.
                top_opts = dict(top_opts)
                top_opts["page_size"] = str(per_level_tops[start_level])
            top_extra = combine_filters(
                cursor_filter if cursor_level == start_level else None,
                segment_filters.get(start_level),
            )
            query = self._format_query_params(
                top_opts,
                top_extra,
                self._expand_level_order_by(
                    segments, start_level, namespace, cursor_level, cursor_order
                ),
            )
            if not has_children:
                return f"{base}?{query}"
            user_leaf_filter = opts.get("filter")
            inner = ""
            for i in range(len(segments) - 1, start_level, -1):
                is_leaf = i == len(segments) - 1
                # ``per_level_tops`` is indexed by absolute segment level.
                parts: list[str] = []
                if per_level_tops is not None:
                    parts.append(f"$top={per_level_tops[i]}")
                level_filter = combine_filters(
                    cursor_filter if cursor_level == i else None,
                    segment_filters.get(i),
                    user_leaf_filter if is_leaf else None,
                )
                if cursor_level == i and cursor_select:
                    parts.append(f"$select={cursor_select}")
                if level_filter:
                    parts.append(f"$filter={level_filter}")
                level_order = self._expand_level_order_by(
                    segments, i, namespace, cursor_level, cursor_order
                )
                if level_order:
                    parts.append(f"$orderby={level_order}")
                if inner:
                    parts.append(f"$expand={inner}")
                # No options at all (no $top/filter/select/orderby/expand) ⇒
                # emit the bare nav-property name; ``Leaf()`` is not valid.
                inner = f"{segments[i]}({';'.join(parts)})" if parts else segments[i]
            return f"{base}?{query}&$expand={inner}"

        # --- read paths --------------------------------------------------------

        def _set_excluded_ancestor_columns(self, table_options: dict[str, str] | None) -> None:
            """Parse the ``exclude_ancestor_columns`` table option (a
            comma-separated list of FK column names) onto ``self`` for the
            duration of a schema/metadata/read call.

            Held on ``self`` — mirroring ``self._pagination`` — so the shared
            ``_resolve_fk_columns`` primitive (and everything that derives from
            it: schema, primary keys, row tagging) sees the exclusion without
            threading it through every internal call site. Reset on every
            entry point, so one table's exclusion can't leak into the next.
            """
            raw = (table_options or {}).get("exclude_ancestor_columns") or ""
            self._excluded_ancestor_columns = frozenset(c.strip() for c in raw.split(",") if c.strip())

        def _all_fk_column_names(self, segments: list[str], namespace: str | None) -> set[str]:
            """Full set of ancestor-FK column names for a contained path,
            BEFORE any ``exclude_ancestor_columns`` filtering — so callers can
            validate the option's names against what the path actually emits."""
            if len(segments) < 2:
                return set()
            self._resolve_fk_columns(segments, namespace)  # ensure cache populated
            full = self._metadata_state().fk_columns.get((tuple(segments), namespace)) or {}
            return set(full.values())

        def _resolve_fk_columns(
            self, segments: list[str], namespace: str | None
        ) -> dict[tuple[str, str], str]:
            """Map ``(segment, pk_name) → unique FK column name`` for every
            non-leaf ancestor.

            OData v4 §13.4.3 makes contained-entity keys unique only within
            their immediate parent, so the destination composite key needs
            the full ancestor chain to be globally unique. Default name is
            ``<segment>_<pk>``; collisions get a leading ``_`` until unique.
            Empty mapping for flat tables.

            FK columns named in the ``exclude_ancestor_columns`` table option
            (parsed onto ``self._excluded_ancestor_columns`` at each entry
            point) are dropped from the returned mapping, so they vanish from
            the leaf schema, the composite primary key, and the stamped rows
            alike. A lone ``*`` drops every ancestor-FK column at once. The
            full mapping is cached untouched; the exclusion is a cheap
            post-filter so the same contained path can be read with different
            exclusions without poisoning the cache.
            """
            if len(segments) < 2:
                return {}
            state = self._metadata_state()
            cache_key = (tuple(segments), namespace)
            resolved = state.fk_columns.get(cache_key)
            if resolved is None:
                leaf_field_names = {
                    f.name
                    for f in self._own_fields_for_et(
                        self._entity_type_for(CONTAINED_PATH_SEP.join(segments), namespace)
                    )
                }
                used = set(leaf_field_names)
                resolved = {}
                for idx in range(len(segments) - 1):
                    ancestor_et = self._entity_type_for(
                        CONTAINED_PATH_SEP.join(segments[: idx + 1]), namespace
                    )
                    seg = segments[idx]
                    for pk in self._own_primary_keys_for_et(ancestor_et):
                        candidate = fk_column_name(seg, pk)
                        while candidate in used:
                            candidate = "_" + candidate
                        resolved[(seg, pk)] = candidate
                        used.add(candidate)
                state.fk_columns[cache_key] = resolved
            excluded = getattr(self, "_excluded_ancestor_columns", frozenset())
            if "*" in excluded:
                return {}
            if excluded:
                return {k: v for k, v in resolved.items() if v not in excluded}
            return resolved

        def _tag_with_ancestor_fks(
            self,
            row: dict,
            segments: list[str],
            chain: list[dict[str, Any]],
            fk_columns: dict[tuple[str, str], str],
        ) -> None:
            """Write every ancestor's primary-key values onto ``row`` under
            the resolved FK column names from ``fk_columns``."""
            for idx, ancestor_keys in enumerate(chain):
                seg = segments[idx]
                for pk_name, pk_val in ancestor_keys.items():
                    col = fk_columns.get((seg, pk_name))
                    if col is not None:
                        row[col] = pk_val

        def _find_cursor_level(
            self,
            segments: list[str],
            namespace: str | None,
            cursor_field: str,
        ) -> int:
            """Return the segment index whose entity type declares
            ``cursor_field`` as a property. Walk leaf → root; the closest
            match wins. Returns ``-1`` if no segment has it."""
            for idx in range(len(segments) - 1, -1, -1):
                et = self._entity_type_for(CONTAINED_PATH_SEP.join(segments[: idx + 1]), namespace)
                if any(f.name == cursor_field for f in self._own_fields_for_et(et)):
                    return idx
            return -1

        def _ancestor_cursor_field(
            self, table_name: str, namespace: str | None, cursor_field: str
        ) -> StructField | None:
            """``StructField`` for ``cursor_field`` when it lives on a non-leaf
            ancestor of a contained path; ``None`` when the leaf owns it or
            the path is flat. Used by ``get_table_schema`` to add the column
            to the leaf schema."""
            segments = parse_contained_path(table_name) or [table_name]
            if len(segments) < 2:
                return None
            cursor_level = self._find_cursor_level(segments, namespace, cursor_field)
            if cursor_level in (-1, len(segments) - 1):
                return None
            ancestor_et = self._entity_type_for(
                CONTAINED_PATH_SEP.join(segments[: cursor_level + 1]), namespace
            )
            for field in self._own_fields_for_et(ancestor_et):
                if field.name == cursor_field:
                    return field
            return None

        def _iter_parent_chains_with_cursor(
            self,
            segments: list[str],
            namespace: str | None,
            table_options: dict[str, str] | None,
            cursor_level: int,
            cursor_field: str,
            since: Any,
            top_parent_rows: list[dict] | None = None,
        ) -> Iterator[tuple[list[dict[str, Any]], Any]]:
            """Like ``_iter_parent_key_chains`` but applies a cursor filter at
            the ancestor that owns ``cursor_field``. Yields
            ``(chain, ancestor_cursor_value)`` pairs; the cursor value is the
            value at ``cursor_level`` for that chain.

            ``top_parent_rows`` lets a partitioned caller (PartitionMixin)
            supply a pre-discovered subset of level-0 rows instead of
            fetching the whole top-level set. Each row dict must carry the
            top-level entity's PKs (and, when ``cursor_level == 0``, the
            cursor value). The supplied subset is consumed in order without
            re-fetching."""
            segment_filters = resolve_segment_filters(table_options, segments)

            def _walk(level: int, chain: list[dict[str, Any]], cur_val: Any):
                if level == len(segments) - 1:
                    yield list(chain), cur_val
                    return
                sub_segments = segments[: level + 1]
                ancestor_et = self._entity_type_for(CONTAINED_PATH_SEP.join(sub_segments), namespace)
                ancestor_pks = self._own_primary_keys_for_et(ancestor_et)
                if not ancestor_pks:
                    raise ValueError(
                        f"Cannot walk contained path: segment {segments[level]!r} "
                        f"has no primary key declared in $metadata."
                    )
                row_source: Iterator[dict]
                if level == 0 and top_parent_rows is not None:
                    # Skip the level-0 fetch; the partitioned caller has
                    # already discovered + filtered + selected this subset.
                    row_source = iter(top_parent_rows)
                else:
                    select_cols = list(ancestor_pks)
                    extra_filter: str | None = None
                    # Default to PK-only ordering so server skiptoken
                    # pagination is stable even at non-cursor levels —
                    # OData v4 §11.2.5.7 doesn't promise stable default
                    # ordering across pages without an explicit
                    # ``$orderby``. The cursor level overrides this with a
                    # cursor-first composite below.
                    order_by: str | None = _ancestor_pk_order_by(ancestor_pks)
                    if level == cursor_level:
                        if cursor_field not in select_cols:
                            select_cols.append(cursor_field)
                        extra_filter = self._cursor_filter(cursor_field, since)
                        terms = [f"{cursor_field} asc"]
                        terms.extend(f"{pk} asc" for pk in ancestor_pks if pk != cursor_field)
                        order_by = ",".join(terms)
                    opts = {"select": ",".join(select_cols)}
                    # Propagate the user's ``page_size`` only when set; with no
                    # ``page_size`` no ``$top`` is sent (see
                    # ``_format_query_params``).
                    if (table_options or {}).get("page_size"):
                        opts["page_size"] = table_options["page_size"]
                    if segment_filters.get(level):
                        opts["filter"] = segment_filters[level]
                    url = (
                        self._build_url(segments[0], opts, extra_filter=extra_filter, order_by=order_by)
                        if level == 0
                        else self._build_contained_url(
                            sub_segments,
                            chain,
                            opts,
                            extra_filter=extra_filter,
                            order_by=order_by,
                        )
                    )
                    row_source = self._fetch_pages(url)
                for row in row_source:
                    next_cur = row.get(cursor_field) if level == cursor_level else cur_val
                    chain.append({pk: row.get(pk) for pk in ancestor_pks})
                    yield from _walk(level + 1, chain, next_cur)
                    chain.pop()

            yield from _walk(0, [], None)

        def _iter_parent_key_chains(
            self,
            segments: list[str],
            namespace: str | None,
            table_options: dict[str, str] | None,
            top_parent_rows: list[dict] | None = None,
        ) -> Iterator[list[dict[str, Any]]]:
            """Yield every ancestor key chain (len = len(segments) - 1) reaching
            the leaf. Each level fetched with ``$select=<pks>``; user ``filter``
            not forwarded — that string lands at the leaf URL only. To filter
            an ancestor walk use ``filter_at_<segment>`` / ``filter_at_<idx>``.

            ``top_parent_rows`` lets a partitioned caller supply a pre-
            discovered subset of level-0 rows; when provided, the level-0
            HTTP fetch is skipped and the rows are consumed in order."""
            segment_filters = resolve_segment_filters(table_options, segments)

            def _walk(level: int, chain: list[dict[str, Any]]):
                if level == len(segments) - 1:
                    yield list(chain)
                    return
                sub_segments = segments[: level + 1]
                ancestor_et = self._entity_type_for(CONTAINED_PATH_SEP.join(sub_segments), namespace)
                ancestor_pks = self._own_primary_keys_for_et(ancestor_et)
                if not ancestor_pks:
                    raise ValueError(
                        f"Cannot walk contained path: segment {segments[level]!r} "
                        f"has no primary key declared in $metadata."
                    )
                row_source: Iterator[dict]
                if level == 0 and top_parent_rows is not None:
                    row_source = iter(top_parent_rows)
                else:
                    opts = {"select": ",".join(ancestor_pks)}
                    # Propagate the user's ``page_size`` only when set; with no
                    # ``page_size`` no ``$top`` is sent (see
                    # ``_format_query_params``).
                    if (table_options or {}).get("page_size"):
                        opts["page_size"] = table_options["page_size"]
                    if segment_filters.get(level):
                        opts["filter"] = segment_filters[level]
                    # PK-only ``$orderby`` so server skiptoken pagination
                    # over the ancestor key set is stable across pages —
                    # without this, sources whose default sort isn't PK
                    # (or whose skiptoken doesn't encode the PK) can skip
                    # or duplicate parents and silently lose every leaf
                    # row under the skipped parent. See
                    # ``_leaf_cursor_order_by`` for the leaf-side comment
                    # documenting the same skiptoken concern one level
                    # deeper.
                    order_by = _ancestor_pk_order_by(ancestor_pks)
                    url = (
                        self._build_url(segments[0], opts, order_by=order_by)
                        if level == 0
                        else self._build_contained_url(sub_segments, chain, opts, order_by=order_by)
                    )
                    row_source = self._fetch_pages(url)
                for row in row_source:
                    chain.append({pk: row.get(pk) for pk in ancestor_pks})
                    yield from _walk(level + 1, chain)
                    chain.pop()

            yield from _walk(0, [])

        def _build_probe_url(
            self,
            segments: list[str],
            parent_chain: list[dict[str, Any]],
            table_options: dict[str, str],
            cursor_field: str,
        ) -> str:
            """Shallow change-probe over one leaf-parent collection.

            ``parent_chain`` (len = ``len(segments) - 2``) addresses the
            leaf-parent *collection* under its grandparent tuple; the URL asks
            only for the leaf-parent PKs plus the **single newest leaf by
            cursor**::

                A(a)/B(b)/C?$top=<page>&$select=<Cpk>&$orderby=<Cpk> asc
                           &$expand=D($orderby=<cursor> desc;$top=1;$select=<cursor>)

            The caller (:meth:`_iter_dirty_leaf_parent_chains`) marks a leaf-parent
            dirty when that newest leaf's cursor is ``> since`` — the change test
            is done **client-side**, with no inner ``$filter`` at all. Ordering the
            inner ``$expand`` by the cursor descending makes the one returned row
            the MAX-cursor leaf *by construction*, so a server that applies
            ``$top`` before anything else still returns the right row. That is the
            whole point: an earlier ``$top=1;$filter`` shape let servers slice the
            first expanded row *before* applying the inner ``$filter``, so a
            leaf-parent whose changed leaf wasn't first by default order was
            wrongly reported clean and its leaves silently dropped. Comparing the
            max cursor client-side removes that trap.

            NB: relies on the server honouring ``$orderby``/``$top`` *inside*
            ``$expand`` (basic expand options). A server that ignores ``$orderby``
            could return a non-newest row and under-report — that residual
            server-dependence is why ``cursor_probe`` is opt-in (default off):
            enable it only where the source is known to honour inner-``$expand``
            options. A ``filter_at_<leaf>`` segment filter is deliberately NOT
            applied in the probe (it has no inner ``$filter``); at worst that
            over-fetches a parent whose recent changes the filter excludes — the
            hydrate then emits nothing, never a miss.
            """
            namespace = (table_options or {}).get("namespace")
            parent_segments = segments[:-1]
            leaf_nav = segments[-1]
            segment_filters = resolve_segment_filters(table_options, segments)
            lp_pks = self._own_primary_keys_for_et(
                self._entity_type_for(CONTAINED_PATH_SEP.join(parent_segments), namespace)
            )
            inner = [f"$orderby={cursor_field} desc", "$top=1", f"$select={cursor_field}"]
            outer = []
            if (table_options or {}).get("page_size"):
                outer.append(f"$top={table_options['page_size']}")
            outer.append(f"$select={','.join(lp_pks)}")
            lp_filter = segment_filters.get(len(parent_segments) - 1)
            if lp_filter:
                outer.append(f"$filter={lp_filter}")
            order_by = _ancestor_pk_order_by(lp_pks)
            if order_by:
                outer.append(f"$orderby={order_by}")
            outer.append(f"$expand={leaf_nav}({';'.join(inner)})")
            base = join_url(self.service_url, self._build_contained_path(parent_segments, parent_chain))
            return f"{base}?{'&'.join(outer)}"

        def _iter_dirty_leaf_parent_chains(
            self,
            segments: list[str],
            namespace: str | None,
            table_options: dict[str, str] | None,
            cursor_field: str,
            since: Any,
        ) -> Iterator[list[dict[str, Any]]]:
            """``cursor_probe`` chain source: yield only the full key chains
            (len = ``len(segments) - 1``) whose leaf collection has ≥1 changed
            row since ``since``.

            A drop-in for :meth:`_iter_parent_key_chains` in the leaf-cursor
            read: it enumerates leaf-grandparent tuples the same way, then runs
            one :meth:`_build_probe_url` per tuple and emits the leaf-parent key
            (extending the chain) only for parents the probe flags dirty. Like
            the plain enumerator it is consumed lazily and is deterministic for
            a fixed ``since``, so the leaf-cursor walk's flat ``parent_idx``
            resume works unchanged — a resumed batch re-probes the skipped
            parents (cheap; no leaf fetches) exactly as the plain walk re-pages
            skipped ancestors.

            ``since`` is ``None`` on the first batch → every leaf-parent with any
            leaf reads as dirty, so the first incremental batch behaves like the
            standard full walk (correct, no speed-up until a watermark exists)."""
            parent_segments = segments[:-1]
            leaf_nav = segments[-1]
            lp_pks = self._own_primary_keys_for_et(
                self._entity_type_for(CONTAINED_PATH_SEP.join(parent_segments), namespace)
            )
            for pchain in self._iter_parent_key_chains(parent_segments, namespace, table_options):
                url = self._build_probe_url(segments, pchain, table_options, cursor_field)
                for row in self._fetch_pages(url):
                    # The probe returns the newest leaf (``$orderby cursor desc;
                    # $top=1``). Max over the returned rows so we're still correct
                    # if a server ignores ``$top`` and hands back several. Dirty
                    # when that max cursor exceeds the watermark (or on the first
                    # batch, ``since is None``, whenever the leaf-parent has a
                    # leaf at all) — this matches the hydrate's ``cursor gt since``.
                    max_cursor = None
                    for child in row.get(leaf_nav) or []:
                        val = child.get(cursor_field)
                        if val is not None and (max_cursor is None or val > max_cursor):
                            max_cursor = val
                    if max_cursor is not None and (since is None or max_cursor > since):
                        yield pchain + [{pk: row.get(pk) for pk in lp_pks}]

        def _verify_cursor_probe_support(
            self,
            segments: list[str],
            namespace: str | None,
            table_options: dict[str, str] | None,
            cursor_field: str,
            start_offset: dict | None = None,
            strict: bool = True,
        ) -> tuple[bool, bool]:
            """Behavioural capability check for the nested-``$expand`` probe.

            Returns ``(supported, conclusive)``. ``supported`` is whether the
            server can be trusted to run the probe correctly; ``conclusive`` is
            whether the verdict is a *conclusive* pass the caller may persist.
            When ``strict`` (``cursor_probe=nested-expand``) and the server mis-orders inner
            ``$expand``, **raises** with the actionable message. When not strict
            (``auto`` cascade), a mis-ordering server returns ``(False, False)`` so
            the caller can fall back to ``$batch`` / the plain walk instead.

            ``cursor_probe`` (default on) silently drops rows on a server that
            mishandles ``$orderby``/``$top`` inside ``$expand``. This behavioural
            preflight catches that *before* any data is read and turns it into a
            clear error.

            Result is cached per ``(path, namespace)`` so the check runs once per
            connector instance. But the Spark Python Data Source recreates the
            reader per batch, so that instance cache is cold every batch — the
            preflight's handful of GETs would recur indefinitely. To avoid that, a
            *conclusive* pass is also persisted in the resume offset as
            ``cursor_probe_ok``; when a prior batch's offset carries it, the
            preflight requests are skipped entirely. Only a conclusive pass is
            trusted this way. An *inconclusive* result — no leaf-parent yet has
            ``>= 2`` distinct leaf cursors, so ordering can't cause a miss — is
            re-checked every batch, so a server that begins to mis-order once its
            data grows discriminating is still caught.

            ``(supported, conclusive)``: ``supported`` is ``True`` via the persisted
            offset flag or any non-mis-ordering preflight verdict; ``conclusive`` is
            ``True`` only on a conclusive pass the caller may persist as
            ``cursor_probe_ok`` (an *inconclusive* scan is re-checked every batch).
            Raises (``strict``) or returns ``(False, False)`` (non-strict) on a
            mis-ordering server."""
            if (start_offset or {}).get("cursor_probe_ok"):
                return (True, True)
            cache = self.__dict__.setdefault("_cursor_probe_verified", {})
            cache_key = (tuple(segments), namespace)
            if cache_key not in cache:
                cache[cache_key] = self._run_cursor_probe_preflight(
                    segments, namespace, table_options, cursor_field
                )
            problem, conclusive = cache[cache_key]
            if problem:
                if strict:
                    raise ValueError(problem)
                return (False, False)
            return (True, conclusive)

        def _run_cursor_probe_preflight(
            self,
            segments: list[str],
            namespace: str | None,
            table_options: dict[str, str] | None,
            cursor_field: str,
        ) -> tuple[str | None, bool]:
            """Behavioural capability check for :meth:`_iter_dirty_leaf_parent_chains`.

            Returns ``(problem, conclusive)``: ``problem`` is an actionable error
            message when the server mishandles inner ``$expand`` ordering (the probe
            would under-report dirty leaf-parents and drop rows), else ``None``.
            ``conclusive`` is ``True`` only when a discriminating sample was found
            AND the probe shape returned the true newest leaf — the verdict the
            caller may persist across batches (see
            :meth:`_verify_cursor_probe_support`); ``False`` on an inconclusive
            scan, which must be re-checked rather than trusted.

            Finds a sample leaf-parent with ≥2 distinct leaf cursors and verifies
            that the probe's own ``$expand($orderby cursor desc;$top=1)`` returns
            the true newest leaf — cross-checked against a trusted direct-navigation
            ``$orderby`` query (basic collection ordering, far more universally
            honoured than inner-``$expand`` ordering). Inconclusive (no
            discriminating sample within :data:`_CURSOR_PROBE_PREFLIGHT_SCAN`) →
            ``(None, False)``: with ≤1 leaf per parent, ordering can't cause a
            miss."""
            parent_segments = segments[:-1]
            leaf_nav = segments[-1]
            lp_pks = self._own_primary_keys_for_et(
                self._entity_type_for(CONTAINED_PATH_SEP.join(parent_segments), namespace)
            )
            if not lp_pks:
                return (None, False)
            page_size = (table_options or {}).get("page_size") or DEFAULT_PAGE_SIZE
            lp_order = _ancestor_pk_order_by(lp_pks)
            scanned = 0
            for pchain in self._iter_parent_key_chains(parent_segments, namespace, table_options):
                lp_base = join_url(
                    self.service_url, self._build_contained_path(parent_segments, pchain)
                )
                next_url: str | None = f"{lp_base}?$select={','.join(lp_pks)}&$top={page_size}"
                if lp_order:
                    next_url += f"&$orderby={lp_order}"
                while next_url:
                    lp_rows, next_url = self._fetch_one_expand_page(next_url)
                    for lp_row in lp_rows:
                        scanned += 1
                        lp_key = {pk: lp_row.get(pk) for pk in lp_pks}
                        status, message = self._cursor_probe_check_sample(
                            parent_segments, pchain, segments, namespace, lp_key, leaf_nav, cursor_field
                        )
                        if status == "ok":
                            return (None, True)
                        if status == "error":
                            return (message, False)
                        if scanned >= _CURSOR_PROBE_PREFLIGHT_SCAN:
                            return (None, False)
            return (None, False)

        # pylint: disable=too-many-arguments,too-many-positional-arguments
        def _cursor_probe_check_sample(
            self,
            parent_segments: list[str],
            pchain: list[dict[str, Any]],
            segments: list[str],
            namespace: str | None,
            lp_key: dict[str, Any],
            leaf_nav: str,
            cursor_field: str,
        ) -> tuple[str, str | None]:
            """Verify the probe shape against trusted ordering for one leaf-parent.

            Returns ``("skip", None)`` when the sample can't discriminate (< 2
            distinct leaf cursors), ``("ok", None)`` when the probe's inner
            ``$expand`` ordering returns the true newest leaf, or
            ``("error", msg)`` when it does not."""
            full_chain = pchain + [lp_key]
            leaf_base = join_url(self.service_url, self._build_contained_path(segments, full_chain))
            # Trusted reference: direct-navigation ordering on the leaf collection.
            direct_rows, _ = self._fetch_one_expand_page(
                f"{leaf_base}?$orderby={cursor_field} desc&$top=2&$select={cursor_field}"
            )
            vals = [r.get(cursor_field) for r in direct_rows if r.get(cursor_field) is not None]
            if len(vals) < 2 or vals[0] == vals[1]:
                return ("skip", None)
            direct_max = vals[0]
            # The probe's own shape, targeted to this leaf-parent via an outer
            # key $filter (basic collection filtering, not an inner-$expand option).
            lp_coll = join_url(self.service_url, self._build_contained_path(parent_segments, pchain))
            pk_filter = " and ".join(f"{k} eq {odata_literal(v)}" for k, v in lp_key.items())
            lp_pks = self._own_primary_keys_for_et(
                self._entity_type_for(CONTAINED_PATH_SEP.join(parent_segments), namespace)
            )
            expand_url = (
                f"{lp_coll}?$select={','.join(lp_pks)}&$filter={pk_filter}"
                f"&$expand={leaf_nav}($orderby={cursor_field} desc;$top=1;$select={cursor_field})"
            )
            exp_rows, _ = self._fetch_one_expand_page(expand_url)
            children = (exp_rows[0].get(leaf_nav) if exp_rows else None) or []
            inner_max = max(
                (c.get(cursor_field) for c in children if c.get(cursor_field) is not None),
                default=None,
            )
            if inner_max == direct_max:
                return ("ok", None)
            return (
                "error",
                "cursor_probe=nested-expand requires the source to honour $orderby/$top "
                f"inside $expand, but {self._build_contained_path(segments, full_chain)!r} "
                f"returned {inner_max!r} as its newest {leaf_nav} via $expand when the "
                f"true newest is {direct_max!r} (direct navigation). This server "
                "silently mis-orders inner $expand, so cursor_probe would drop changed "
                "rows. Use cursor_probe=batch or cursor_probe=auto (which falls back to "
                "$batch / the plain N+1 walk), or cursor_probe=false for the plain walk.",
            )

        def _with_probe_ok(self, offset: dict) -> dict:
            """Return ``offset`` carrying the persisted ``cursor_probe_ok`` flag.

            Records that this server's inner-``$expand`` ordering has been verified
            so a per-batch-recreated reader can skip the capability preflight next
            batch (see :meth:`_verify_cursor_probe_support`). Never mutates the
            input — the framework may retain the prior offset object — and is a
            no-op (returns the same object) when the flag is already present, so an
            idled overlap re-read that returns ``start_offset`` keeps its identity.
            The flag carries no cursor progress; :meth:`_finalize_cursor_read`
            excludes it from the no-progress comparison."""
            if offset.get("cursor_probe_ok"):
                return offset
            return {**offset, "cursor_probe_ok": True}

        def _with_batch_ok(self, offset: dict) -> dict:
            """Return ``offset`` carrying the persisted ``batch_ok`` flag — the
            ``$batch`` analogue of :meth:`_with_probe_ok`. Records that the server
            accepts OData ``$batch`` so a per-batch-recreated reader skips the
            capability POST next batch. Never mutates the input; no-op when already
            present. The flag carries no cursor progress (excluded from the
            no-progress comparison in :meth:`_finalize_cursor_read`)."""
            if offset.get("batch_ok"):
                return offset
            return {**offset, "batch_ok": True}

        def _batch_relative(self, url: str) -> str:
            """Make ``url`` service-root-relative for a JSON ``$batch`` sub-request.

            The OData v4 JSON batch format resolves a sub-request ``url`` against the
            service root, so an absolute URL under the root is stripped to its
            remainder; an already-relative URL (e.g. a resolved ``@odata.nextLink``
            that came back service-relative) is returned without a leading slash."""
            root = self.service_url if self.service_url.endswith("/") else self.service_url + "/"
            if url.startswith(root):
                return url[len(root) :]
            parsed = urlparse(url)
            if parsed.scheme:
                return parsed.path.lstrip("/") + (f"?{parsed.query}" if parsed.query else "")
            return url.lstrip("/")

        def _post_batch(self, urls: list[str]) -> list[dict]:
            """POST one OData v4 JSON ``$batch`` of GET sub-requests; return the
            per-sub-request response objects in the SAME order as ``urls``.

            Routes through :meth:`_http_get` with ``method="POST"`` so the batch
            shares the connector's throttle / transient / token-refresh retry path.
            Caller must keep ``len(urls) <= _BATCH_MAX_OPS``. Raises if the batch
            envelope itself fails (non-2xx, malformed JSON, or a missing sub-response
            id); per-sub-request HTTP errors are carried inside the envelope for the
            caller to inspect."""
            session = self._get_session()
            payload = {
                "requests": [
                    {"id": str(i), "method": "GET", "url": self._batch_relative(u)}
                    for i, u in enumerate(urls)
                ]
            }
            batch_url = join_url(self.service_url, "$batch")
            resp = self._http_get(session, batch_url, method="POST", json=payload)
            if resp.status_code >= 400:
                raise RuntimeError(
                    f"OData $batch POST to {batch_url!r} failed: "
                    f"{resp.status_code} {(resp.text or '')[:300]}"
                )
            data = resp.json()
            by_id = {str(r.get("id")): r for r in data.get("responses", [])}
            out = []
            for i in range(len(urls)):
                if str(i) not in by_id:
                    raise RuntimeError(
                        f"OData $batch response from {batch_url!r} is missing "
                        f"sub-response id {i!r}; got ids {sorted(by_id)}."
                    )
                out.append(by_id[str(i)])
            return out

        def _verify_batch_support(
            self,
            segments: list[str],
            table_options: dict[str, str] | None,
            start_offset: dict | None = None,
        ) -> bool:
            """Whether the server supports OData ``$batch`` (fail-closed).

            Used by ``cursor_probe=batch`` and the ``auto`` cascade to decide
            between a ``$batch`` hydrate and the plain N+1 walk. A pass is cached per
            connector instance and persisted in the resume offset as ``batch_ok``
            (mirrors ``cursor_probe_ok``) so a per-batch-recreated reader skips the
            capability POST. ANY failure — 405/404, a malformed envelope, a non-200
            sub-response, or a transport error — returns ``False`` (never raises);
            the caller degrades to the plain walk."""
            if (start_offset or {}).get("batch_ok"):
                return True
            cached = self.__dict__.get("_batch_supported")
            if cached is not None:
                return cached
            probe_url = join_url(self.service_url, segments[0]) + "?$top=1"
            ok = False
            try:
                session = self._get_session()
                payload = {
                    "requests": [{"id": "0", "method": "GET", "url": self._batch_relative(probe_url)}]
                }
                # SINGLE attempt (not the retrying ``_http_get``): a capability probe
                # must fail FAST. A server that lacks ``$batch`` returns 405/404 (or
                # the transport errors), and running the transient-retry/backoff loop
                # on that would stall every ``auto`` read by tens of seconds before
                # giving up. A transient blip here just falls back to the plain walk
                # for this batch and is re-probed next batch (nothing is persisted).
                resp = session.post(
                    join_url(self.service_url, "$batch"), json=payload, timeout=self.timeout
                )
                if resp.status_code < 400:
                    subs = resp.json().get("responses") or []
                    ok = bool(subs) and int(subs[0].get("status", 0) or 0) < 400
            except Exception:  # capability probe — any failure means "unsupported"
                ok = False
            self.__dict__["_batch_supported"] = ok
            return ok

        def _read_contained_snapshot(
            self, table_name: str, table_options: dict[str, str]
        ) -> tuple[Iterator[dict], dict]:
            """Walk the parent-key tree N+1 and emit leaf rows tagged with
            ancestor FKs, streamed lazily.

            Rows are yielded as each leaf page is fetched; no full
            materialisation. On wide subtrees (many parents, many pages
            per parent) this keeps peak memory bounded by one page worth
            of rows rather than the whole result set.
            """
            segments = parse_contained_path(table_name) or [table_name]
            namespace = (table_options or {}).get("namespace")
            fk_columns = self._resolve_fk_columns(segments, namespace)
            segment_filters = resolve_segment_filters(table_options, segments)
            leaf_extra = segment_filters.get(len(segments) - 1)
            leaf_order_by = self._leaf_pk_order_by(segments, namespace)

            def _emit() -> Iterator[dict]:
                for chain in self._iter_parent_key_chains(segments, namespace, table_options):
                    url = self._build_contained_url(
                        segments, chain, table_options, extra_filter=leaf_extra, order_by=leaf_order_by
                    )
                    for row in self._fetch_pages(url):
                        self._tag_with_ancestor_fks(row, segments, chain, fk_columns)
                        yield row

            return _emit(), {}

        def _warn_expand_inner_truncation_risk(self, segments: list[str]) -> None:
            """Warn when ``expand_contained=true`` runs under ``pagination=nextlink``.

            In nextlink mode the client-driven inner-``$expand`` continuation is
            disabled (:meth:`_inner_expand_continuation_url` returns ``None``), so a
            server that page-limits a nested ``$expand`` while omitting its
            ``<NavProp>@odata.nextLink`` silently drops the deeper rows (the exact
            failure this guard exists to surface). The default ``auto`` — and
            ``keyset``/``skip`` — drain those collections themselves; nextlink mode
            trusts the server's links entirely.

            (A missing ``$top`` is a related risk — the drainer can't size a
            continuation without one — but ``read_table`` always defaults
            ``page_size`` for the client-driven modes, and nextlink mode is caught
            here regardless, so that case can't independently arise.)
            """
            if len(segments) < 2:
                return
            if getattr(self, "_pagination", "nextlink") == "nextlink":
                _LOG.warning(
                    "expand_contained=true with pagination=nextlink on %r: if the "
                    "server page-limits a nested $expand collection without emitting "
                    "its <NavProp>@odata.nextLink, the deeper rows (e.g. changed "
                    "leaf-level records) are silently dropped. Use the default "
                    "pagination=auto so the connector drains inner collections "
                    "itself.",
                    CONTAINED_PATH_SEP.join(segments),
                )

        def _read_contained_expand(
            self,
            table_name: str,
            start_offset: dict | None,
            table_options: dict[str, str],
        ) -> tuple[Iterator[dict], dict]:
            """Iterative work-queue pull driven by nested ``$expand``;
            flatten each response into leaf rows tagged with ancestor FKs.
            When ``cursor_field`` is set, a ``$filter``/``$orderby`` is
            injected at the closest segment that owns the cursor (top-level
            query or inner ``$expand``), restricting the response to
            changed subtrees. Emitted leaf rows are stamped with the cursor
            value from that segment when they don't carry it themselves.
            Server depth caps surface as HTTP 4xx — no client-side
            fallback.

            The pull is capped at ``max_records_per_batch`` rows (default
            10000). When the cap fires, the remaining work queue — a list
            of self-contained ``{url, level, chain, cur_val, skip}`` fetch
            tasks (see ``_drain_expand_pages``) — is parked in the resume
            offset as ``pending_fetches`` so the next ``read()`` call
            resumes exactly where it left off: top-level pagination,
            inner-collection ``@odata.nextLink`` follows, and mid-page row
            positions all live in the queue. For cursor mode the watermark
            only advances once the chain fully drains — mid-chain advance
            would skip unread rows under the same ``since``. While a chain
            is in flight the running max cursor lives at
            ``running_max_cursor`` in the offset; on chain completion it
            becomes the new ``cursor`` value.
            """
            segments = parse_contained_path(table_name) or [table_name]
            if len(segments) < 2:
                raise ValueError(f"expand_contained requires a contained path; {table_name!r} is flat.")
            namespace = (table_options or {}).get("namespace")
            cursor_field = (table_options or {}).get("cursor_field")
            # Resolve the read-floor window for THIS read (static value, or the
            # ``auto`` measurement carried in the offset) before building the
            # cursor clause — ``_apply_cursor_lookback`` reads it off ``self``.
            self._active_lookback_seconds = self._resolve_active_lookback(start_offset)
            cursor_level, cursor_filter, cursor_order, cursor_select = self._cursor_expand_clause(
                segments, namespace, cursor_field, (start_offset or {}).get("cursor")
            )
            # Read-scoped context the flatten recursion needs to synthesize a
            # client-driven continuation for an inner collection whose
            # ``<NavProp>@odata.nextLink`` the server omitted (see
            # ``_build_expand_continuation_url``). Stashed on ``self`` — like
            # ``self._pagination`` — so it survives into the lazy streaming
            # generator without threading through every flatten call site.
            self._expand_cont_opts = table_options
            self._expand_cont_since = (start_offset or {}).get("cursor")
            if cursor_field and cursor_level == -1:
                raise ValueError(
                    f"cursor_field={cursor_field!r} is not a property of any "
                    f"segment in {table_name!r}."
                )
            pks_per_level: list[list[str]] = []
            for idx in range(len(segments) - 1):
                et = self._entity_type_for(CONTAINED_PATH_SEP.join(segments[: idx + 1]), namespace)
                pks = self._own_primary_keys_for_et(et)
                if not pks:
                    raise ValueError(
                        f"Cannot $expand contained path: segment {segments[idx]!r} "
                        f"has no primary key declared in $metadata."
                    )
                pks_per_level.append(pks)
            fk_columns = self._resolve_fk_columns(segments, namespace)
            max_records = int((table_options or {}).get("max_records_per_batch", "10000"))
            # Either resume from a parked work queue or seed it with the
            # top-level URL. Each queue item is self-contained (URL +
            # level + ancestor chain + captured cursor) so resume needs
            # no URL rebuild.
            pending_in = (start_offset or {}).get("pending_fetches")
            if pending_in:
                initial_queue = list(pending_in)
                resuming = True
            else:
                initial_queue = [
                    {
                        "url": self._build_expand_url(
                            segments,
                            table_options,
                            cursor_level=cursor_level if cursor_field else None,
                            cursor_filter=cursor_filter,
                            cursor_order=cursor_order,
                            cursor_select=cursor_select,
                        ),
                        "level": 0,
                        "chain": [],
                        "cur_val": None,
                        "skip": 0,
                    }
                ]
                resuming = False
            ctx = (cursor_field, cursor_level, None) if cursor_field else None
            # The page_size budget (``None`` when unset — no ``$top`` is sent at
            # any level). The drainer/streamer re-derive the per-level ``$top``
            # distribution per work item from its root level (see
            # :func:`compute_expand_tops_for_root`), so a continuation rooted deep
            # in the chain budgets across only its own collection levels rather than
            # the whole chain.
            page_size_opt = (table_options or {}).get("page_size")
            page_size = int(page_size_opt) if page_size_opt else None
            self._warn_expand_inner_truncation_risk(segments)
            if start_offset is None:
                # Batch reader: offset discarded, ``since`` is None (no cursor
                # filter), cap disabled, guard skipped — so the ``emitted``
                # accumulation the drainer does serves nothing. Stream leaf
                # rows one response at a time so an uncapped batch doesn't
                # materialise the whole result set. See ``read_table``.
                return (
                    self._stream_expand_pages(
                        initial_queue, segments, pks_per_level, fk_columns, ctx, page_size
                    ),
                    {},
                )
            emitted: list[dict] = []
            # Wall-clock around the eager drain measures this batch's walk time,
            # feeding the ``auto`` lookback window (see ``_attach_lookback_state``).
            drain_start = time.monotonic()
            remaining_queue = self._drain_expand_pages(
                initial_queue,
                max_records,
                segments,
                pks_per_level,
                fk_columns,
                emitted,
                ctx,
                page_size,
            )
            drain_elapsed = time.monotonic() - drain_start
            end_offset = self._build_expand_end_offset(
                emitted, cursor_field, start_offset, remaining_queue
            )
            if not cursor_field:
                return iter(emitted), end_offset
            if not emitted and not resuming:
                return iter([]), start_offset or {}
            records, out_offset = self._finalize_cursor_read(
                start_offset, end_offset, emitted, table_name, cursor_field
            )
            return records, self._attach_lookback_state(
                out_offset, start_offset, bool(remaining_queue), drain_elapsed
            )

        # pylint: disable=too-many-arguments,too-many-positional-arguments,too-many-locals
        def _drain_expand_pages(
            self,
            initial_queue: list[dict],
            max_records: int,
            segments: list[str],
            pks_per_level: list[list[str]],
            fk_columns: dict[str, str],
            emitted: list[dict],
            ctx: tuple | None,
            page_size: int | None,
        ) -> list[dict]:
            """Iterative work-queue processor.

            Each queue item is a self-contained "fetch this URL and
            process the rows it returns" task::

                {
                    "url":     str,              # HTTP URL to GET (one page)
                    "level":   int,              # level the URL's rows live at
                    "chain":   list[dict],       # ancestor PK chain (snapshot)
                    "cur_val": Any | None,       # captured cursor value
                    "skip":    int,              # top_row index to start at
                }

            Items are popped FIFO; each pop performs ONE HTTP fetch and
            processes its top_rows starting from ``skip``. Inner-collection
            ``@odata.nextLink`` values discovered during a row's inline
            descent are APPENDED to the queue (via
            ``_flatten_expand_response``'s ``pending_fetches`` arg) rather
            than followed inline. After each fully-processed top_row the
            ``max_records`` cap is checked: when exceeded, the current
            item is re-queued at the front with ``skip`` advanced past the
            rows just emitted, and the loop exits. The returned queue is
            the work left to do — non-empty means "continuation pending",
            empty means "chain drained".

            Cap deviation per batch is bounded by ONE HTTP response's
            worth of leaf rows (≤ ``page_size``), not by the size of a
            single top_row's subtree as in the previous design.
            """
            # Take ownership: mutated in-place by appends from
            # ``_flatten_expand_response`` and by our own front re-queues.
            queue: list[dict] = list(initial_queue)
            cur_field, cur_level, _ = ctx or (None, -1, None)
            while queue and len(emitted) < max_records:
                item = queue.pop(0)
                url = item["url"]
                level = item["level"]
                chain = [dict(p) for p in item.get("chain") or []]
                cur_val = item.get("cur_val")
                skip = int(item.get("skip", 0) or 0)
                item_ctx = (cur_field, cur_level, cur_val) if cur_field else None
                # Tops budgeted over only THIS request's collection levels
                # (root == item level downward); ancestors above are fixed keys.
                item_tops = (
                    compute_expand_tops_for_root(page_size, len(segments), level) if page_size else None
                )
                # Fetch one page only — pulling further pages of THIS
                # collection waits until the next dequeue so we can check
                # the cap between them.
                page_rows, page_next_url = self._fetch_one_expand_page(url)
                if not page_rows:
                    if page_next_url:
                        queue.append(
                            {
                                "url": page_next_url,
                                "level": level,
                                "chain": [dict(p) for p in chain],
                                "cur_val": cur_val,
                                "skip": 0,
                            }
                        )
                    continue
                truncated = False
                for row_idx in range(skip, len(page_rows)):
                    self._flatten_expand_response(
                        level,
                        page_rows[row_idx],
                        segments,
                        pks_per_level,
                        chain,
                        fk_columns,
                        emitted,
                        item_ctx,
                        item_tops,
                        response_url=url,
                        pending_fetches=queue,
                        page_size=page_size,
                    )
                    if len(emitted) >= max_records and row_idx + 1 < len(page_rows):
                        # Mid-page: re-queue the SAME URL at the front so
                        # the next batch resumes here without scrambling
                        # depth ordering.
                        queue.insert(
                            0,
                            {
                                "url": url,
                                "level": level,
                                "chain": [dict(p) for p in chain],
                                "cur_val": cur_val,
                                "skip": row_idx + 1,
                            },
                        )
                        truncated = True
                        break
                if not truncated and page_next_url:
                    queue.append(
                        {
                            "url": page_next_url,
                            "level": level,
                            "chain": [dict(p) for p in chain],
                            "cur_val": cur_val,
                            "skip": 0,
                        }
                    )
            return queue

        def _stream_expand_pages(
            self,
            initial_queue: list[dict],
            segments: list[str],
            pks_per_level: list[list[str]],
            fk_columns: dict[tuple[str, str], str],
            ctx: tuple | None,
            page_size: int | None,
        ) -> Iterator[dict]:
            """Lazy variant of :meth:`_drain_expand_pages` for the batch reader.

            Pops fetch tasks FIFO, fetches one page each, flattens that page's
            rows into a short-lived local buffer and yields them, deferring
            inner-collection ``@odata.nextLink`` continuations back onto the
            queue exactly as the drainer does. No ``max_records`` cap and no
            cross-page accumulation: peak memory is one response's flattened
            cross-product (bounded by the ``page_size`` budget) plus the queue
            of pending fetch descriptors (URLs + chains, not rows). Emission
            order matches the drainer's ``emitted`` order — inline rows first,
            deferred continuations processed when their queue item is popped."""
            queue: list[dict] = list(initial_queue)
            cur_field, cur_level, _ = ctx or (None, -1, None)
            while queue:
                item = queue.pop(0)
                url = item["url"]
                level = item["level"]
                chain = [dict(p) for p in item.get("chain") or []]
                cur_val = item.get("cur_val")
                skip = int(item.get("skip", 0) or 0)
                item_ctx = (cur_field, cur_level, cur_val) if cur_field else None
                item_tops = (
                    compute_expand_tops_for_root(page_size, len(segments), level) if page_size else None
                )
                page_rows, page_next_url = self._fetch_one_expand_page(url)
                if not page_rows:
                    if page_next_url:
                        queue.append(
                            {
                                "url": page_next_url,
                                "level": level,
                                "chain": [dict(p) for p in chain],
                                "cur_val": cur_val,
                                "skip": 0,
                            }
                        )
                    continue
                for row_idx in range(skip, len(page_rows)):
                    local_out: list[dict] = []
                    self._flatten_expand_response(
                        level,
                        page_rows[row_idx],
                        segments,
                        pks_per_level,
                        chain,
                        fk_columns,
                        local_out,
                        item_ctx,
                        item_tops,
                        response_url=url,
                        pending_fetches=queue,
                        page_size=page_size,
                    )
                    yield from local_out
                if page_next_url:
                    queue.append(
                        {
                            "url": page_next_url,
                            "level": level,
                            "chain": [dict(p) for p in chain],
                            "cur_val": cur_val,
                            "skip": 0,
                        }
                    )

        def _fetch_one_expand_page(self, url: str) -> tuple[list[dict], str | None]:
            """One HTTP GET; returns ``(page_rows, next_url)``. Thin wrapper
            over :meth:`_fetch_pages_with_links` that consumes a single
            iteration so the caller can check the cap between fetches.

            No-progress guard for the work-queue drainers: those slice pagination
            one page per call, so the in-generator guard in
            :meth:`_client_paginate_pages` is bypassed. The drainer instead drops
            the link when the resolved next URL equals the one we just fetched —
            i.e. the continuation didn't advance (server ignored the seek/``$skip``,
            or a self-referential ``@odata.nextLink``) — so the collection stops
            instead of looping forever.

            A continuation must keep going past a SHORT page, because a server that
            page-limits below the requested ``$top`` while omitting
            ``@odata.nextLink`` returns short pages that are NOT exhaustion —
            stopping there silently drops the rest of the inner collection (and in
            cursor mode the watermark then advances past the dropped rows, losing
            them permanently). The optimization that budgets a deep continuation's
            ``$top`` up to ``page_size`` makes this the common case: ``$top`` now
            routinely exceeds the server's per-response cap, so every continuation
            page is short. :meth:`_fetch_pages_with_links` drains short link-less
            pages; draining is safe even though its in-generator guard can't span
            these per-page re-entries: for keyset/skip the next seek differs from the
            current URL only when rows advanced, so a server that ignores the seek
            trips the ``page_next_url == url`` guard after at most one repeated page
            — and a repeated row is deduped at the destination by ``apply_changes``'
            MERGE on the primary key (a harmless duplicate, vs. the data loss a
            short-page stop causes)."""
            for page_rows, page_next_url in self._fetch_pages_with_links(url):
                return page_rows, (None if page_next_url == url else page_next_url)
            return [], None

        def _build_expand_end_offset(
            self,
            emitted: list[dict],
            cursor_field: str | None,
            start_offset: dict | None,
            pending_queue: list[dict],
        ) -> dict:
            """Compose the resume offset for ``_read_contained_expand``.

            Three modes:

            * **Snapshot, chain in flight** → ``{pending_fetches: [...]}``.
            * **Snapshot, chain done** → ``{}`` (framework treats as
              terminal).
            * **Cursor mode** → the watermark stays at the original
              ``since`` while a chain is in flight, with the running max
              parked at ``running_max_cursor``. On chain exhaustion the
              running max becomes the new ``cursor`` value.

            ``pending_fetches`` is the work queue parked for the next
            batch — each entry is a self-contained
            ``{url, level, chain, cur_val, skip}`` (see
            :meth:`_drain_expand_pages`).
            """
            in_flight = bool(pending_queue)
            if not cursor_field:
                return {"pending_fetches": list(pending_queue)} if in_flight else {}
            prior_running = (start_offset or {}).get("running_max_cursor")
            batch_cursors = [r.get(cursor_field) for r in emitted if r.get(cursor_field) is not None]
            if batch_cursors and prior_running is not None:
                new_running = max([*batch_cursors, prior_running])
            elif batch_cursors:
                new_running = max(batch_cursors)
            else:
                new_running = prior_running
            since = (start_offset or {}).get("cursor")
            if in_flight:
                offset: dict = {"pending_fetches": list(pending_queue)}
                if since is not None:
                    offset["cursor"] = since
                if new_running is not None:
                    offset["running_max_cursor"] = new_running
                return offset
            if new_running is not None:
                return {"cursor": new_running}
            if since is not None:
                return {"cursor": since}
            # Chain drained AND no watermark to park (no prior ``since``, no
            # ``running_max_cursor``, no new cursor values this batch).
            # Returning ``dict(start_offset or {})`` would echo a resume
            # input like ``{"pending_fetches": [...]}`` back unchanged —
            # ``_read_contained_expand`` then sees ``start_offset ==
            # end_offset`` with ``emitted`` empty and returns the same
            # offset, and the framework re-issues it forever. Return ``{}``
            # so the offset advances and the chain terminates cleanly.
            return {}

        def _cursor_expand_clause(
            self,
            segments: list[str],
            namespace: str | None,
            cursor_field: str | None,
            since: Any,
        ) -> tuple[int, str | None, str | None, str | None]:
            """``(cursor_level, $filter, $orderby, $select)`` for ``$expand``
            mode. Returns ``(-1, None, None, None)`` when no cursor is set;
            the caller raises if the cursor isn't a property of any segment.
            ``$select`` is non-empty only when the cursor lives on a non-top
            segment — it forces the server to project the cursor column on
            the expanded ancestor (some servers default-omit it)."""
            if not cursor_field:
                return -1, None, None, None
            cursor_level = self._find_cursor_level(segments, namespace, cursor_field)
            if cursor_level == -1:
                return -1, None, None, None
            level_et = self._entity_type_for(
                CONTAINED_PATH_SEP.join(segments[: cursor_level + 1]), namespace
            )
            level_pks = self._own_primary_keys_for_et(level_et)
            order_terms = [f"{cursor_field} asc"]
            order_terms.extend(f"{p} asc" for p in level_pks if p != cursor_field)
            # No ``$select`` injection: the cursor column is returned by
            # default projection on declared CSDL properties, so it isn't
            # needed for stamping. Adding it silently trims other columns
            # the user didn't opt out of — particularly harmful when the
            # cursor segment is also the leaf (2-segment paths). Users who
            # want to trim can set ``select`` themselves on the leaf side.
            # Read floor lags the committed watermark by ``cursor_lookback_seconds``
            # so a non-atomic ``expand_contained=true`` walk re-scans rows that
            # arrived mid-walk and landed below the walk's final max (see
            # ``_apply_cursor_lookback``). Only the read filter is floored; the
            # committed watermark stays the true max of emitted rows
            # (``_build_expand_end_offset``), so the offset still advances.
            read_since = self._apply_cursor_lookback(since)
            return (
                cursor_level,
                self._cursor_filter(cursor_field, read_since),
                ",".join(order_terms),
                None,
            )

        # pylint: disable=too-many-arguments,too-many-positional-arguments,too-many-locals
        def _flatten_expand_response(
            self,
            level: int,
            row: dict,
            segments: list[str],
            pks_per_level: list[list[str]],
            chain: list[dict[str, Any]],
            fk_columns: dict[tuple[str, str], str],
            out: list[dict],
            cursor_ctx: tuple[str | None, int, Any] | None = None,
            per_level_tops: list[int] | None = None,
            response_url: str | None = None,
            pending_fetches: list[dict] | None = None,
            page_size: int | None = None,
        ) -> None:
            """Recurse into the nested $expand payload; tag and emit leaf rows.
            ``cursor_ctx`` is ``(cursor_field, cursor_level, captured_value)``
            threaded down the recursion: when ``level == cursor_level`` the
            captured value snaps to ``row[cursor_field]`` and propagates to
            every leaf row beneath, stamped only when the leaf doesn't
            already carry the column.

            OData v4 §11.2.6.1: when an expanded collection is server-paged
            the response carries a ``<NavProp>@odata.nextLink`` annotation
            alongside the inline page. The spec requires that link to
            preserve the original ``$expand`` chain, so following it yields
            the rest of the children with their grandchildren still
            expanded.

            ``per_level_tops`` is the per-level ``$top`` distribution from
            the initial request (see :func:`compute_dynamic_tops`). When
            deferring an inner-collection nextLink to the work queue, the
            connector rewrites the URL's ``$top`` to a value sized for
            that continuation's smaller cross-product, so wide inner
            collections don't take 100s of round trips paging at the
            original per-level ``$top``.

            ``response_url`` is the URL of the HTTP response that yielded
            ``row``. Used to resolve any relative ``<NavProp>@odata.nextLink``
            per OData v4 §11.2.5.7 / RFC 3986 (relative-reference
            resolution against the document's base URL). Falls back to
            ``service_url`` when not provided (only the unit tests do that).

            ``pending_fetches`` is the per-batch work queue used by
            :meth:`_drain_expand_pages`. Inner-collection nextLinks are
            APPENDED to it instead of followed inline — that lets the
            outer drainer check ``max_records_per_batch`` between fetches
            (at any level) rather than only after a full top-row subtree.
            The append captures the chain snapshot + captured cursor so
            the work item is self-contained for cross-batch resume.
            """
            base_url = response_url or self.service_url
            cur_field, cur_level, cur_val = cursor_ctx or (None, -1, None)
            if cur_field and level == cur_level:
                cur_val = row.get(cur_field)
            if level == len(segments) - 1:
                # Drop both top-level (``@odata.foo``) and per-property
                # (``Foo@odata.nextLink``) annotations from leaf rows; the
                # framework wouldn't know what to do with either.
                clean = {k: v for k, v in row.items() if "@odata." not in k}
                self._tag_with_ancestor_fks(clean, segments, chain, fk_columns)
                if cur_field and cur_val is not None and clean.get(cur_field) is None:
                    clean[cur_field] = cur_val
                out.append(clean)
                return
            pks = pks_per_level[level]
            chain.append({pk: row.get(pk) for pk in pks})
            next_ctx = (cur_field, cur_level, cur_val) if cur_field else None
            next_seg = segments[level + 1]
            for child in row.get(next_seg) or []:
                self._flatten_expand_response(
                    level + 1,
                    child,
                    segments,
                    pks_per_level,
                    chain,
                    fk_columns,
                    out,
                    next_ctx,
                    per_level_tops,
                    response_url=base_url,
                    pending_fetches=pending_fetches,
                    page_size=page_size,
                )
            inner_next = row.get(f"{next_seg}@odata.nextLink")
            if inner_next:
                resolved = urljoin(base_url, inner_next)
                if per_level_tops:
                    # Continuation pages the collection at ``level + 1``
                    # under one specific parent at ``level``. The original
                    # ``$top`` for that level was sized against the FULL
                    # cross-product budget (top × inner × …); the
                    # continuation is one outer level shallower, so we
                    # have more budget to spend per response. New $top is
                    # ``page_size_budget / inner_product`` where
                    # ``inner_product`` is the cross-product of all levels
                    # deeper than ``level + 1`` (which the server-side
                    # ``$expand`` chain in the nextLink still applies).
                    continuation_level = level + 1
                    inner_product = 1
                    for t in per_level_tops[continuation_level + 1 :]:
                        inner_product *= t
                    # Budget is the full page_size: the ancestors 0..level are a
                    # single fixed parent in the continuation, so they don't
                    # multiply. ``page_size`` is passed explicitly rather than
                    # re-derived from per_level_tops, whose entries below this
                    # request's root level are placeholders. (per_level_tops is only
                    # truthy when page_size was set, so page_size is present here.)
                    new_top = max(MIN_DYNAMIC_TOP, (page_size or 0) // max(1, inner_product))
                    resolved = rewrite_top_in_url(resolved, new_top)
            else:
                # No ``<NavProp>@odata.nextLink``. In a client-driven pagination
                # mode (keyset/skip/auto), synthesize a direct-navigation
                # continuation when the inline page is a FULL page (== $top) and
                # so plausibly truncated; otherwise the inline page is taken as
                # the whole collection — today's nextlink-only behaviour. This
                # closes the inner-``$expand`` hole for servers that page-limit a
                # response but never emit the continuation link.
                resolved = self._inner_expand_continuation_url(
                    level, row, segments, chain, next_ctx, per_level_tops
                )
            if resolved is not None:
                if pending_fetches is not None:
                    # Defer the follow: the outer drainer pops one fetch
                    # at a time and checks the cap between them. Snapshot
                    # the ancestor chain so the work item is self-contained
                    # for cross-batch resume.
                    pending_fetches.append(
                        {
                            "url": resolved,
                            "level": level + 1,
                            "chain": [dict(p) for p in chain],
                            "cur_val": cur_val,
                            "skip": 0,
                        }
                    )
                    chain.pop()
                    return
                # Track the URL that fetched each follow-up page so its
                # children resolve THEIR relative nextLinks correctly. In
                # keyset/skip mode ``_fetch_pages_with_links`` drives the
                # continuation via ``_client_paginate_pages`` (the synthesized
                # URL carries the seek/skip), draining the whole collection.
                inner_current = resolved
                for page_rows, page_next in self._fetch_pages_with_links(resolved):
                    for child in page_rows:
                        self._flatten_expand_response(
                            level + 1,
                            child,
                            segments,
                            pks_per_level,
                            chain,
                            fk_columns,
                            out,
                            next_ctx,
                            per_level_tops,
                            response_url=inner_current,
                        )
                    inner_current = page_next or inner_current
            chain.pop()

        def _inner_expand_continuation_url(
            self,
            level: int,
            row: dict,
            segments: list[str],
            chain: list[dict[str, Any]],
            cursor_ctx: tuple[str | None, int, Any] | None,
            per_level_tops: list[int] | None,
        ) -> str | None:
            """Synthesize a client-driven continuation for a parent's inner
            collection when the server returned a *full* inline page but omitted
            its ``<NavProp>@odata.nextLink``.

            Returns ``None`` unless ``pagination`` is keyset/skip/auto, ``$top``
            is in force (``per_level_tops`` set), and the inline child page is
            exactly ``$top`` rows (so it's plausibly truncated). A short page is
            proof the collection is complete, so it's taken at face value.
            """
            mode = getattr(self, "_pagination", "nextlink")
            if mode == "nextlink" or per_level_tops is None:
                return None
            child_level = level + 1
            if child_level >= len(segments):
                return None
            children = row.get(segments[child_level]) or []
            if not children:
                # Empty inline collection: an ``$expand`` returns ``[]`` for a
                # genuinely empty child collection, and there's no boundary row
                # to seek past — nothing to continue.
                return None
            # A SHORT inline page is NOT proof the collection is complete: a
            # server may page-limit a nested ``$expand`` below the requested
            # ``$top`` while omitting its ``<NavProp>@odata.nextLink`` (its
            # inner page size is smaller than our computed per-level ``$top``).
            # Mirroring the top-level ``auto`` contract (:meth:`_client_paginate_pages`
            # — seek until EMPTY, not until short), synthesize a continuation
            # past the last inline child on ANY non-empty page. When the inline
            # page was in fact complete the continuation's first page comes back
            # empty and the walk stops, costing one trailing empty request per
            # parent — the same price top-level ``auto`` pays. This closes the
            # silent-truncation hole that drops changed deep-level rows on
            # servers that don't emit inner-``$expand`` continuation links
            # (previously this returned ``None`` whenever the inline page was
            # shorter than the per-level ``$top``, taking a short page as proof
            # of exhaustion).
            cur_field = cursor_ctx[0] if cursor_ctx else None
            return self._build_expand_continuation_url(
                segments, level, chain, cur_field, mode, children[-1], len(children)
            )

        # pylint: disable=too-many-arguments,too-many-positional-arguments,too-many-locals
        def _build_expand_continuation_url(
            self,
            segments: list[str],
            level: int,
            chain: list[dict[str, Any]],
            cursor_field: str | None,
            mode: str,
            last_child: dict,
            inline_count: int,
        ) -> str:
            """Direct-navigation URL paging the inner collection at ``level + 1``
            under the single parent identified by the current flatten ``chain``
            (keys for levels ``0..level``), with the grandchildren still
            ``$expand``-ed::

                Parent(k0)/.../Child?$top=N&$orderby=...&$expand=<grandchildren>

            plus a continuation marker that resumes *after* the inline page: a
            ``(k gt last_child)`` keyset seek on the ``$orderby`` keys (keyset /
            auto), or ``$skip=<inline_count>`` (skip, or keyset with a null
            boundary value). Fed back through :meth:`_fetch_pages_with_links`,
            which — in these modes — drives the rest of the collection via
            :meth:`_client_paginate_pages`.

            The cursor ``$filter``/``$orderby`` are re-derived from the read's
            stashed options so a child-level cursor stays applied across the
            continuation; the keyset seek subsumes ``cursor gt since`` for keyset
            mode, and the explicit cursor ``$filter`` keeps the filtered set
            intact for ``$skip``.
            """
            table_options = getattr(self, "_expand_cont_opts", None) or {}
            since = getattr(self, "_expand_cont_since", None)
            namespace = table_options.get("namespace")
            if cursor_field:
                cursor_level, cursor_filter, cursor_order, cursor_select = self._cursor_expand_clause(
                    segments, namespace, cursor_field, since
                )
            else:
                cursor_level, cursor_filter, cursor_order, cursor_select = -1, None, None, None
            child_level = level + 1
            # ``chain`` holds keys for levels 0..level (== child_level - 1), so it
            # has exactly the prefix-key count ``_build_contained_path`` needs to
            # root the request at this parent's child collection.
            contained_base = join_url(
                self.service_url,
                self._build_contained_path(segments[: child_level + 1], chain),
            )
            # Budget the continuation's $top over only its own collection levels
            # (child_level..leaf); levels 0..level are now fixed keys in the path, so
            # they take no share. This is what gives the inner collection a real
            # $top (e.g. [100, 10] for the last two levels) rather than the
            # whole-chain floor (… 5, 5) the initial root-0 distribution would force.
            page_size_opt = table_options.get("page_size")
            cont_tops = (
                compute_expand_tops_for_root(int(page_size_opt), len(segments), child_level)
                if page_size_opt
                else None
            )
            segment_filters = resolve_segment_filters(table_options, segments)
            url = self._assemble_expand_url(
                contained_base,
                segments,
                child_level,
                table_options,
                segment_filters,
                cursor_level,
                cursor_filter,
                cursor_order,
                cursor_select,
                cont_tops,
            )
            order_keys = _pg_orderby_keys(url)
            if mode in ("keyset", "auto") and order_keys:
                seek = _pg_keyset_filter(order_keys, last_child)
                if seek is not None:
                    # Stash the clean child-level $filter as the keyset base so a
                    # cross-batch resume REPLACES the seek instead of accumulating.
                    return _pg_keyset_seek_url(url, _pg_get_query(url, "$filter"), seek)
            return _pg_set_query(url, "$skip", str(inline_count))

        def _leaf_cursor_order_by(
            self, table_name: str, namespace: str | None, cursor_field: str
        ) -> str:
            """``cursor asc, pk1 asc, ...`` — unique total order so server
            skiptokens don't split same-cursor cohorts."""
            leaf_pks = self._own_primary_keys_for_et(self._entity_type_for(table_name, namespace))
            terms = [f"{cursor_field} asc"]
            terms.extend(f"{pk} asc" for pk in leaf_pks if pk != cursor_field)
            return ",".join(terms)

        def _leaf_pk_order_by(self, segments: list[str], namespace: str | None) -> str:
            """PK-only ``$orderby`` for a full leaf-collection fetch.

            Snapshot, ancestor-cursor, and partition reads pull the whole
            leaf collection under a parent with no cursor ``$filter``. Like
            the ancestor key fetches (``_ancestor_pk_order_by``), these page
            across server skiptokens, and OData v4 §11.2.5.7 doesn't promise
            a stable default order — without an explicit unique ``$orderby``
            the skiptoken can silently drop or duplicate leaf rows. Returns
            ``""`` when the leaf declares no PK (``_format_query_params``
            treats that as "no ``$orderby``")."""
            leaf_et = self._entity_type_for(CONTAINED_PATH_SEP.join(segments), namespace)
            return _ancestor_pk_order_by(self._own_primary_keys_for_et(leaf_et))

        # pylint: disable=too-many-statements
        def _walk_contained_with_cursor(
            self,
            segments: list[str],
            chains_iter: Iterator[list[dict[str, Any]]],
            parent_idx_start: int,
            table_options: dict[str, str],
            order_by: str,
            cursor_field: str,
            since: Any,
            truncated_chain_cursor: Any,
            chain_next_link: str | None,
            max_records: int,
            fk_columns: dict[tuple[str, str], str],
            leaf_segment_filter: str | None = None,
            effective=None,
            skip_null: bool = False,
        ) -> tuple[list[dict], bool, int, str | None, Any]:
            """Drive the per-parent fetch loop (leaf-cursor mode).

            ``chains_iter`` is consumed lazily and the walk stops at the
            first parent that offers a valid resume checkpoint once the
            ``max_records`` cap is reached. Peak memory is normally bounded
            to one chain; the exception is a *complete* parent whose entire
            leaf collection shares a single cursor value (see below), which
            is emitted in full and absorbed into the walk rather than
            checkpointed.

            Resume preference, applied to the chain at ``parent_idx_start``:

            1. ``chain_next_link`` (server skiptoken) — fetched directly,
               bypassing URL rebuild. Used when the previous batch parked
               at a page boundary mid-chain.
            2. ``truncated_chain_cursor`` — used as ``cursor gt <value>``
               in a freshly-built URL. Used when the previous batch dropped
               a trailing same-cursor cohort at a complete-parent boundary.
            3. Otherwise the global ``since`` is used.

            Truncation checkpoint, decided when the cap is hit:

            * **Page boundary** (server returned an ``@odata.nextLink``) →
              ``chain_next_link_out`` is set; resume re-enters this parent.
            * **Complete parent with a distinct-cursor boundary** (no
              nextLink) → the trailing same-cursor cohort is dropped and
              ``truncated_chain_cursor_out`` is set; resume re-reads it.
            * **Complete parent, single cursor value** (no nextLink, no
              splittable boundary) → no checkpoint is possible and none is
              needed: the cohort is complete, so all its rows are kept and
              the walk continues to the next parent. The cap is overshot
              for that one parent (bounded by one server response).

            Returns ``(rows, truncated, parent_idx, chain_next_link_out,
            truncated_chain_cursor_out)``.

            ``effective(row)`` supplies the cursor value used for filtering,
            the boundary trim and (via the caller) the watermark — the
            ``cursor_nulls`` resolver, so a null cursor can resolve to a
            synthetic floor without mutating the emitted row. ``skip_null``
            drops rows with a real null cursor (``cursor_nulls=ignore``)."""
            if effective is None:

                def effective(row):
                    return row.get(cursor_field)

            emitted: list[dict] = []
            truncated = False
            parent_idx = 0
            chain_start_idx = 0
            chain_next_link_out: str | None = None
            truncated_chain_cursor_out: Any = None
            for chain in chains_iter:
                # Skip the chains we already emitted in prior batches. The
                # iterator still pays for the ancestor pages that produce
                # those chains (no way to skip without knowing the keys),
                # but no leaf fetches happen here.
                if parent_idx < parent_idx_start:
                    parent_idx += 1
                    continue
                chain_start_idx = len(emitted)
                chain_since: Any
                initial_url: str
                if parent_idx == parent_idx_start and chain_next_link is not None:
                    # Resume from the server's own skiptoken; no client-side
                    # filter — the link already encodes filter/order state.
                    chain_since = None
                    initial_url = chain_next_link
                else:
                    if parent_idx == parent_idx_start and truncated_chain_cursor is not None:
                        chain_since = truncated_chain_cursor
                    else:
                        chain_since = since
                    initial_url = self._build_contained_url(
                        segments,
                        chain,
                        table_options,
                        extra_filter=combine_filters(
                            self._cursor_filter(cursor_field, chain_since),
                            leaf_segment_filter,
                        ),
                        order_by=order_by,
                    )
                cap_hit_in_page = False
                page_next_url: str | None = None
                # Under the default ``auto``, a
                # server that page-limits a leaf below $top while omitting
                # @odata.nextLink is still drained (keyset seek until empty), so a
                # cursor read isn't silently truncated to one short page. The
                # synthesized seek that surfaces as ``page_next_url`` when the cap is
                # hit mid-leaf is itself the resume checkpoint: a compound
                # ``(cursor gt v) or (cursor eq v and pk gt p)`` seek that re-enters
                # this parent at the exact row, correctly continuing a same-cursor
                # cohort that spans the cap (better than the cursor-only trim below,
                # which is kept for nextlink mode / whole-leaf-in-one-response
                # servers where ``page_next_url`` is None).
                for page_rows, page_next_url in self._fetch_pages_with_links(initial_url):
                    for row in page_rows:
                        if skip_null and row.get(cursor_field) is None:
                            continue
                        rec_cursor = effective(row)
                        if (
                            chain_since is not None
                            and rec_cursor is not None
                            and rec_cursor <= chain_since
                        ):
                            continue
                        self._tag_with_ancestor_fks(row, segments, chain, fk_columns)
                        emitted.append(row)
                        if len(emitted) >= max_records:
                            cap_hit_in_page = True
                    if cap_hit_in_page:
                        # Finish the current page (above) so its nextLink is a
                        # clean checkpoint, then stop fetching more pages of
                        # this chain and decide how to checkpoint below.
                        break
                if cap_hit_in_page:
                    if page_next_url is not None:
                        # Page boundary mid-collection: the server skiptoken is
                        # a clean resume point — park it and re-enter this
                        # parent next batch.
                        truncated = True
                        chain_next_link_out = page_next_url
                        break
                    # No nextLink ⇒ the server returned this parent's ENTIRE
                    # leaf collection, so its cohort is complete. Prefer an
                    # intra-parent boundary: drop the trailing same-cursor
                    # cohort and resume this parent at ``cursor gt`` the last
                    # distinct value (which re-reads that cohort).
                    trimmed = _trim_to_distinct_cursor_boundary(emitted[chain_start_idx:], cursor_field)
                    if trimmed:
                        del emitted[chain_start_idx + len(trimmed) :]
                        truncated = True
                        # Effective value (synthetic floor for a null under
                        # coalesce) so the resumed ``cursor gt`` is a real,
                        # comparable boundary — never the restored-null column.
                        truncated_chain_cursor_out = effective(trimmed[-1])
                        break
                    # Every row of this complete parent shares one cursor value
                    # — no splittable boundary exists, and re-reading the parent
                    # can't make progress. The cohort is COMPLETE, so keep all
                    # its rows and continue to the next parent. The cap is
                    # necessarily overshot for this parent (bounded by one
                    # server response); there is no valid mid-walk checkpoint,
                    # which beats failing the batch. (Formerly a RuntimeError.)
                    parent_idx += 1
                    continue
                parent_idx += 1
            return (
                emitted,
                truncated,
                parent_idx,
                chain_next_link_out,
                truncated_chain_cursor_out,
            )

        # pylint: disable=too-many-arguments,too-many-positional-arguments
        def _batch_walk_contained_with_cursor(
            self,
            segments: list[str],
            chains_iter: Iterator[list[dict[str, Any]]],
            parent_idx_start: int,
            table_options: dict[str, str],
            order_by: str,
            cursor_field: str,
            since: Any,
            max_records: int,
            fk_columns: dict[tuple[str, str], str],
            leaf_segment_filter: str | None = None,
            effective=None,
            skip_null: bool = False,
        ) -> tuple[list[dict], bool, int, None, None]:
            """OData ``$batch`` counterpart to :meth:`_walk_contained_with_cursor`.

            Hydrates leaf collections via ``$batch`` instead of one GET per
            leaf-parent: chains are buffered into groups of :data:`_BATCH_MAX_OPS`,
            each group sent as a single ``$batch`` of ``cursor gt since`` reads with
            **no ``$top``** (server-driven paging), and every per-sub-response
            ``@odata.nextLink`` is re-batched (also capped at ``_BATCH_MAX_OPS``)
            until each collection is drained. Rows go through the same null-skip /
            below-floor trim / FK-tag pipeline as the plain walk, so the emitted set
            is identical — only the request shape differs.

            Resume + cap are **chunk-aligned**: the cap is checked after each
            fully-drained group, so truncation parks ``parent_idx`` at the next group
            boundary. ``chain_next_link`` / ``truncated_chain_cursor`` are unused
            (returned ``None``) — a resumed batch re-enumerates ancestors and skips
            ``parent_idx`` chains exactly like the plain walk. The cap is overshot by
            at most one group's worth of changed rows (the same bounded-overshoot
            tolerance the plain walk applies to a single complete parent).

            Returns the 5-tuple ``(emitted, truncated, parent_idx, None, None)``."""
            if effective is None:

                def effective(row):
                    return row.get(cursor_field)

            emitted: list[dict] = []
            truncated = False
            parent_idx = 0
            group: list[list[dict[str, Any]]] = []
            # Drop ``page_size`` so the per-leaf-parent sub-requests carry NO ``$top``
            # — the server drives paging and emits ``@odata.nextLink`` for any
            # overflow (the keyset/$skip drain the plain ``auto`` walk would use to
            # continue a short link-less page can't run inside a batch sub-request).
            leaf_opts = {k: v for k, v in (table_options or {}).items() if k != "page_size"}

            def _drain_group(buffered: list[list[dict[str, Any]]]) -> None:
                # idx-keyed initial URLs (no $top → server pages + emits nextLink).
                pending: list[tuple[int, str]] = []
                chain_by_key: dict[int, list[dict[str, Any]]] = {}
                for key, chain in enumerate(buffered):
                    pending.append(
                        (
                            key,
                            self._build_contained_url(
                                segments,
                                chain,
                                leaf_opts,
                                extra_filter=combine_filters(
                                    self._cursor_filter(cursor_field, since), leaf_segment_filter
                                ),
                                order_by=order_by,
                            ),
                        )
                    )
                    chain_by_key[key] = chain
                while pending:
                    round_ = pending[:_BATCH_MAX_OPS]
                    pending = pending[_BATCH_MAX_OPS:]
                    responses = self._post_batch([u for _, u in round_])
                    for (key, req_url), resp in zip(round_, responses):
                        body = resp.get("body") if isinstance(resp, dict) else None
                        rows = body.get("value", []) if isinstance(body, dict) else []
                        chain = chain_by_key[key]
                        for row in rows:
                            if skip_null and row.get(cursor_field) is None:
                                continue
                            rec_cursor = effective(row)
                            if since is not None and rec_cursor is not None and rec_cursor <= since:
                                continue
                            clean = {k: v for k, v in row.items() if not k.startswith("@odata.")}
                            self._tag_with_ancestor_fks(clean, segments, chain, fk_columns)
                            emitted.append(clean)
                        raw_next = body.get("@odata.nextLink") if isinstance(body, dict) else None
                        if raw_next:
                            pending.append((key, self._resolve_next_link(req_url, raw_next)))

            for chain in chains_iter:
                if parent_idx < parent_idx_start:
                    parent_idx += 1
                    continue
                group.append(chain)
                parent_idx += 1
                if len(group) >= _BATCH_MAX_OPS:
                    _drain_group(group)
                    group = []
                    if len(emitted) >= max_records:
                        truncated = True
                        break
            else:
                if group:
                    _drain_group(group)
            return (emitted, truncated, parent_idx, None, None)

        def _no_progress_cursor_error(
            self, table_name: str, cursor_field: str, n_emitted: int
        ) -> RuntimeError:
            """Build the RuntimeError the caller raises when a cursor-mode
            batch emitted rows but the offset did not advance. Two causes
            share this symptom: every row's cursor is null (so
            ``running_max`` can't update), or the source returned rows whose
            cursor equals the prior ``since`` (server did not honor
            ``cursor gt``). Committing the rows would loop forever — the
            framework re-issues the same offset; dropping them silently
            would lose data. The caller raises this error so the operator
            sees the cause."""
            return RuntimeError(
                f"emitted {n_emitted} rows from {table_name!r} but cursor_field="
                f"{cursor_field!r} did not advance. Either every row in this "
                f"batch has a null {cursor_field}, or the source returned rows "
                f"whose {cursor_field} equals the prior offset (server did not "
                f"honor `{cursor_field} gt <since>`). Fix the cursor at the "
                f"source (non-nullable, strictly monotonic), exclude offending "
                f"rows with `filter`/`filter_at_<segment>`, or pick a different "
                f"cursor."
            )

        def _finalize_cursor_read(
            self,
            start_offset: dict | None,
            end_offset: dict,
            emitted: list[dict],
            table_name: str,
            cursor_field: str,
        ) -> tuple[Iterator[dict], dict]:
            """Apply the no-progress guard shared by every cursor-mode read
            path. Returns ``(iter(emitted), end_offset)`` on the happy path;
            raises when rows were emitted but the offset did not advance;
            returns ``(iter([]), start_offset)`` when nothing was emitted on
            a no-progress batch (terminal/empty). ``start_offset is None``
            is the batch-reader signal (``LakeflowBatchReader`` passes
            ``None`` and discards the returned offset) — no-progress can't
            loop in that mode, so the guard is skipped and rows are emitted
            as-is. Streaming first batch passes ``{}`` (see
            ``LakeflowStreamReader.initialOffset``); the plain ``==`` then
            catches both ``{}`` and populated equal-offsets. See
            ``_no_progress_cursor_error`` for the two causes that land in
            the raise branch."""
            if start_offset is None:
                return iter(emitted), end_offset

            # Compare progress on the cursor/continuation state only. Strip the
            # ``lb_*`` auto-lookback bookkeeping (its measurement fluctuates batch
            # to batch without representing real cursor progress) and the persisted
            # ``cursor_probe_ok`` / ``batch_ok`` capability flags (one-time-set
            # markers, not progress) — otherwise a batch that merely bakes in a flag
            # would read as forward progress and bypass the no-progress guard.
            def _progress_view(off: dict | None) -> dict:
                return {
                    k: v
                    for k, v in (off or {}).items()
                    if not k.startswith("lb_") and k not in ("cursor_probe_ok", "batch_ok")
                }

            if _progress_view(start_offset) == _progress_view(end_offset):
                if emitted:
                    # With cursor_lookback the read floor lags the committed
                    # watermark by the overlap window, so a quiescent trigger
                    # re-reads the trailing overlap rows (cursor <= committed)
                    # without the watermark advancing. That is expected, not a
                    # stall: a row with cursor > committed (forward progress)
                    # would have advanced end_offset and skipped this branch. So
                    # idle — suppress the overlap re-reads (idempotent under
                    # apply_changes MERGE anyway) rather than raising. The
                    # late-arriver rows the overlap exists to catch are emitted on
                    # the next PROGRESSING batch, when end_offset advances past
                    # the prior watermark.
                    if getattr(self, "_active_lookback_seconds", 0) > 0:
                        return iter([]), start_offset
                    raise self._no_progress_cursor_error(table_name, cursor_field, len(emitted))
                return iter([]), start_offset
            return iter(emitted), end_offset

        def _read_contained_incremental(
            self,
            table_name: str,
            start_offset: dict | None,
            table_options: dict[str, str],
            cursor_field: str,
        ) -> tuple[Iterator[dict], dict]:
            """Walk every parent tuple with ``$filter=cursor gt since``; track
            global max cursor in the offset. Truncation parks ``parent_idx``
            for next-call resume. When the leaf entity doesn't declare
            ``cursor_field``, the closest ancestor that does owns the filter
            and its cursor value is propagated onto each leaf row."""
            segments = parse_contained_path(table_name) or [table_name]
            namespace = (table_options or {}).get("namespace")
            cursor_level = self._find_cursor_level(segments, namespace, cursor_field)
            if cursor_level == -1:
                raise ValueError(
                    f"cursor_field {cursor_field!r} is not a property on "
                    f"{table_name!r} or any of its ancestors. Pick a column "
                    f"declared on the leaf or one of the parent segments."
                )
            mode = self._cursor_probe_mode(table_options)  # auto | probe | batch | off
            explicit = "cursor_probe" in (table_options or {})
            is_leaf_cursor = cursor_level == len(segments) - 1
            probe_applicable = is_leaf_cursor and self._cursor_probe_applicable(
                segments, namespace, cursor_field, cursor_level
            )
            # Strict misconfig raises apply only to an EXPLICIT opt-in that names a
            # strategy this path structurally can't run. ``auto`` (the default) and
            # ``off`` never raise — they degrade to a correct fallback.
            if explicit and mode == "probe" and not probe_applicable:
                if not is_leaf_cursor:
                    raise ValueError(
                        "cursor_probe=nested-expand requires cursor_field on the leaf "
                        f"segment (it lives on ancestor segment {segments[cursor_level]!r} "
                        f"of {table_name!r}). cursor_probe only accelerates leaf-owned "
                        "cursor reads; an ancestor cursor already filters whole "
                        "subtrees, so drop cursor_probe for this table."
                    )
                raise ValueError(
                    f"cursor_probe=nested-expand won't help on {table_name!r}: its leaf-parent "
                    f"collection {segments[-2]!r} is a batch-snapshot level (it does "
                    f"not declare {cursor_field!r}), so the distance from the leaf to "
                    "the nearest snapshot ancestor is 1 — every leaf-parent is fetched "
                    "anyway and there are no clean ones to skip. cursor_probe pays off "
                    "only when the leaf's parent is itself an incremental, "
                    "high-cardinality collection. Drop cursor_probe here."
                )
            if explicit and mode == "batch" and not is_leaf_cursor:
                raise ValueError(
                    f"cursor_probe=batch only accelerates leaf-owned cursor reads, but "
                    f"{cursor_field!r} lives on ancestor segment {segments[cursor_level]!r} "
                    f"of {table_name!r} — an ancestor cursor already filters whole "
                    "subtrees. Drop cursor_probe for this table."
                )
            if start_offset is None:
                # Batch reader: offset discarded, ``since`` is None (no cursor
                # filter), no cap, no no-progress guard — so the ``emitted``
                # list, watermark and truncation checkpoint the streaming
                # walks build all serve nothing. Stream leaf rows one page at
                # a time so an uncapped batch doesn't materialise the whole
                # result set. See ``read_table`` for why the cap is disabled.
                return (
                    self._stream_contained_incremental(
                        table_name, segments, namespace, table_options, cursor_field, cursor_level
                    ),
                    {},
                )
            if cursor_level == len(segments) - 1:
                # Overlap re-read window for the (non-atomic) leaf-cursor walk: the
                # probe and the plain N+1 walk have the same mid-walk-arrival gap as
                # expand mode (a leaf inserted under an already-passed / probed-clean
                # parent lands below the committed max and is skipped forever by the
                # next ``cursor gt``). Floor the READ filter to ``committed - window``
                # while still committing the true max. Resolved here (the leaf
                # branch) so it never bleeds into the ancestor-cursor path. See
                # ``_read_contained_incremental_leaf_cursor`` for the read-side use.
                self._active_lookback_seconds = self._resolve_active_lookback(start_offset)
                read_since = self._apply_cursor_lookback((start_offset or {}).get("cursor"))
                # Engage the probe only where it pays off (``probe_applicable``):
                # the leaf-parent must itself be a cursor-bearing collection, so
                # there are clean leaf-parents to skip. A snapshot leaf-parent
                # (e.g. .../Projects/WorkPackageDetails) is enumerated in full
                # either way, so default-on cursor_probe stays inert there.
                chains_iter = None
                persist_probe_ok = False
                use_batch = False
                persist_batch_ok = False
                used_probe = False
                if mode in ("probe", "auto") and probe_applicable:
                    # Capability-verify the nested-$expand probe. ``probe`` (explicit
                    # ``true``) is STRICT — ``_verify_cursor_probe_support`` raises if
                    # the server mis-orders inner $expand. ``auto`` is non-strict — a
                    # mis-ordering verdict returns ``supported=False`` so we cascade
                    # to $batch below instead of failing the read. A conclusive pass
                    # (or a flag a prior batch persisted) lets a per-batch-recreated
                    # reader skip the preflight next time.
                    supported, conclusive = self._verify_cursor_probe_support(
                        segments,
                        namespace,
                        table_options,
                        cursor_field,
                        start_offset,
                        strict=(mode == "probe"),
                    )
                    if supported:
                        used_probe = True
                        persist_probe_ok = conclusive or bool(
                            (start_offset or {}).get("cursor_probe_ok")
                        )
                        # The probe prunes nothing until a watermark exists: with
                        # ``read_since`` None (first batch) every leaf-parent reads as
                        # dirty, so the per-grandparent probe round-trips would only
                        # add overhead with nothing to skip. Fall back to the plain
                        # enumerator then — identical rows, fewer requests — and
                        # engage the probe once a watermark is established.
                        if read_since is not None:
                            chains_iter = self._iter_dirty_leaf_parent_chains(
                                segments,
                                namespace,
                                table_options,
                                cursor_field,
                                read_since,
                            )
                # Cascade: ``auto`` (probe didn't apply / server mis-orders) and
                # ``batch`` hydrate via $batch when the server supports it; otherwise
                # both fall through to the plain N+1 walk. ``probe`` never reaches
                # here without having engaged (it raised on an unsupported server).
                if not used_probe and mode in ("auto", "batch"):
                    if self._verify_batch_support(segments, table_options, start_offset):
                        use_batch = True
                        persist_batch_ok = True
                return self._read_contained_incremental_leaf_cursor(
                    table_name,
                    segments,
                    start_offset,
                    table_options,
                    cursor_field,
                    chains_iter=chains_iter,
                    persist_probe_ok=persist_probe_ok,
                    use_batch=use_batch,
                    persist_batch_ok=persist_batch_ok,
                )
            return self._read_contained_incremental_ancestor_cursor(
                table_name, segments, start_offset, table_options, cursor_field, cursor_level
            )

        def _stream_contained_incremental(
            self,
            table_name: str,
            segments: list[str],
            namespace: str | None,
            table_options: dict[str, str],
            cursor_field: str,
            cursor_level: int,
        ) -> Iterator[dict]:
            """Lazy batch-mode contained cursor read (leaf- or ancestor-cursor).

            Mirrors the per-row work of ``_read_contained_incremental_*``
            minus everything the batch reader makes moot (``since`` is None,
            offset discarded, cap disabled, guard skipped): no cursor
            ``$filter``, no ``emitted`` buffer, no watermark, no truncation
            checkpoint. Leaf rows stream one page at a time. The cursor lives
            on the leaf (``leaf`` branch — apply ``cursor_nulls=ignore``
            null-skip; ``coalesce`` keeps the real null since nothing consumes
            the synthetic value) or on a non-leaf ancestor (``ancestor``
            branch — stamp the ancestor's cursor value onto each leaf row,
            exactly as ``_walk_ancestor_chains`` does)."""
            fk_columns = self._resolve_fk_columns(segments, namespace)
            segment_filters = resolve_segment_filters(table_options, segments)
            leaf_filter = segment_filters.get(len(segments) - 1)
            if cursor_level == len(segments) - 1:
                order_by = self._leaf_cursor_order_by(table_name, namespace, cursor_field)
                skip_null, _effective = self._make_cursor_resolver(
                    table_name, namespace, cursor_field, table_options
                )
                for chain in self._iter_parent_key_chains(segments, namespace, table_options):
                    url = self._build_contained_url(
                        segments, chain, table_options, extra_filter=leaf_filter, order_by=order_by
                    )
                    for row in self._fetch_pages(url):
                        if skip_null and row.get(cursor_field) is None:
                            continue
                        self._tag_with_ancestor_fks(row, segments, chain, fk_columns)
                        yield row
                return
            leaf_order_by = self._leaf_pk_order_by(segments, namespace)
            chains_iter = self._iter_parent_chains_with_cursor(
                segments, namespace, table_options, cursor_level, cursor_field, None
            )
            for chain, ancestor_cursor in chains_iter:
                url = self._build_contained_url(
                    segments, chain, table_options, extra_filter=leaf_filter, order_by=leaf_order_by
                )
                for row in self._fetch_pages(url):
                    self._tag_with_ancestor_fks(row, segments, chain, fk_columns)
                    row[cursor_field] = ancestor_cursor
                    yield row

        def _read_contained_incremental_leaf_cursor(
            self,
            table_name: str,
            segments: list[str],
            start_offset: dict | None,
            table_options: dict[str, str],
            cursor_field: str,
            chains_iter: Iterator[list[dict[str, Any]]] | None = None,
            persist_probe_ok: bool = False,
            use_batch: bool = False,
            persist_batch_ok: bool = False,
        ) -> tuple[Iterator[dict], dict]:
            """Cursor lives on the leaf entity — filter at the leaf fetch.

            ``use_batch`` hydrates via :meth:`_batch_walk_contained_with_cursor`
            (OData ``$batch``, chunk-aligned resume) instead of the per-parent
            :meth:`_walk_contained_with_cursor`; ``persist_batch_ok`` stamps the
            ``batch_ok`` capability flag into the resume offset (mirrors
            ``persist_probe_ok`` / ``cursor_probe_ok``).

            ``chains_iter`` lets a caller substitute the parent-key source
            (default: every chain via :meth:`_iter_parent_key_chains`). The
            ``cursor_probe`` path passes :meth:`_iter_dirty_leaf_parent_chains`
            — the same chains pruned to parents with changed leaves — so the
            flat ``parent_idx`` resume, watermark and no-progress guard below
            all work unchanged over the reduced set.

            ``_walk_contained_with_cursor`` chooses the truncation
            checkpoint (and trims ``emitted`` to match); this method only
            serialises it into the resume offset. The checkpoint is scoped
            to the truncated chain — subsequent chains keep the original
            ``since`` since per-chain cursor distributions are independent:

            * **NextLink (preferred)**: truncation on a page boundary parks
              the server's @odata.nextLink as ``chain_next_link``; the
              resumed call hands it straight back to the server.
            * **Trim boundary**: a *complete* parent (no nextLink) with a
              distinct-cursor boundary drops its trailing same-cursor cohort
              and parks ``truncated_chain_cursor``; the resumed call rebuilds
              ``cursor gt truncated_chain_cursor`` for that chain only.

            A complete parent whose entire leaf collection shares one cursor
            value has no splittable boundary; the walk emits it in full and
            continues to the next parent (the cap is overshot for that one
            parent), so there is no failure case here.
            """
            namespace = (table_options or {}).get("namespace")
            since = (start_offset or {}).get("cursor")
            # Overlap re-read floor (see ``_read_contained_incremental`` dispatch):
            # the per-chain ``cursor gt`` filters and the in-walk client trim use
            # ``read_since`` (= committed − window) so a non-atomic walk re-scans
            # the overlap; the committed offset below stays the TRUE ``since``/max.
            # ``_active_lookback_seconds`` was resolved on ``self`` by the dispatch
            # (0 for a non-lookback read → ``read_since`` is ``since`` unchanged).
            read_since = self._apply_cursor_lookback(since)
            truncated_chain_cursor_in = (start_offset or {}).get("truncated_chain_cursor")
            chain_next_link_in = (start_offset or {}).get("chain_next_link")
            max_records = int((table_options or {}).get("max_records_per_batch", "10000"))
            order_by = self._leaf_cursor_order_by(table_name, namespace, cursor_field)
            if chains_iter is None:
                chains_iter = self._iter_parent_key_chains(segments, namespace, table_options)
            segment_filters = resolve_segment_filters(table_options, segments)
            # ``cursor_nulls`` resolver (synthetic floor for nulls under
            # coalesce; skip nulls under ignore). The cursor lives on the leaf
            # entity, so PKs/floor come from the full contained path's leaf.
            skip_null, effective = self._make_cursor_resolver(
                table_name, namespace, cursor_field, table_options
            )
            # Wall-clock around the walk feeds the ``auto`` lookback window
            # (see ``_attach_lookback_state``), exactly as the expand path does.
            walk_start = time.monotonic()
            if use_batch:
                (
                    emitted,
                    truncated,
                    parent_idx,
                    chain_next_link_out,
                    truncated_chain_cursor_out,
                ) = self._batch_walk_contained_with_cursor(
                    segments,
                    chains_iter,
                    int((start_offset or {}).get("parent_idx", 0)),
                    table_options,
                    order_by,
                    cursor_field,
                    read_since,
                    max_records,
                    self._resolve_fk_columns(segments, namespace),
                    leaf_segment_filter=segment_filters.get(len(segments) - 1),
                    effective=effective,
                    skip_null=skip_null,
                )
            else:
                (
                    emitted,
                    truncated,
                    parent_idx,
                    chain_next_link_out,
                    truncated_chain_cursor_out,
                ) = self._walk_contained_with_cursor(
                    segments,
                    chains_iter,
                    int((start_offset or {}).get("parent_idx", 0)),
                    table_options,
                    order_by,
                    cursor_field,
                    read_since,
                    truncated_chain_cursor_in,
                    chain_next_link_in,
                    max_records,
                    self._resolve_fk_columns(segments, namespace),
                    leaf_segment_filter=segment_filters.get(len(segments) - 1),
                    effective=effective,
                    skip_null=skip_null,
                )
            walk_elapsed = time.monotonic() - walk_start
            if truncated:
                # The walk has already chosen the checkpoint and trimmed
                # ``emitted`` accordingly: ``chain_next_link_out`` for a page
                # boundary, else ``truncated_chain_cursor_out`` for a complete
                # parent with a distinct-cursor boundary. (A complete parent
                # with a single cursor value never truncates — the walk emits
                # it in full and continues — so there's no failure case here.)
                end_offset: dict = {"parent_idx": parent_idx}
                # The ``$batch`` walk resumes purely on ``parent_idx`` (chunk-aligned)
                # — it never parks a mid-collection checkpoint — so its truncation
                # offset carries neither continuation key.
                if not use_batch:
                    if chain_next_link_out is not None:
                        end_offset["chain_next_link"] = chain_next_link_out
                    else:
                        end_offset["truncated_chain_cursor"] = truncated_chain_cursor_out
                if since is not None:
                    end_offset["cursor"] = since
            else:
                if not emitted:
                    empty = start_offset or {}
                    if persist_probe_ok:
                        empty = self._with_probe_ok(empty)
                    if persist_batch_ok:
                        empty = self._with_batch_ok(empty)
                    return iter([]), empty
                cursors = [effective(r) for r in emitted if effective(r) is not None]
                # Mirror ``_build_expand_end_offset`` /
                # ``_ancestor_cursor_offset``: when there's no cursor data this
                # batch and no prior ``since`` to carry, the offset is ``{}`` —
                # not ``{"cursor": None}`` (see ``_cursor_max_end_offset``).
                end_offset = self._cursor_max_end_offset(cursors, since)
            records, out_offset = self._finalize_cursor_read(
                start_offset, end_offset, emitted, table_name, cursor_field
            )
            # Carry the ``auto`` walk-duration history (no-op for static/off and
            # for the idled overlap re-read). ``truncated`` ⇒ walk in flight, so
            # its partial duration isn't recorded as a completed walk.
            out_offset = self._attach_lookback_state(out_offset, start_offset, truncated, walk_elapsed)
            # Persist the verified cursor_probe capability so a freshly-constructed
            # reader on the next batch can skip the preflight requests. Applied
            # AFTER the no-progress finalize (whose comparison ignores
            # ``cursor_probe_ok`` — see ``_finalize_cursor_read``) so it never reads
            # as false forward progress, and an idled overlap re-read that already
            # carries the flag returns ``start_offset`` unchanged.
            if persist_probe_ok:
                out_offset = self._with_probe_ok(out_offset)
            # Same treatment for the ``$batch`` capability flag (excluded from the
            # no-progress comparison alongside ``cursor_probe_ok``).
            if persist_batch_ok:
                out_offset = self._with_batch_ok(out_offset)
            return records, out_offset

        def _read_contained_incremental_ancestor_cursor(
            self,
            table_name: str,
            segments: list[str],
            start_offset: dict | None,
            table_options: dict[str, str],
            cursor_field: str,
            cursor_level: int,
        ) -> tuple[Iterator[dict], dict]:
            """Cursor lives on a non-leaf ancestor. Filter at that ancestor
            level (changed subtrees only), fetch full leaf collections under
            each filtered ancestor, and stamp the ancestor's cursor value
            onto every emitted leaf row.

            Truncation uses **nextLink-based mid-chain resume** exclusively.
            Every leaf under a chain shares that chain's stamped cursor by
            construction, so a within-chain ``cursor gt`` rebuild would
            either re-fetch the whole chain or skip the whole chain — there
            is no meaningful split.
            """
            namespace = (table_options or {}).get("namespace")
            since = (start_offset or {}).get("cursor")
            chains_iter = self._iter_parent_chains_with_cursor(
                segments, namespace, table_options, cursor_level, cursor_field, since
            )
            segment_filters = resolve_segment_filters(table_options, segments)
            walk_state = self._walk_ancestor_chains(
                segments,
                chains_iter,
                table_options,
                cursor_field,
                int((start_offset or {}).get("parent_idx", 0)),
                (start_offset or {}).get("chain_next_link"),
                int((table_options or {}).get("max_records_per_batch", "10000")),
                self._resolve_fk_columns(segments, namespace),
                leaf_segment_filter=segment_filters.get(len(segments) - 1),
            )
            end_offset = self._ancestor_cursor_offset(walk_state, start_offset, since, cursor_field)
            return self._finalize_cursor_read(
                start_offset, end_offset, walk_state["emitted"], table_name, cursor_field
            )

        def _walk_ancestor_chains(
            self,
            segments: list[str],
            chains_iter: Iterator[tuple[list[dict[str, Any]], Any]],
            table_options: dict[str, str],
            cursor_field: str,
            parent_idx_start: int,
            chain_next_link_in: str | None,
            max_records: int,
            fk_columns: dict[tuple[str, str], str],
            leaf_segment_filter: str | None = None,
        ) -> dict[str, Any]:
            """Walk ancestor chains, fetching each chain's leaf collection
            and stamping rows with the chain's cursor.

            ``chains_iter`` is consumed lazily: the per-ancestor enumeration
            stops as soon as the loop breaks on a ``max_records`` hit, so
            we never fetch ancestor pages beyond the chain we actually
            emit from. Peak memory is bounded to one chain.

            Page-aware: a truncation at a page boundary parks the chain's
            ``@odata.nextLink``; when the chain happens to end on the
            truncating page, ``parent_idx`` simply advances past it."""
            namespace = (table_options or {}).get("namespace")
            leaf_order_by = self._leaf_pk_order_by(segments, namespace)
            parent_idx = 0
            emitted: list[dict] = []
            truncated = False
            chain_next_link_out: str | None = None
            for chain, ancestor_cursor in chains_iter:
                # Skip already-emitted chains. Ancestor-page HTTP cost is
                # unavoidable (we need the keys to identify the chain), but
                # no leaf fetches happen during the skip.
                if parent_idx < parent_idx_start:
                    parent_idx += 1
                    continue
                if parent_idx == parent_idx_start and chain_next_link_in is not None:
                    initial_url = chain_next_link_in
                else:
                    initial_url = self._build_contained_url(
                        segments,
                        chain,
                        table_options,
                        extra_filter=leaf_segment_filter,
                        order_by=leaf_order_by,
                    )
                page_next_url: str | None = None
                # See the leaf-cursor walk: the
                # default auto drains a link-omitting, sub-$top-capped leaf via the
                # keyset seek, and the synthesized seek doubles as the cap-hit resume
                # checkpoint.
                for page_rows, page_next_url in self._fetch_pages_with_links(initial_url):
                    for row in page_rows:
                        self._tag_with_ancestor_fks(row, segments, chain, fk_columns)
                        row[cursor_field] = ancestor_cursor
                        emitted.append(row)
                    if len(emitted) >= max_records:
                        truncated = True
                        break
                if truncated:
                    if page_next_url is not None:
                        chain_next_link_out = page_next_url
                    else:
                        parent_idx += 1
                    break
                parent_idx += 1
            return {
                "emitted": emitted,
                "truncated": truncated,
                "parent_idx": parent_idx,
                "chain_next_link": chain_next_link_out,
            }

        def _ancestor_cursor_offset(
            self,
            walk_state: dict[str, Any],
            start_offset: dict | None,
            since: Any,
            cursor_field: str,
        ) -> dict:
            """Build the offset for the ancestor-cursor read path.

            On truncation: preserve original ``since`` (the chain enumeration
            interleaves cursors across top-level parents, so advancing
            ``since`` to the global max would silently skip lower-cursor
            chains under not-yet-walked parents). Accumulate ``running_max``
            across resume batches so natural completion records the actual
            highest cursor seen — without it, a resume that started from
            ``since=None`` would lose the cursor on completion and re-walk
            the whole table on the next trigger.
            """
            emitted = walk_state["emitted"]
            cursors = [r.get(cursor_field) for r in emitted if r.get(cursor_field) is not None]
            this_batch_max = max(cursors) if cursors else None
            prev_running_max = (start_offset or {}).get("running_max")
            new_running_max = _max_or(this_batch_max, prev_running_max)
            if walk_state["truncated"]:
                offset: dict = {"parent_idx": walk_state["parent_idx"]}
                if since is not None:
                    offset["cursor"] = since
                if walk_state["chain_next_link"] is not None:
                    offset["chain_next_link"] = walk_state["chain_next_link"]
                if new_running_max is not None:
                    offset["running_max"] = new_running_max
                return offset
            if new_running_max is not None:
                return {"cursor": new_running_max}
            if since is not None:
                return {"cursor": since}
            return {}


    ########################################################
    # src/databricks/labs/community_connector/sources/odata/_partition.py
    ########################################################

    _DEFAULT_NUM_PARTITIONS = 4
    _OPT_NUM_PARTITIONS = "num_partitions"


    class PartitionMixin(SupportsPartitionedStream):
        """Mixes ``SupportsPartitionedStream`` into ``ODataLakeflowConnect``.

        Only methods specific to partitioning live here. Discovery of
        top-level parent keys, leaf walking, and FK tagging are delegated
        back into the rest of the connector via duck-typed ``self.*``
        calls (same pattern as ``ContainedNavMixin``).
        """

        # ------------------------------------------------------------------
        # SupportsPartitionedStream interface
        # ------------------------------------------------------------------

        def is_partitioned(self, table_name: str) -> bool:
            """Opt this table into the partitioned read path.

            Streaming + partitioning has a stricter precondition than batch
            + partitioning because the connector has to fence each micro-
            batch's cursor window upfront in ``latest_offset`` — there's no
            way to communicate "max cursor observed" back from executors.
            For batch reads any contained N+1 path is partitionable; for
            streaming reads we additionally require the cursor to live on
            the top-level entity so a single probe can compute the fence.

            The framework calls this without table_options, so we read
            them from ``self.options`` — safe because each
            ``LakeflowSource`` instance carries one table's options.
            """
            if parse_contained_path(table_name) is None:
                return False
            opts = getattr(self, "options", {}) or {}
            if opts.get("expand_contained", "false").strip().lower() == "true":
                return False
            if self._delta_setting(opts) != "disabled":
                return False
            # If a cursor is set, it must live at the top level for the
            # streaming fence probe to make sense. Snapshot reads (no
            # cursor_field) clear this trivially.
            cursor_field = opts.get("cursor_field")
            if cursor_field:
                segments = parse_contained_path(table_name) or [table_name]
                namespace = opts.get("namespace")
                if self._find_cursor_level(segments, namespace, cursor_field) != 0:
                    return False
            return True

        def latest_offset(
            self,
            table_name: str,
            table_options: dict[str, str],
            start_offset: dict | None = None,
        ) -> dict:
            """Probe the top-level entity for the current max cursor value.

            Each micro-batch reads ``(start_cursor, end_cursor]`` — the
            ``end`` returned here becomes ``start`` of the next batch when
            Spark commits, so cursor progression is monotonic.

            For snapshot streams (no ``cursor_field``) the offset is a
            wall-clock epoch — there's no source-side notion of "what's
            new" without a cursor, so each trigger reads a full snapshot
            and Spark commits the new epoch.
            """
            opts = table_options or {}
            cursor_field = opts.get("cursor_field")
            if not cursor_field:
                return {"snapshot_id": _wall_clock_ns()}
            segments = parse_contained_path(table_name) or [table_name]
            namespace = opts.get("namespace")
            max_cursor = self._probe_top_level_max_cursor(segments[0], namespace, cursor_field)
            prior = (start_offset or {}).get("cursor")
            if max_cursor is None:
                # Empty top set or all-null cursor column. Keep the prior
                # value so Spark sees no progress and skips the batch.
                return {"cursor": prior} if prior is not None else {}
            return {"cursor": max_cursor}

        def get_partitions(
            self,
            table_name: str,
            table_options: dict[str, str],
            start_offset: dict | None = None,
            end_offset: dict | None = None,
        ) -> Sequence[dict]:
            """Return partition descriptors covering this read.

            Two invocation shapes (PySpark dispatches both into the same
            method):

            * ``get_partitions(table, options)`` — batch path. Returns
              partitions over the full top-level set.
            * ``get_partitions(table, options, start, end)`` — streaming
              path. Returns partitions filtered to the cursor window
              ``(start.cursor, end.cursor]``.

            For tables ``is_partitioned`` rejects, the framework still
            invokes this on the batch path; in that case we hand back a
            single empty descriptor so ``read_partition`` falls through
            to the existing serial ``read_table`` semantics.
            """
            if parse_contained_path(table_name) is None:
                # Flat table — let the existing serial path handle it.
                return [{}]
            opts = table_options or {}
            if opts.get("expand_contained", "false").strip().lower() == "true":
                return [{}]
            if self._delta_setting(opts) != "disabled":
                return [{}]
            if start_offset == end_offset and start_offset is not None:
                # Streaming: no new data — no work to partition.
                return []
            segments = parse_contained_path(table_name) or [table_name]
            namespace = opts.get("namespace")
            cursor_field = opts.get("cursor_field")
            self._pagination = self._parse_pagination(opts)
            if cursor_field or self._pagination != "nextlink":
                # Cursor-based read, or client-driven pagination (which needs a
                # $top to size pages): default page_size so a $top is sent.
                # Snapshot + nextlink leaves it unset → no $top.
                opts = {**opts, "page_size": opts.get("page_size", DEFAULT_PAGE_SIZE)}
            # ``cursor_lower`` is "what we've already read up to" — used
            # by read_partition as ``cursor gt cursor_lower``. ``end`` is
            # the previously-probed fence; we stamp it onto each row's
            # cursor column so the next batch's ``cursor_lower`` matches.
            cursor_lower = (start_offset or {}).get("cursor")
            top_rows = self._discover_top_parent_rows(
                segments, namespace, opts, cursor_field, cursor_lower
            )
            if not top_rows:
                return []
            num_partitions = max(1, int(opts.get(_OPT_NUM_PARTITIONS, _DEFAULT_NUM_PARTITIONS)))
            return _bin_pack(top_rows, num_partitions, cursor_lower)

        def read_partition(
            self,
            table_name: str,
            partition: dict,
            table_options: dict[str, str],
        ) -> Iterator[dict]:
            """Walk one partition's slice of top-level parents.

            An empty descriptor ``{}`` (returned by ``get_partitions`` for
            unsupported configurations) falls back to the existing serial
            ``read_table`` — same shape as the simple-reader path. With a
            ``top_parent_rows`` key, the chain enumeration starts from
            that subset instead of fetching the whole level-0 set.
            """
            opts = table_options or {}
            if not partition or "top_parent_rows" not in partition:
                # Single-partition fallback: defer to read_table which
                # returns (iter, offset). Drop the offset; partitioned
                # mode commits offsets via latest_offset, not per-read.
                records, _ = self.read_table(table_name, None, opts)
                return records
            segments = parse_contained_path(table_name) or [table_name]
            cursor_field = opts.get("cursor_field")
            self._pagination = self._parse_pagination(opts)
            if cursor_field or self._pagination != "nextlink":
                # Cursor-based read, or client-driven pagination (needs a $top
                # to size pages): default page_size so a $top is sent.
                # Snapshot + nextlink leaves it unset → no $top.
                opts = {**opts, "page_size": opts.get("page_size", DEFAULT_PAGE_SIZE)}
            top_parent_rows = partition["top_parent_rows"]
            cursor_lower = partition.get("cursor_lower")
            return self._iter_partition_rows(
                segments, opts, top_parent_rows, cursor_field, cursor_lower
            )

        # ------------------------------------------------------------------
        # Per-table helpers (called by the methods above)
        # ------------------------------------------------------------------

        def _probe_top_level_max_cursor(
            self,
            top_set: str,
            namespace: str | None,
            cursor_field: str,
        ):
            """One HTTP probe: ``$top=1&$orderby=<cursor> desc`` → max value.

            Returns ``None`` when the top set is empty or every row has a
            null cursor. The caller decides whether that means "no new
            data" or "first call against an empty source."
            """
            # Use the existing URL builder + page-fetch plumbing so OAuth,
            # extra_headers, retries, etc. all carry through unchanged.
            et = self._entity_type_for(top_set, namespace)
            own_fields = self._own_fields_for_et(et)
            if not any(f.name == cursor_field for f in own_fields):
                return None
            opts = {
                "page_size": "1",
                "select": cursor_field,
            }
            url = self._build_url(top_set, opts, order_by=f"{cursor_field} desc")
            for row in self._fetch_pages(url):
                value = row.get(cursor_field)
                if value is not None:
                    return value
            return None

        def _discover_top_parent_rows(
            self,
            segments: list[str],
            namespace: str | None,
            table_options: dict[str, str],
            cursor_field: str | None,
            cursor_lower,
        ) -> list[dict]:
            """Fetch the rows of the top-level entity set that bound this
            read. Returns level-0 PK dicts (plus the cursor column when a
            cursor is present, so executors can stamp rows without re-
            fetching). Apply the cursor filter at the top set when the
            cursor lives at level 0; otherwise no filter is applied here
            and per-leaf filtering picks up the slack in the executor."""
            top_set = segments[0]
            ancestor_et = self._entity_type_for(top_set, namespace)
            ancestor_pks = self._own_primary_keys_for_et(ancestor_et)
            select_cols = list(ancestor_pks)
            cursor_extra: str | None = None
            # Default to PK-only ordering so server skiptoken pagination
            # is stable when there's no cursor at the top set (or the
            # cursor lives deeper). See ``_ancestor_pk_order_by`` for the
            # skiptoken-safety argument.
            order_by: str | None = _ancestor_pk_order_by(ancestor_pks)
            if cursor_field:
                own_fields = self._own_fields_for_et(ancestor_et)
                if any(f.name == cursor_field for f in own_fields):
                    if cursor_field not in select_cols:
                        select_cols.append(cursor_field)
                    if cursor_lower is not None:
                        cursor_extra = self._cursor_filter(cursor_field, cursor_lower)
                    terms = [f"{cursor_field} asc"]
                    terms.extend(f"{pk} asc" for pk in ancestor_pks if pk != cursor_field)
                    order_by = ",".join(terms)
            # AND the level-0 segment filter (``filter_at_<top>``) with any
            # cursor filter. Without this the partition pre-fetch returns
            # every parent, then per-partition leaf fetches issue one
            # request per parent — even though the user explicitly told us
            # which parents to walk. The leaf filter then matches inside
            # every unfiltered parent, surfacing rows that should have been
            # excluded by the top filter.
            segment_filters = resolve_segment_filters(table_options, segments)
            extra_filter = combine_filters(cursor_extra, segment_filters.get(0))
            opts = {"select": ",".join(select_cols)}
            # Propagate the user's ``page_size`` only when set; with no
            # ``page_size`` no ``$top`` is sent (see ``_format_query_params``).
            if table_options.get("page_size"):
                opts["page_size"] = table_options["page_size"]
            url = self._build_url(top_set, opts, extra_filter=extra_filter, order_by=order_by)
            return list(self._fetch_pages(url))

        def _iter_partition_rows(
            self,
            segments: list[str],
            table_options: dict[str, str],
            top_parent_rows: list[dict],
            cursor_field: str | None,
            cursor_lower,
        ) -> Iterator[dict]:
            """Stream leaf rows for one partition's slice of parents.

            Dispatch mirrors ``read_table``'s contained branches: cursor on
            a non-leaf ancestor → ancestor-cursor walk with stamped cursor
            values; cursor on the leaf → per-leaf cursor filter; no
            cursor → full snapshot per chain.
            """
            namespace = (table_options or {}).get("namespace")
            fk_columns = self._resolve_fk_columns(segments, namespace)
            segment_filters = resolve_segment_filters(table_options, segments)
            leaf_seg_filter = segment_filters.get(len(segments) - 1)
            leaf_order_by = self._leaf_pk_order_by(segments, namespace)
            if not cursor_field:
                for chain in self._iter_parent_key_chains(
                    segments, namespace, table_options, top_parent_rows=top_parent_rows
                ):
                    url = self._build_contained_url(
                        segments,
                        chain,
                        table_options,
                        extra_filter=leaf_seg_filter,
                        order_by=leaf_order_by,
                    )
                    for row in self._fetch_pages(url):
                        self._tag_with_ancestor_fks(row, segments, chain, fk_columns)
                        yield row
                return
            cursor_level = self._find_cursor_level(segments, namespace, cursor_field)
            if cursor_level == -1:
                raise ValueError(
                    f"cursor_field {cursor_field!r} is not a property on "
                    f"the contained path or any of its ancestors."
                )
            # Partition activation requires cursor at level 0 for the
            # streaming probe to make sense; this branch is the only one
            # reached in practice. We still go through the with-cursor
            # iterator so the cursor column is stamped onto leaf rows.
            chains_iter = self._iter_parent_chains_with_cursor(
                segments,
                namespace,
                table_options,
                cursor_level,
                cursor_field,
                cursor_lower,
                top_parent_rows=top_parent_rows,
            )
            for chain, ancestor_cursor in chains_iter:
                url = self._build_contained_url(
                    segments, chain, table_options, extra_filter=leaf_seg_filter, order_by=leaf_order_by
                )
                for row in self._fetch_pages(url):
                    self._tag_with_ancestor_fks(row, segments, chain, fk_columns)
                    if cursor_level == len(segments) - 1:
                        # Leaf-cursor mode: filter per row by ``cursor gt
                        # cursor_lower``. (Server-side filter would be
                        # cheaper, but partition activation gates this to
                        # cursor_level==0; this branch exists for
                        # completeness only.)
                        rec = row.get(cursor_field)
                        if cursor_lower is not None and rec is not None and rec <= cursor_lower:
                            continue
                    else:
                        row[cursor_field] = ancestor_cursor
                    yield row


    def _bin_pack(rows: list[dict], num_partitions: int, cursor_lower) -> list[dict]:
        """Split ``rows`` into ``num_partitions`` partition descriptors.

        Round-robin assignment with each partition carrying a contiguous
        slice — keeps cursor ordering stable within a partition (the
        ``_discover_top_parent_rows`` caller sorts by cursor when one is
        set). Empty bins are dropped so the framework doesn't spawn
        no-op executors.
        """
        if not rows:
            return []
        bin_size = max(1, (len(rows) + num_partitions - 1) // num_partitions)
        partitions: list[dict] = []
        for i in range(0, len(rows), bin_size):
            partitions.append(
                {
                    "top_parent_rows": rows[i : i + bin_size],
                    "cursor_lower": cursor_lower,
                }
            )
        return partitions


    def _wall_clock_ns() -> int:
        """Wall-clock nanoseconds for snapshot-stream offset progression.

        Imported lazily here so ``_partition.py`` has no module-level
        import-time work — the connector is forked + re-imported per
        PySpark Python Data Source ``.load()`` call, and import cost is
        on the hot path.
        """
        import time  # pylint: disable=import-outside-toplevel

        return time.time_ns()


    ########################################################
    # src/databricks/labs/community_connector/sources/odata/odata.py
    ########################################################

    _EDM_TO_SPARK = {
        "Edm.String": StringType(),
        "Edm.Boolean": BooleanType(),
        # Widen integers up to Int32 to IntegerType (the framework's
        # parse_value doesn't support ShortType or ByteType, so the narrow
        # EDM widths can't map to their natural Spark types). Int64 needs
        # the full 64-bit range, so it stays as LongType.
        "Edm.Byte": IntegerType(),
        "Edm.SByte": IntegerType(),
        "Edm.Int16": IntegerType(),
        "Edm.Int32": IntegerType(),
        "Edm.Int64": LongType(),
        "Edm.Single": FloatType(),
        "Edm.Double": DoubleType(),
        "Edm.Decimal": DecimalType(38, 18),
        "Edm.Date": DateType(),
        "Edm.DateTime": TimestampType(),
        "Edm.DateTimeOffset": TimestampType(),
        "Edm.TimeOfDay": StringType(),
        "Edm.Duration": StringType(),
        "Edm.Guid": StringType(),
        "Edm.Binary": BinaryType(),
    }

    _NS_EDMX = "{http://docs.oasis-open.org/odata/ns/edmx}"
    _NS_EDM = "{http://docs.oasis-open.org/odata/ns/edm}"

    # Delta tracking constants.
    #
    # Synthetic columns appended to the schema when delta is active so the
    # destination MERGE (apply_changes) has a sequence column and a tombstone
    # flag. Their names are namespaced so they can't collide with any real
    # OData property — OData property names start with a letter, never an
    # underscore.
    _DELTA_PREFER = "odata.track-changes"
    _DELETED_COL = "_deleted"
    _SEQUENCE_COL = "_lc_sequence"
    # Effectively-unlimited value for ``max_records_per_batch`` when the
    # framework's batch reader is detected (``start_offset is None``).
    # A bare ``sys.maxsize`` is unnecessary — the per-fetch cap arithmetic
    # only ever compares ``<= len(emitted)``; any value larger than what a
    # single ingestion could plausibly buffer works.
    _BATCH_UNCAPPED = 10**12

    # Pagination strategy for walking a collection's pages:
    #   * nextlink — follow the server's ``@odata.nextLink`` only; strictly
    #     spec-compliant, and the choice for a ``$top``-free snapshot scan.
    #   * keyset — ignore ``@odata.nextLink``; seek the next page via a
    #     ``(k gt last)`` predicate on the ``$orderby`` key set. For servers
    #     that page-limit a response but omit the continuation link.
    #   * skip — ignore ``@odata.nextLink``; page via ``$top`` + ``$skip``.
    #     The keyless fallback (entities with no unique sort key); O(n)
    #     offsets and fragile under concurrent writes.
    #   * auto (default) — follow ``@odata.nextLink`` while emitted; when the
    #     server stops linking, drain via a keyset (when the ``$orderby`` has
    #     keys) or skip seek until an *empty* page. This covers a server that
    #     page-limits below ``$top`` while omitting the link, and one that
    #     treats ``$top`` as a total-result limit and propagates the budget
    #     through its skiptoken links (the chain self-terminates at ``$top``;
    #     auto seeks past it when ``fetched >= top``).
    # keyset/skip/auto require a ``$top`` to size pages and detect
    # truncation, so they force a default ``page_size`` when none is set.
    _PAGINATION_MODES = frozenset({"nextlink", "keyset", "skip", "auto"})

    # ``cursor_lookback_seconds=auto`` self-sizes the overlap window from the
    # **max** measured walk duration over the last ``_LOOKBACK_AUTO_WINDOW``
    # completed walks (the worst recent walk is the robust ceiling on how long a
    # walk runs — far less hand-wavy than last-value × a big fudge factor, and
    # resistant to a single slow spike skewing the estimate). That max is then
    # multiplied by ``cursor_lookback_factor`` (small margin for a walk worse
    # than any seen recently) and clamped to ``cursor_lookback_max_seconds`` — a
    # runaway backstop. Both the factor and ceiling are per-table options; these
    # are their defaults.
    _LOOKBACK_AUTO_WINDOW = 5
    _LOOKBACK_AUTO_DEFAULT_FACTOR = 1.5
    _LOOKBACK_AUTO_DEFAULT_CEILING_SECONDS = 3600
    # Monotonic across the whole process — guarantees each emitted record
    # has a strictly increasing sequence value, so apply_changes can pick a
    # deterministic winner when the same primary key appears multiple times
    # in one batch (e.g. update then delete arriving back-to-back).
    _SEQUENCE_COUNTER = itertools.count()

    # Process-wide CSDL cache, keyed by service_url. SDP creates a fresh
    # ``LakeflowSource`` (and ``ODataLakeflowConnect``) for every
    # ``spark.readStream.format("lakeflow_connect").load()`` call; within
    # a single Python process this cache makes all instances share one
    # parse.
    _METADATA_CACHE: dict[str, tuple[str, ET.Element, "_CsdlIndex"]] = {}

    # On-disk CSDL cache. PySpark's Python Data Source forks a fresh
    # ``pyspark.daemon`` worker for schema inference on every ``.load()``
    # call, so the process-wide cache above doesn't survive — each fork
    # starts with an empty dict. On a pipeline with N tables that means
    # N HTTP fetches and N multi-MB XML parses during INITIALIZING. The
    # file cache lets each forked worker read a pickled parsed tree from
    # tempdir instead, saving the HTTP RT + parse on every fork after the
    # first. The TTL is short so subsequent pipeline triggers pick up
    # upstream schema changes; per-trigger we still pay one fresh fetch.
    _METADATA_FILE_CACHE_TTL_SECONDS = 60

    # Network-level exceptions treated as transient by ``_http_get``'s retry
    # loop. ``ConnectionError`` covers TCP resets, DNS failures, and remote
    # disconnects (e.g. the server killed the keep-alive connection mid-
    # request). ``Timeout`` covers both connect and read timeouts.
    # ``ChunkedEncodingError`` covers servers that close mid-body during a
    # chunked transfer (seen in practice with Hexagon SCApi under load).
    _TRANSIENT_NETWORK_ERRORS = (
        requests.exceptions.ConnectionError,
        requests.exceptions.Timeout,
        requests.exceptions.ChunkedEncodingError,
    )

    # HTTP status codes treated as transient by ``_http_get``'s retry loop:
    # * 429 — Too Many Requests (throttling).
    # * 500 — Internal Server Error. Frequently transient (the "contact
    #   support" templated body that Hexagon SCApi returns under load is
    #   the prototype case); deterministic 500s eat the retry budget and
    #   surface the original body, same as deterministic 503s.
    # * 502 — Bad Gateway. Upstream proxy failure; virtually always
    #   transient.
    # * 503 — Service Unavailable. Server overload / restart.
    # * 504 — Gateway Timeout. Upstream took too long; same shape as 502.
    # 429 and 503 honour the server's ``Retry-After`` header when present;
    # 500/502/504 fall back to pure exponential backoff (Retry-After is
    # rarely emitted on those, and we shouldn't trust it if it is).
    _RETRYABLE_HTTP_STATUSES = frozenset({429, 500, 502, 503, 504})

    # Module logger. Always-on:
    #   * WARNING — every retry (network/429/503/JSON decode), so an
    #     operator inspecting pipeline logs sees how often the source
    #     flakes without enabling anything extra.
    #   * ERROR   — JSON decode failure (after retries exhausted) and
    #     other terminal problems re-raised as exceptions.
    # Opt-in via the ``verbose_http_logging`` connection option:
    #   * INFO    — one log line per request URL + response status / body
    #     snippet. Useful for triaging "why am I missing rows" but
    #     **emits source data into the log stream**, so it's off by
    #     default. Body snippet length is bounded by
    #     ``verbose_http_log_body_chars`` (default 500).
    _LOG = logging.getLogger(__name__)


    def _metadata_cache_path(service_url: str) -> str:
        """Tempdir path for the pickled CSDL of ``service_url``."""
        digest = hashlib.sha256(service_url.encode("utf-8")).hexdigest()[:16]
        return os.path.join(tempfile.gettempdir(), f"odata_csdl_{digest}.pickle")


    def _clear_metadata_cache() -> None:
        """Clear the in-process CSDL cache and remove any on-disk pickle
        files. Tests use this between cases that reuse a ``service_url``
        with different mocked ``$metadata`` bodies."""
        _METADATA_CACHE.clear()
        # Best-effort cleanup of all on-disk cache files. Tests don't know
        # the service_url hash in advance, so wipe the whole pattern.
        tmpdir = tempfile.gettempdir()
        try:
            for entry in os.listdir(tmpdir):
                if entry.startswith("odata_csdl_") and entry.endswith(".pickle"):
                    try:
                        os.remove(os.path.join(tmpdir, entry))
                    except OSError:
                        pass
        except OSError:
            pass


    @dataclass
    class _CsdlIndex:
        """One-time index of a parsed CSDL document.

        Before this index existed every metadata lookup (resolve an entity
        set to its type, follow a base-type chain, find an entity type by
        qualified name) re-walked the whole ET tree. On a multi-MB CSDL
        that's tens of milliseconds per call, and the connector makes
        dozens of calls per table — measurable both during INITIALIZING
        (table discovery, schema inference) and during steady-state
        incremental reads (FK column resolution per batch).

        The index is built once per parsed root and bundled with that root
        in the in-memory cache; whenever the root is refreshed (file-cache
        TTL expiry, in-process eviction) the index is rebuilt with it.
        Per-instance memo dicts hang off ``ODataLakeflowConnect`` rather
        than this dataclass — they're populated lazily by callers and
        invalidated when the index they were built against is replaced.
        """

        # Every ``(schema_namespace, entity_set_name)`` pair declared in
        # ``$metadata``. Order matches CSDL declaration order so error
        # hints and listings stay deterministic.
        entity_set_pairs: list[tuple[str, str]]
        # ``(namespace, entity_set_name) → entity_type_ref_string`` — the
        # raw ``EntityType=`` attribute the entity set points at.
        entity_set_to_type_ref: dict[tuple[str, str], str]
        # ``entity_set_name → list[(namespace, type_ref)]``. Multiple
        # entries means the same name lives in two schemas; callers must
        # disambiguate via the ``namespace`` table option.
        entity_set_by_name: dict[str, list[tuple[str, str]]]
        # ``namespace → list[entity_set_name]``. Used for error hints when
        # a namespace was supplied but the set wasn't found.
        entity_set_names_by_ns: dict[str, list[str]]
        # ``namespace_or_alias → canonical_namespace``. CSDL ``Alias``
        # attributes route through here so ``BaseType="graph.user"``
        # resolves to the schema declaring ``Namespace="microsoft.graph"``.
        alias_to_namespace: dict[str, str]
        # Fully-qualified type name (using canonical namespace) →
        # ``EntityType`` element. The qname uses the canonical namespace,
        # not any alias; callers must alias-resolve first.
        entity_type_by_qname: dict[str, ET.Element]
        # All namespaces that declare at least one entity set. Used for
        # error hints when the requested namespace declares only types.
        namespaces_with_sets: list[str]


    def _build_csdl_index(root: ET.Element) -> _CsdlIndex:
        """Single tree walk that populates every lookup in ``_CsdlIndex``.

        The CSDL can declare multiple ``<Schema>`` blocks; each schema can
        declare entity types and (optionally) an ``<EntityContainer>`` with
        entity sets. The walk threads schemas → containers → entity sets in
        one pass while also indexing every ``<EntityType>`` by qualified
        name. Subsequent dict lookups replace what used to be O(N) tree
        scans.
        """
        entity_set_pairs: list[tuple[str, str]] = []
        entity_set_to_type_ref: dict[tuple[str, str], str] = {}
        entity_set_by_name: dict[str, list[tuple[str, str]]] = {}
        entity_set_names_by_ns: dict[str, list[str]] = {}
        alias_to_namespace: dict[str, str] = {}
        entity_type_by_qname: dict[str, ET.Element] = {}
        namespaces_with_sets: list[str] = []

        for schema in root.iter(f"{_NS_EDM}Schema"):
            ns = schema.get("Namespace") or ""
            if ns:
                alias_to_namespace[ns] = ns
            alias = schema.get("Alias")
            if alias:
                alias_to_namespace[alias] = ns

            for entity_type in schema.findall(f"{_NS_EDM}EntityType"):
                type_name = entity_type.get("Name")
                if type_name:
                    entity_type_by_qname[f"{ns}.{type_name}"] = entity_type

            had_set = False
            for container in schema.iter(f"{_NS_EDM}EntityContainer"):
                for es in container.iter(f"{_NS_EDM}EntitySet"):
                    set_name = es.get("Name")
                    type_ref = es.get("EntityType") or ""
                    entity_set_pairs.append((ns, set_name))
                    entity_set_to_type_ref[(ns, set_name)] = type_ref
                    entity_set_by_name.setdefault(set_name, []).append((ns, type_ref))
                    entity_set_names_by_ns.setdefault(ns, []).append(set_name)
                    had_set = True
            if had_set and ns and ns not in namespaces_with_sets:
                namespaces_with_sets.append(ns)

        return _CsdlIndex(
            entity_set_pairs=entity_set_pairs,
            entity_set_to_type_ref=entity_set_to_type_ref,
            entity_set_by_name=entity_set_by_name,
            entity_set_names_by_ns=entity_set_names_by_ns,
            alias_to_namespace=alias_to_namespace,
            entity_type_by_qname=entity_type_by_qname,
            namespaces_with_sets=namespaces_with_sets,
        )


    @dataclass
    class _MetadataState:
        """Per-instance bundle for parsed-CSDL state: the root, the index
        built from it, and the memo dicts populated as callers walk it.

        Bundling lets ``ODataLakeflowConnect`` stay within pylint's
        instance-attribute budget (one attribute vs. seven) and ensures
        the memos invalidate atomically when the root is refreshed —
        callers reach for ``self._metadata`` and either get the full
        bundle or rebuild it from scratch."""

        root: ET.Element
        index: _CsdlIndex
        # All memos are keyed off either ``id(et)`` (for methods taking
        # an ``ET.Element``) or ``(table_name, namespace)``. They're
        # safe across the lifetime of ``root`` because element identity
        # is stable within one parsed tree.
        fields: dict = field(default_factory=dict)
        primary_keys: dict = field(default_factory=dict)
        base_chain: dict = field(default_factory=dict)
        own_fields: dict = field(default_factory=dict)
        own_pks: dict = field(default_factory=dict)
        entity_type: dict = field(default_factory=dict)
        fk_columns: dict = field(default_factory=dict)


    def _next_sequence() -> str:
        """Strictly-increasing per-record sequence value for apply_changes.

        Format: ``<ns_since_epoch:020d>_<counter:012d>``. Both parts
        are zero-padded so the lexicographic string ordering used by
        ``apply_changes`` matches the underlying numeric ordering. The
        nanosecond timestamp tracks wall-clock so values stay ordered
        across process restarts (latest data wins per key); the counter
        breaks ties for records emitted in the same nanosecond.

        ``time.time_ns()`` skips the ``datetime`` + ``strftime`` round-
        trip the previous ISO-8601 format paid per row — meaningful for
        delta-tracked tables that synthesise a sequence on every record.
        """
        return f"{time.time_ns():020d}_{next(_SEQUENCE_COUNTER):012d}"


    class ODataLakeflowConnect(
        LakeflowConnect,
        SupportsNamespaces,
        PartitionMixin,
        ContainedNavMixin,
    ):
        """LakeflowConnect implementation for OData v4 services.

        OData ``$metadata`` documents can declare multiple ``<Schema>`` blocks,
        each with its own namespace and its own entity sets. Two schemas in the
        same service can re-use entity set names (e.g. ``Sales.Customers`` and
        ``HR.Customers``), so this connector exposes the schema namespace as a
        single-segment Lakeflow namespace path.

        Pipelines disambiguate by passing ``namespace`` in *table_options*. When
        only one schema declares a given table name, ``namespace`` may be omitted.
        """

        def __init__(self, options: dict[str, str]) -> None:
            super().__init__(options)
            self.service_url = _require(options, "service_url")
            # Default 180s (3 min). Deep ``expand_contained=true`` chains
            # (3+ segments) materialise a large cross-product server-side
            # before responding; 60s isn't long enough for most real
            # deployments and the previous default surfaced as
            # ``ReadTimeout`` retried-to-exhaustion failures. Connection
            # option ``timeout_seconds`` overrides per deployment.
            self.timeout = int(options.get("timeout_seconds", "180"))
            # On-disk pickle TTL. The default suits typical 1-minute SDP
            # trigger intervals — each trigger spawns a fresh forked
            # worker, the file cache survives, but stale state is bounded.
            # Users with stable schemas can raise this to skip even the
            # first-fork fetch within a longer window; users iterating on
            # the source model can drop it to 0 to disable file caching.
            self.metadata_cache_ttl_seconds = int(
                options.get("metadata_cache_ttl_seconds", _METADATA_FILE_CACHE_TTL_SECONDS)
            )
            # Retry budget for transient server-side failures (HTTP 429 / 503).
            # 5 attempts at exponential backoff (1, 2, 4, 8, 16 s) covers the
            # vast majority of momentary throttling spikes from Graph /
            # Dataverse / S/4HANA Cloud without keeping a Spark task pinned
            # indefinitely. `retry_max_delay_seconds` caps any single sleep —
            # honour the server's Retry-After header but never sleep longer
            # than this (some misbehaving servers emit hour-long values).
            self.max_retries = int(options.get("max_retries", "5"))
            self.retry_max_delay_seconds = int(options.get("retry_max_delay_seconds", "60"))
            # Per-request diagnostic logging. Off by default — when on,
            # writes one INFO line per HTTP request (URL + status + body
            # snippet) to the module logger. The body snippet is the
            # source's response data, so enabling this emits source rows
            # into pipeline logs; turn it on only for triage.
            self.verbose_http_logging = (
                options.get("verbose_http_logging") or "false"
            ).strip().lower() == "true"
            # How many chars of the response body to include in each INFO
            # log line when ``verbose_http_logging`` is on. Default 500.
            self.verbose_http_log_body_chars = int(options.get("verbose_http_log_body_chars", "500"))
            self._session: requests.Session | None = None
            # Parsed CSDL bundle: root + lookup index + per-instance memos.
            # ``None`` until the first ``_metadata_root()`` call.
            self._metadata: _MetadataState | None = None
            # Monotonic deadline (seconds) for the current OAuth access token.
            # Set when the token endpoint returns ``expires_in``; `None` means we
            # don't know the expiry (user-supplied access token without metadata)
            # so we fall through to the 401-retry path only.
            self._access_token_expires_at: float | None = None
            # Delta-tracking capability cache, keyed by (namespace_or_empty,
            # table_name). Populated lazily by ``_probe_delta_support`` on the
            # first metadata-resolution call for each table in ``auto`` mode.
            # ``enabled`` mode trusts the user and skips the cache; ``disabled``
            # mode never touches it.
            self._delta_capable: dict[tuple[str, str], bool] = {}

        # ------------------------------------------------------------------
        # LakeflowConnect interface
        # ------------------------------------------------------------------

        def list_tables(self) -> list[str]:
            """Flat fallback used by the framework when SupportsNamespaces is absent.

            Includes both top-level entity sets and contained collections
            reachable via ``ContainsTarget="true"`` navigation properties
            (double-underscore-pathed, e.g. ``Instances__Assets__AssetDocuments``).
            """
            names: set[str] = set()
            for ns, es_name in self._entity_set_index():
                names.add(es_name)
                names.update(self._enumerate_contained_paths(es_name, ns))
            return sorted(names)

        def list_namespaces(self, prefix: list[str] | None = None) -> list[list[str]]:
            # OData has a single, flat level of schema namespaces. Anything
            # below the root has no further children.
            if prefix:
                return []
            index = self._entity_set_index()
            seen = sorted({ns for ns, _ in index if ns})
            return [[ns] for ns in seen]

        def list_tables_in_namespace(self, namespace: list[str]) -> list[str]:
            index = self._entity_set_index()
            if not namespace:
                # Entity sets always live inside a Schema with a Namespace
                # attribute; root-level tables don't exist in OData v4.
                return []
            target = namespace[0]
            flat = sorted({es for ns, es in index if ns == target})
            contained: set[str] = set()
            for es_name in flat:
                contained.update(self._enumerate_contained_paths(es_name, target))
            return flat + sorted(contained)

        def get_table_schema(self, table_name: str, table_options: dict[str, str]) -> StructType:
            namespace = (table_options or {}).get("namespace")
            self._set_excluded_ancestor_columns(table_options)
            excluded = self._excluded_ancestor_columns
            fields = self._fields_for(table_name, namespace)
            # ``exclude_ancestor_columns`` can ONLY drop synthetic ancestor-FK
            # columns (the filter in ``_resolve_fk_columns`` iterates the FK
            # mapping alone) — a leaf/own table column named here is left in
            # place. Validate against the path's real FK columns, but only for
            # contained paths: a flat table has none, so a connection-wide
            # default applied to it is a silent no-op rather than warning noise.
            if excluded and "*" not in excluded and _parse_contained_path(table_name) is not None:
                segments = _parse_contained_path(table_name)
                all_fk = self._all_fk_column_names(segments, namespace)
                non_fk = excluded - all_fk
                if non_fk:
                    # Split into "names a real table column (kept on purpose)"
                    # vs "matches nothing (likely a typo)" so the message is
                    # actionable either way.
                    own_cols = {f.name for f in fields} - all_fk
                    kept = sorted(non_fk & own_cols)
                    typos = sorted(non_fk - own_cols)
                    if kept:
                        _LOG.warning(
                            "exclude_ancestor_columns for %r names %s, which are "
                            "table columns, not synthetic ancestor-FK columns; they "
                            "are kept (only ancestor-FK columns can be excluded).",
                            table_name,
                            kept,
                        )
                    if typos:
                        _LOG.warning(
                            "exclude_ancestor_columns for %r names %s, which match "
                            "no column of this path (FK columns: %s); they have no "
                            "effect. Check for typos.",
                            table_name,
                            typos,
                            sorted(all_fk),
                        )
            select = (table_options or {}).get("select")
            if select:
                wanted = {c.strip() for c in select.split(",")}
                # ``select`` filters leaf columns only; FK columns survive.
                segments = _parse_contained_path(table_name) or [table_name]
                fk_names = set(self._resolve_fk_columns(segments, namespace).values())
                fields = [f for f in fields if f.name in fk_names or f.name in wanted]
            # Contained path + cursor_field lives on an ancestor → propagate
            # the ancestor's cursor column type onto the leaf schema. The
            # incremental read path stamps the value onto each emitted row.
            cursor_field = (table_options or {}).get("cursor_field")
            if cursor_field:
                ancestor_cursor = self._ancestor_cursor_field(table_name, namespace, cursor_field)
                if ancestor_cursor is not None and ancestor_cursor.name not in {f.name for f in fields}:
                    fields = list(fields) + [ancestor_cursor]
            if not fields:
                raise ValueError(
                    f"Could not derive a non-empty schema for entity set {table_name!r}. "
                    f"Check the 'select' option."
                )
            # When delta tracking is active for this table the connector emits
            # two synthetic columns alongside the entity's own properties:
            # ``_deleted`` (in-band tombstone flag) and ``_lc_sequence`` (the
            # cursor column apply_changes uses to order updates). Both must be
            # in the declared schema so Spark accepts the records.
            if self._delta_active_for(table_name, table_options):
                fields = list(fields) + [
                    StructField(_DELETED_COL, BooleanType(), False),
                    StructField(_SEQUENCE_COL, StringType(), False),
                ]
            return StructType(fields)

        def read_table_metadata(self, table_name: str, table_options: dict[str, str]) -> dict:
            namespace = (table_options or {}).get("namespace")
            self._set_excluded_ancestor_columns(table_options)
            primary_keys = self._primary_keys_for(table_name, namespace)
            user_cursor = (table_options or {}).get("cursor_field")
            # Contained paths skip the delta probe (server delta is for
            # top-level sets only; mutex enforced in dispatch below).
            if _parse_contained_path(table_name) is None and self._delta_active_for(
                table_name, table_options
            ):
                return {
                    "primary_keys": primary_keys,
                    "cursor_field": _SEQUENCE_COL,
                    "ingestion_type": "cdc",
                }
            return {
                "primary_keys": primary_keys,
                "cursor_field": user_cursor,
                "ingestion_type": "cdc" if user_cursor else "snapshot",
            }

        def read_table(
            self, table_name: str, start_offset: dict, table_options: dict[str, str]
        ) -> tuple[Iterator[dict], dict]:
            # The Spark Python Data Source batch reader
            # (``LakeflowBatchReader``) passes ``start_offset=None`` and
            # discards the returned end-offset — so any continuation state
            # the connector would normally park in the offset (e.g.
            # ``pending_fetches`` on the ``expand_contained=true`` path,
            # ``chain_next_link`` on the leaf-cursor N+1 path) is dropped.
            # Honouring ``max_records_per_batch`` here would therefore
            # truncate the read at the cap and silently lose the remainder:
            # a cap can only do something *correct* when the offset survives
            # to resume from, which it never does under the batch reader.
            # So treat ``start_offset is None`` as the batch-mode signal and
            # force the cap effectively-infinite regardless of whether the
            # user set one — warning when we override a user value so the
            # ignored option isn't silent. Streaming readers always pass a
            # dict (``{}`` or the parked offset) and keep their cap intact.
            # The cursor read paths additionally stream lazily in this mode
            # (see ``_read_incremental`` / ``_read_contained_incremental`` /
            # ``_read_contained_expand``) so an uncapped batch doesn't
            # materialise the whole result set in memory.
            opts = dict(table_options or {})
            # Pagination strategy for this read. keyset/skip/auto drive
            # pagination client-side (for servers that omit @odata.nextLink)
            # and need a $top to size pages, so force a default page_size when
            # the user left it unset. Held on ``self`` for the duration of the
            # read so the shared fetch primitives pick it up without threading
            # it through every call site; defaults to nextlink (today's
            # behaviour) for any path that doesn't set it.
            self._pagination = self._parse_pagination(opts)
            self._set_excluded_ancestor_columns(opts)
            # Overlap re-read window for non-atomic walks. Held on ``self`` for
            # the read's duration (like ``_pagination``); the floor is applied
            # only to the read filter (``_apply_cursor_lookback``), never to the
            # committed offset. Applies to every contained cursor-read path —
            # ``expand_contained=true``, the N+1 leaf-cursor walk, and the
            # ``cursor_probe`` hydrate — each of which self-sizes the ``auto``
            # window from its measured walk duration. No-op for non-timestamp
            # cursors.
            self._cursor_lookback = self._parse_cursor_lookback(opts)
            # ``auto`` tuning knobs (ignored for static/off modes).
            self._cursor_lookback_factor = self._parse_cursor_lookback_factor(opts)
            self._cursor_lookback_max_seconds = self._parse_cursor_lookback_ceiling(opts)
            # Resolved per-read in the expand-cursor path (see
            # ``_read_contained_expand``); stays 0 for every other read.
            self._active_lookback_seconds = 0
            # Only an EXPLICIT positive window is validated against the read
            # config — the default ``auto`` is a no-op outside the expand-cursor
            # path, so leaving it on for flat / N+1 / snapshot tables must not
            # raise.
            if (
                isinstance(self._cursor_lookback, int)
                and self._cursor_lookback > 0
                and not (_parse_contained_path(table_name) is not None and opts.get("cursor_field"))
            ):
                raise ValueError(
                    "cursor_lookback_seconds (an explicit value) is supported "
                    "only with a cursor_field on a contained path — it floors the "
                    "read filter for the non-atomic expand_contained=true walk and "
                    "the leaf-cursor N+1 / cursor_probe walk. Use 'auto' (default) "
                    "or 'off' for other read configurations."
                )
            # ``auto`` (the default) is a best-effort hint that no-ops where it can't
            # engage, so these conflict checks fire only on an EXPLICIT strategy
            # opt-in (``cursor_probe=nested-expand`` or ``cursor_probe=batch``) — otherwise
            # every flat / snapshot / expand_contained read would trip them.
            cursor_probe_raw = (opts.get("cursor_probe") or "").strip().lower()
            if "cursor_probe" in opts and self._cursor_probe_mode(opts) in ("probe", "batch"):
                if _parse_contained_path(table_name) is None:
                    raise ValueError(
                        f"cursor_probe={cursor_probe_raw} is supported only on "
                        f"contained-collection paths; {table_name!r} is a flat entity "
                        "set, which is already a single filtered request per batch."
                    )
                if self._expand_contained_active(opts):
                    raise ValueError(
                        f"cursor_probe={cursor_probe_raw} conflicts with "
                        "expand_contained=true: both fetch only changed leaves, by "
                        "different strategies. Pick one (expand_contained for shallow "
                        "trees; cursor_probe=nested-expand/batch for deep trees with sparse "
                        "changes)."
                    )
                if not opts.get("cursor_field"):
                    raise ValueError(
                        f"cursor_probe={cursor_probe_raw} requires a cursor_field (it "
                        "only changes how a leaf-owned cursor read is executed). Set "
                        "cursor_field or drop cursor_probe."
                    )
            if self._pagination != "nextlink":
                opts.setdefault("page_size", _DEFAULT_PAGE_SIZE)
            if start_offset is None:
                if "max_records_per_batch" in opts:
                    _LOG.warning(
                        "max_records_per_batch=%s ignored for %r: the batch reader "
                        "(LakeflowBatchReader) discards the returned offset, so a "
                        "cap can only truncate the read and silently drop the "
                        "remainder. Reading uncapped. Use a streaming table for a "
                        "resumable per-batch cap.",
                        opts["max_records_per_batch"],
                        table_name,
                    )
                opts["max_records_per_batch"] = str(_BATCH_UNCAPPED)
            # ``offset`` is a local view used for shape checks below.
            # The original ``start_offset`` (``None`` for batch reader,
            # ``{}`` or populated dict for streaming) is passed through to
            # the read methods so ``_finalize_cursor_read`` can distinguish
            # batch from streaming and skip the no-progress raise when the
            # framework will discard the returned offset anyway.
            offset = start_offset or {}
            if _parse_contained_path(table_name) is not None:
                if self._delta_setting(opts) == "enabled":
                    raise ValueError(
                        "delta_tracking=enabled is not supported on contained-"
                        "collection paths (server change tracking only applies "
                        "to top-level entity sets). Set delta_tracking=disabled "
                        "or ingest the parent set directly."
                    )
                if self._expand_contained_active(opts):
                    # Cursor-based expand keeps a default $top (page_size);
                    # snapshot expand omits $top when page_size is unset.
                    if opts.get("cursor_field"):
                        opts.setdefault("page_size", _DEFAULT_PAGE_SIZE)
                    return self._read_contained_expand(table_name, start_offset, opts)
                if opts.get("cursor_field"):
                    # Cursor-based read: default page_size so a $top is sent.
                    # Snapshot (the branch below) leaves it unset → no $top.
                    opts.setdefault("page_size", _DEFAULT_PAGE_SIZE)
                    return self._read_contained_incremental(
                        table_name, start_offset, opts, opts["cursor_field"]
                    )
                return self._read_contained_snapshot(table_name, opts)
            # Offset-shape check ahead of the delta predicate so a resumed
            # delta stream (offset carries delta_link / next_link) takes the
            # delta path even if delta_tracking is no longer set in options.
            if (
                "delta_link" in offset
                or "next_link" in offset
                or self._delta_active_for(table_name, opts)
            ):
                # Delta (CDC) is cursor-based — keep a default $top.
                opts.setdefault("page_size", _DEFAULT_PAGE_SIZE)
                return self._read_incremental_delta(table_name, offset, opts)
            if opts.get("cursor_field"):
                # Cursor-based read: default page_size so a $top is sent.
                # Snapshot (the branch below) leaves it unset → no $top.
                opts.setdefault("page_size", _DEFAULT_PAGE_SIZE)
                return self._read_incremental(table_name, start_offset, opts, opts["cursor_field"])
            return self._read_snapshot(table_name, opts)

        # ------------------------------------------------------------------
        # Snapshot + incremental read paths
        # ------------------------------------------------------------------

        def _read_snapshot(
            self, table_name: str, table_options: dict[str, str]
        ) -> tuple[Iterator[dict], dict]:
            # Return the page generator directly. Spark's
            # LakeflowBatchReader.read consumes it lazily through a
            # map(parse_value, ...), so each page is fetched, parsed, and
            # streamed out before the next page is requested. Materialising
            # the whole result into a list (the prior shape) pinned every
            # row in memory at once on large tables.
            segment_filters = _resolve_segment_filters(table_options, [table_name])
            # PK-only ``$orderby`` so server skiptoken paging is stable across
            # pages — OData v4 §11.2.5.7 doesn't promise a stable default
            # order, and a value-based skiptoken over an unstable sort can
            # drop or duplicate rows mid-scan. Empty (keyless entity) → no
            # ``$orderby`` appended.
            namespace = (table_options or {}).get("namespace")
            pk_order = ",".join(f"{pk} asc" for pk in self._primary_keys_for(table_name, namespace))
            url = self._build_url(
                table_name,
                table_options,
                extra_filter=segment_filters.get(0),
                order_by=pk_order or None,
            )
            return self._fetch_pages(url), {}

        def _read_incremental(
            self,
            table_name: str,
            start_offset: dict | None,
            table_options: dict[str, str],
            cursor_field: str,
        ) -> tuple[Iterator[dict], dict]:
            # No wall-clock upper bound on the cursor — `max_records_per_batch`
            # is the only per-call cap. Each call fetches `cursor gt since`
            # (no `le` clause), advances the offset, and Spark drives the
            # call loop. Two consequences worth knowing:
            #   * Continuous SDP pipelines pick up new rows as they arrive,
            #     because we never freeze a "snapshot at startup" timestamp.
            #     The connector instance can live for the whole stream and
            #     each batch still sees fresh source state.
            #   * Cursor type doesn't matter for the filter. Timestamps,
            #     monotonic integer IDs, GUIDs — anything the server can
            #     order in `$orderby` and compare in `$filter` works the
            #     same way. There is no type mismatch between the cursor
            #     literal and the server's column type because we don't
            #     manufacture a timestamp ceiling out of wall-clock time.
            if start_offset is None:
                # Batch reader: offset discarded, ``since`` is None (no
                # ``cursor gt`` filter), no cap and no no-progress guard — so
                # the watermark, same-cursor trim and ``records`` buffer the
                # streaming path builds all serve nothing. Stream pages
                # straight through so peak memory is one page, not the whole
                # table. See ``read_table`` for why the cap is force-disabled.
                return self._stream_incremental_flat(table_name, table_options, cursor_field), {}
            since = start_offset.get("cursor") if start_offset else None
            segment_filters = _resolve_segment_filters(table_options, [table_name])
            extra_filter = _combine_filters(
                self._cursor_filter(cursor_field, since),
                segment_filters.get(0),
            )
            # Append primary-key columns as $orderby tie-breakers. Without a
            # fully unique sort, OData servers that paginate internally (via
            # `@odata.nextLink` with a value-based skiptoken) can split a
            # same-cursor cohort across pages: the skiptoken's strict-`>` on
            # the cursor value drops the unread tail. A unique total ordering
            # forces the skiptoken to use the key as well, so no rows are lost.
            namespace = (table_options or {}).get("namespace")
            order_terms = [f"{cursor_field} asc"]
            for pk in self._primary_keys_for(table_name, namespace):
                if pk != cursor_field:
                    order_terms.append(f"{pk} asc")
            url = self._build_url(
                table_name,
                table_options,
                extra_filter=extra_filter,
                order_by=",".join(order_terms),
            )
            max_records = int(table_options.get("max_records_per_batch", "10000"))
            # ``cursor_nulls`` policy: ``effective`` yields the value used for
            # filtering/trim/watermark (a synthetic floor for nulls under
            # ``coalesce``); ``skip_null`` drops null-cursor rows under
            # ``ignore``. The emitted row is never mutated — its cursor column
            # keeps the real null.
            skip_null, effective = self._make_cursor_resolver(
                table_name, namespace, cursor_field, table_options
            )

            records: list[dict] = []
            truncated = False
            for row in self._fetch_pages(url):
                if skip_null and row.get(cursor_field) is None:
                    continue
                rec_cursor = effective(row)
                if since is not None and rec_cursor is not None and rec_cursor <= since:
                    continue
                records.append(row)
                if len(records) >= max_records:
                    truncated = True
                    break

            if not records:
                return iter([]), start_offset or {}

            # Cursor boundary safety: the next call resumes with
            # `cursor gt <last_cursor>`, so if the trailing records share that
            # cursor with unseen records on the next page — OR with concurrently
            # inserted siblings that arrive before the next call — the `gt`
            # filter would silently drop them. Trim back to the last distinct
            # cursor on every batch (not just truncated ones), so a stop/restart
            # or natural completion can't lose same-cursor inserts at the boundary.
            # Re-fetched rows on the next call are deduped at the destination
            # via apply_changes' MERGE on the primary key.
            trimmed = _trim_to_distinct_cursor_boundary(records, cursor_field)
            if not trimmed:
                # Every record in this batch shares one cursor value (including
                # an all-null-cursor batch, which trims to empty here and is
                # kept as-is; under cursor_nulls=coalesce the watermark still
                # advances via the synthetic effective value below).
                if truncated:
                    raise RuntimeError(
                        f"max_records_per_batch ({max_records}) is too small for "
                        f"{table_name!r}: every record in the batch shares cursor "
                        f"value {records[-1].get(cursor_field)!r}. Increase "
                        f"max_records_per_batch above the largest same-cursor "
                        f"cohort, or choose a higher-cardinality cursor field."
                    )
                # Natural exhaustion of a single-cursor cohort. Emit as-is —
                # trimming would lose data with no way to re-fetch. There's a
                # residual race for same-cursor rows added between now and any
                # future call, which is unavoidable without finer cursor resolution.
            else:
                records = trimmed

            # OData responses ordered by the cursor — the trailing distinct
            # cursor carries the watermark in the common case. But a nullable
            # cursor with server-dependent null-ordering can produce records
            # with null cursor values, and the cohort fall-through above
            # keeps records as-is when every value is null. Compute ``max``
            # over the non-null cursors and fall back to ``since`` / ``{}``
            # — mirrors ``_read_contained_incremental_leaf_cursor``'s
            # normalization. The shared no-progress guard then fires on
            # null-only batches (committing ``{"cursor": None}`` would loop
            # because every subsequent trigger re-emits the same nulls).
            cursors = [effective(r) for r in records if effective(r) is not None]
            end_offset = self._cursor_max_end_offset(cursors, since)
            return self._finalize_cursor_read(
                start_offset, end_offset, records, table_name, cursor_field
            )

        def _stream_incremental_flat(
            self, table_name: str, table_options: dict[str, str], cursor_field: str
        ) -> Iterator[dict]:
            """Lazy batch-mode flat cursor read.

            Mirrors ``_read_incremental``'s per-row work minus everything the
            batch reader makes moot: no ``cursor gt`` filter (``since`` is
            None), no cap, no same-cursor trim, no watermark, no no-progress
            guard. The only per-row behaviour kept is ``cursor_nulls=ignore``
            null-skipping (``coalesce`` emits the real null as-is here, since
            nothing consumes the synthetic ``effective`` value). Pages stream
            through ``_fetch_pages`` so peak memory is one page."""
            namespace = (table_options or {}).get("namespace")
            segment_filters = _resolve_segment_filters(table_options, [table_name])
            order_terms = [f"{cursor_field} asc"]
            for pk in self._primary_keys_for(table_name, namespace):
                if pk != cursor_field:
                    order_terms.append(f"{pk} asc")
            url = self._build_url(
                table_name,
                table_options,
                extra_filter=segment_filters.get(0),
                order_by=",".join(order_terms),
            )
            skip_null, _effective = self._make_cursor_resolver(
                table_name, namespace, cursor_field, table_options
            )
            for row in self._fetch_pages(url):
                if skip_null and row.get(cursor_field) is None:
                    continue
                yield row

        def _read_incremental_delta(
            self,
            table_name: str,
            start_offset: dict,
            table_options: dict[str, str],
        ) -> tuple[Iterator[dict], dict]:
            """Delta-tracked read via OData ``Prefer: odata.track-changes``.

            Three offset shapes, three entry behaviours:

            * No ``delta_link`` and no ``next_link`` — bootstrap. Send the
              initial entity-set GET with ``Prefer: odata.track-changes``,
              verify the server acknowledges via ``Preference-Applied``, and
              stream the full snapshot. The terminal page carries
              ``@odata.deltaLink``.
            * ``next_link`` set — we hit ``max_records_per_batch`` mid-
              pagination on a previous call. Resume by walking from that
              link.
            * ``delta_link`` set — server's "changes since" cursor. Walk
              ``@odata.nextLink`` chain (if any) until the terminal page
              delivers a fresh ``@odata.deltaLink``.

            Records emitted carry two synthetic columns: ``_deleted`` (bool,
            in-band tombstone flag — set ``True`` for ``@removed`` entries)
            and ``_lc_sequence`` (monotonic per-record string used as
            apply_changes' sequence column). The microsoft_teams connector
            established this convention in this repo; we follow it so the
            framework's standard ``cdc`` path handles tombstones without
            needing ``cdc_with_deletes`` + ``read_table_deletes`` split.
            """
            prev_delta_link = (start_offset or {}).get("delta_link")
            prev_next_link = (start_offset or {}).get("next_link")
            is_bootstrap = prev_delta_link is None and prev_next_link is None
            url, initial_headers = self._delta_initial_request(
                table_name, table_options, prev_delta_link, prev_next_link
            )

            namespace = (table_options or {}).get("namespace")
            primary_keys = self._primary_keys_for(table_name, namespace)
            max_records = int((table_options or {}).get("max_records_per_batch", "10000"))

            records, new_delta_link, carry_next_link, rebootstrap = self._delta_walk_pages(
                url=url,
                initial_headers=initial_headers,
                is_bootstrap=is_bootstrap,
                prev_delta_link=prev_delta_link,
                prev_next_link=prev_next_link,
                table_name=table_name,
                table_options=table_options,
                primary_keys=primary_keys,
                max_records=max_records,
            )
            if rebootstrap:
                # 410 Gone surfaced during pagination → re-bootstrap from
                # scratch. ``MERGE``-on-PK + ``_lc_sequence`` ordering
                # reconciles re-fetched rows at the destination; no data
                # loss, only HTTP cost.
                return self._read_incremental_delta(table_name, {}, table_options)

            # Graph-rotation guard. Some servers (notably Microsoft Graph)
            # mint a fresh ``@odata.deltaLink`` on every response, even when
            # the change set is empty. If we already had a delta link and
            # produced no records this call, hand back the prior link so the
            # framework sees ``end_offset == start_offset`` and a trigger
            # like AvailableNow can terminate. Following microsoft_teams.py.
            if prev_delta_link is not None and not records and not carry_next_link:
                return iter([]), {"delta_link": prev_delta_link}

            if carry_next_link:
                offset: dict = {"next_link": carry_next_link}
                # Preserve the prior delta_link as a fallback if the
                # next_link expires before the cap-resume call lands.
                if prev_delta_link is not None:
                    offset["delta_link"] = prev_delta_link
                return iter(records), offset

            if new_delta_link is None:
                # Reached end of stream without a deltaLink. Server is
                # misbehaving (spec requires the terminal page to carry one).
                # Resume from the prior delta_link if we have one — better
                # than losing the offset entirely.
                if prev_delta_link is not None:
                    return iter(records), {"delta_link": prev_delta_link}
                raise RuntimeError(
                    f"OData delta bootstrap for {table_name!r} ended without an "
                    f"@odata.deltaLink. The server may have aborted change "
                    f"tracking. Set delta_tracking=disabled to fall back to "
                    f"snapshot or cursor-based reads."
                )

            return iter(records), {"delta_link": new_delta_link}

        def _build_delta_record(self, item: dict, primary_keys: list[str]) -> dict:
            """Translate one delta payload entry into the emitted record shape.

            - ``@removed`` entries become tombstones: a record carrying the
              primary-key fields plus ``_deleted=True``.
            - Regular adds/changes pass through with all ``@odata.*`` control
              properties stripped and ``_deleted=False``.

            Every emitted record gets ``_lc_sequence`` — a strictly monotonic
            string — so apply_changes has a deterministic sequence_by column.
            """
            if "@removed" in item:
                record: dict = {pk: item.get(pk) for pk in primary_keys}
                record[_DELETED_COL] = True
            else:
                record = {k: v for k, v in item.items() if not k.startswith("@odata.")}
                record[_DELETED_COL] = False
            record[_SEQUENCE_COL] = _next_sequence()
            return record

        def _delta_initial_request(
            self,
            table_name: str,
            table_options: dict[str, str] | None,
            prev_delta_link: str | None,
            prev_next_link: str | None,
        ) -> tuple[str, dict[str, str] | None]:
            """Pick the first URL + headers for a delta read.

            ``next_link`` wins over ``delta_link`` when both are present —
            we were mid-pagination on a cap hit, finish that before
            consulting the prior change cursor.
            """
            if prev_next_link is not None:
                return prev_next_link, None
            if prev_delta_link is not None:
                return prev_delta_link, None
            segment_filters = _resolve_segment_filters(table_options, [table_name])
            return (
                self._build_url(table_name, table_options or {}, extra_filter=segment_filters.get(0)),
                {"Prefer": _DELTA_PREFER},
            )

        def _delta_walk_pages(
            self,
            *,
            url: str,
            initial_headers: dict[str, str] | None,
            is_bootstrap: bool,
            prev_delta_link: str | None,
            prev_next_link: str | None,
            table_name: str,
            table_options: dict[str, str] | None,
            primary_keys: list[str],
            max_records: int,
        ) -> tuple[list[dict], str | None, str | None, bool]:
            """Walk the ``@odata.nextLink`` chain until a deltaLink, cap, or 410.

            Returns ``(records, new_delta_link, carry_next_link, rebootstrap)``:

            * ``records`` — emitted records (already passed through
              :py:meth:`_build_delta_record`).
            * ``new_delta_link`` — the freshest ``@odata.deltaLink`` seen.
            * ``carry_next_link`` — set when ``max_records`` capped the read
              mid-pagination; the caller persists this in the offset.
            * ``rebootstrap`` — True iff a 410 fired on a stored link; the
              caller re-issues from a fresh empty offset.
            """
            session = self._get_session()
            records: list[dict] = []
            new_delta_link: str | None = None
            carry_next_link: str | None = None
            page_index = 0
            bootstrap_verified = not is_bootstrap
            sparse_checked = False
            current_url: str | None = url

            while current_url:
                headers = initial_headers if (page_index == 0 and initial_headers) else None
                kwargs: dict[str, Any] = {"headers": headers} if headers else {}
                resp = self._http_get(session, current_url, **kwargs)
                if resp.status_code == 410 and (prev_delta_link or prev_next_link):
                    return [], None, None, True
                _raise_for_status_with_body(resp, current_url)

                if not bootstrap_verified:
                    self._verify_delta_bootstrap(resp, table_name)
                    bootstrap_verified = True

                payload = _decode_json_with_body(resp, current_url)
                sparse_checked = self._delta_collect_page_records(
                    payload=payload,
                    records=records,
                    primary_keys=primary_keys,
                    table_name=table_name,
                    table_options=table_options,
                    sparse_checked=sparse_checked,
                    max_records=max_records,
                )
                fetched_url = resp.url
                current_url, new_delta_link, carry_next_link = self._delta_advance_links(
                    payload=payload,
                    resp_url=resp.url,
                    records=records,
                    max_records=max_records,
                    new_delta_link=new_delta_link,
                    carry_next_link=carry_next_link,
                )
                if current_url is not None and current_url == fetched_url:
                    # Self-referential ``@odata.nextLink`` — the server handed back
                    # the URL we just fetched. Stop rather than loop forever; the
                    # caller persists ``new_delta_link`` (or falls back to the prior
                    # one) so the next run still resumes.
                    _LOG.warning(
                        "delta walk: server returned a self-referential "
                        "@odata.nextLink for %r; stopping to avoid an infinite loop.",
                        fetched_url,
                    )
                    break
                page_index += 1

            return records, new_delta_link, carry_next_link, False

        def _verify_delta_bootstrap(self, resp: requests.Response, table_name: str) -> None:
            """Confirm the server actually honored ``Prefer: odata.track-changes``."""
            applied = resp.headers.get("Preference-Applied", "")
            if _DELTA_PREFER not in applied.lower():
                raise RuntimeError(
                    f"OData server did not honor 'Prefer: odata.track-changes' "
                    f"for {table_name!r} (response missing 'Preference-Applied' "
                    f"header). The probe in delta_tracking=auto should have "
                    f"caught this — your service may have inconsistent support. "
                    f"Set delta_tracking=disabled and use cursor-based "
                    f"incremental instead."
                )

        def _delta_collect_page_records(
            self,
            *,
            payload: dict,
            records: list[dict],
            primary_keys: list[str],
            table_name: str,
            table_options: dict[str, str] | None,
            sparse_checked: bool,
            max_records: int,
        ) -> bool:
            """Append delta records from ``payload`` until cap or page exhaustion.

            Returns the updated ``sparse_checked`` flag so the caller can
            continue to skip the check on later pages once it's already
            passed for this call.
            """
            for item in payload.get("value", []):
                if not sparse_checked and "@removed" not in item:
                    self._check_no_sparse_entity(item, table_name, table_options)
                    sparse_checked = True
                records.append(self._build_delta_record(item, primary_keys))
                if len(records) >= max_records:
                    break
            return sparse_checked

        def _delta_advance_links(
            self,
            *,
            payload: dict,
            resp_url: str,
            records: list[dict],
            max_records: int,
            new_delta_link: str | None,
            carry_next_link: str | None,
        ) -> tuple[str | None, str | None, str | None]:
            """Resolve the next URL + offset bookkeeping after one page.

            Returns ``(next_url, new_delta_link, carry_next_link)``.
            ``next_url`` is ``None`` when pagination should stop (either we
            hit the cap, saw a terminal deltaLink, or the server omitted
            both pagination links).
            """
            raw_delta = payload.get("@odata.deltaLink")
            raw_next = payload.get("@odata.nextLink")
            cap_hit = len(records) >= max_records

            if cap_hit:
                if raw_next:
                    carry_next_link = urljoin(resp_url, raw_next)
                # Capture the deltaLink even on a cap-hit page — when the
                # cap lines up exactly with the terminal page we still want
                # the next-batch resume to follow ``delta_link`` rather
                # than re-walk the whole bootstrap.
                if raw_delta and new_delta_link is None:
                    new_delta_link = urljoin(resp_url, raw_delta)
                return None, new_delta_link, carry_next_link

            if raw_delta:
                new_delta_link = urljoin(resp_url, raw_delta)
                return None, new_delta_link, carry_next_link
            if raw_next:
                return urljoin(resp_url, raw_next), new_delta_link, carry_next_link
            return None, new_delta_link, carry_next_link

        def _check_no_sparse_entity(
            self,
            item: dict,
            table_name: str,
            table_options: dict[str, str] | None,
        ) -> None:
            """Refuse silently-corrupting sparse delta responses.

            OData v4 §11.4 lets a delta payload return only the *changed*
            properties on an updated entity. That sounds harmless until you
            realize the connector emits the dict as-is to Spark, which
            treats absent fields as NULL — overwriting good destination
            values with nulls on every partial update. The damage is silent
            and not recoverable from the destination table alone.

            We can't safely apply partial updates in v1, so refuse them up
            front with an actionable error. Run only on the first
            non-tombstone entry per call.

            The expected key set is the declared schema for the table, less
            any selection imposed by ``$select`` and less the synthetic
            ``_deleted`` / ``_lc_sequence`` columns we add ourselves.
            """
            select = (table_options or {}).get("select")
            if select:
                expected = {c.strip() for c in select.split(",") if c.strip()}
            else:
                namespace = (table_options or {}).get("namespace")
                expected = {f.name for f in self._fields_for(table_name, namespace)}
            expected -= {_DELETED_COL, _SEQUENCE_COL}
            actual = {k for k in item.keys() if not k.startswith("@odata.")}
            missing = expected - actual
            if missing:
                raise RuntimeError(
                    f"OData delta response for {table_name!r} returned a sparse "
                    f"entity: missing properties {sorted(missing)}. The connector "
                    f"cannot safely apply partial updates — every missing field "
                    f"would write NULL at the destination, silently corrupting "
                    f"data. Set delta_tracking=disabled to use cursor-based "
                    f"incremental, or restrict the schema with $select to only "
                    f"the fields the server always returns in delta payloads."
                )

        # ------------------------------------------------------------------
        # Delta tracking capability
        # ------------------------------------------------------------------

        def _delta_setting(self, table_options: dict[str, str] | None) -> str:
            """Resolve the delta_tracking option, normalised to lower case.

            Defaults to ``disabled``. Delta tracking is opt-in because most
            OData services don't honor ``Prefer: odata.track-changes``, and
            a default-``auto`` would burn one wasted HTTP probe per table
            per pipeline trigger on the common case where the user doesn't
            want this feature anyway.
            """
            raw = ((table_options or {}).get("delta_tracking") or "disabled").strip().lower()
            if raw not in {"auto", "enabled", "disabled"}:
                raise ValueError(
                    f"Invalid delta_tracking={raw!r}. Expected one of: auto, enabled, disabled."
                )
            return raw

        def _delta_cache_key(
            self, table_name: str, table_options: dict[str, str] | None
        ) -> tuple[str, str]:
            """Cache key for :py:attr:`_delta_capable` keyed on (namespace, table).

            Namespace defaults to the empty string when omitted so multi-schema
            services with a single un-namespaced declaration also key cleanly.
            """
            namespace = (table_options or {}).get("namespace") or ""
            return (namespace, table_name)

        def _delta_active_for(self, table_name: str, table_options: dict[str, str] | None) -> bool:
            """Whether delta tracking is the read mode for this table.

            Resolution order:
              1. ``delta_tracking=disabled`` → never.
              2. ``cursor_field`` set + ``delta_tracking=enabled`` → ValueError
                 (the two are mutually exclusive — delta tracking provides
                 its own sequencing).
              3. ``cursor_field`` set + ``delta_tracking=auto`` → cursor wins;
                 delta is left dormant, no probe.
              4. ``delta_tracking=enabled`` → assume support; a probe failure
                 surfaces at read time rather than here.
              5. ``delta_tracking=auto`` → probe once, cache, decide.
            """
            setting = self._delta_setting(table_options)
            if setting == "disabled":
                return False
            if (table_options or {}).get("cursor_field"):
                if setting == "enabled":
                    raise ValueError(
                        "delta_tracking=enabled is mutually exclusive with "
                        "cursor_field; the server-driven delta stream provides "
                        "its own sequencing. Remove cursor_field, or switch to "
                        "delta_tracking=disabled to use cursor-based incremental."
                    )
                return False
            if setting == "enabled":
                return True
            key = self._delta_cache_key(table_name, table_options)
            if key not in self._delta_capable:
                self._delta_capable[key] = self._probe_delta_support(table_name, table_options)
            return self._delta_capable[key]

        def _probe_delta_support(self, table_name: str, table_options: dict[str, str] | None) -> bool:
            """Light-touch capability probe.

            Sends a small GET against the entity set with the
            ``Prefer: odata.track-changes`` header and inspects the response
            headers for ``Preference-Applied: odata.track-changes``. That
            header is the spec's positive acknowledgement that the server is
            honoring change tracking on this request.

            Returns ``False`` for every failure mode (non-200, missing
            header, malformed body, network error). The cache is populated
            with that ``False`` so we don't retry the probe per call — the
            connector falls back to whatever cursor/snapshot path the
            user's options imply.
            """
            # Force ``$top=1`` for the probe so the response stays small even
            # against entity sets with millions of rows. We only care about
            # headers.
            probe_options = {**(table_options or {}), "page_size": "1"}
            url = self._build_url(table_name, probe_options)
            try:
                session = self._get_session()
                resp = self._http_get(
                    session,
                    url,
                    headers={"Prefer": _DELTA_PREFER},
                )
            except (requests.RequestException, ValueError, RuntimeError, PermissionError):
                return False
            if resp.status_code != 200:
                return False
            applied = resp.headers.get("Preference-Applied", "")
            return _DELTA_PREFER in applied.lower()

        # ------------------------------------------------------------------
        # URL + HTTP plumbing
        # ------------------------------------------------------------------

        def _build_url(
            self,
            table_name: str,
            table_options: dict[str, str],
            extra_filter: str | None = None,
            order_by: str | None = None,
        ) -> str:
            base = _join_url(self.service_url, table_name)
            return f"{base}?{self._format_query_params(table_options, extra_filter, order_by)}"

        def _format_query_params(
            self,
            table_options: dict[str, str],
            extra_filter: str | None = None,
            order_by: str | None = None,
        ) -> str:
            """Compose $top/$select/$filter/$orderby; shared across all URL builders.

            ``$top`` is emitted only when ``page_size`` is set. With no
            ``page_size`` the connector sends no ``$top`` at all and lets the
            server pick its own page size — some services reject or mishandle
            an explicit ``$top`` (e.g. a value above their per-page cap), and
            omitting it is the safe default. Server-driven paging via
            ``@odata.nextLink`` still walks the full collection either way.
            """
            opts = table_options or {}
            params = []
            if opts.get("page_size"):
                params.append(f"$top={opts['page_size']}")
            if opts.get("select"):
                params.append(f"$select={opts['select']}")
            filters = [f for f in (opts.get("filter"), extra_filter) if f]
            if filters:
                if len(filters) == 1:
                    # A single clause goes on the wire as-is. Wrapping it
                    # in parens would compound with any pre-wrapped clause
                    # passed via ``extra_filter`` (e.g. a multi-source
                    # ``combine_filters`` result), producing triple-paren
                    # ``$filter=((A) and (B))`` shapes that are harder to
                    # eyeball.
                    params.append(f"$filter={filters[0]}")
                else:
                    params.append(f"$filter={' and '.join(f'({f})' for f in filters)}")
            if order_by:
                params.append(f"$orderby={order_by}")
            return "&".join(params)

        def _fetch_pages(self, url: str) -> Iterator[dict]:
            """Walk a collection's pages, yielding raw JSON dicts (no coercion).

            Thin row-flattening wrapper over :meth:`_fetch_pages_with_links`,
            which handles the pagination strategy (nextlink / keyset / skip /
            auto). The whole collection is drained within this call: under the
            default ``auto`` a server that page-limits below ``$top`` without a
            continuation link is still fully drained (keep seeking until empty).
            """
            for page_rows, _ in self._fetch_pages_with_links(url):
                yield from page_rows

        def _parse_pagination(self, table_options: dict[str, str] | None) -> str:
            """Parse + validate the ``pagination`` table option.

            Defaults to ``auto``: follow ``@odata.nextLink`` while the server
            emits it (identical to ``nextlink`` for spec-compliant servers), but
            fall back to a keyset/skip continuation on any link-less page and keep
            seeking until empty — so a server that silently page-limits a response
            below the requested ``$top`` *without* a continuation link doesn't drop
            the remainder. ``auto`` forces a default ``page_size`` to size its
            requests (including on snapshot scans); a spec-compliant server that
            keeps emitting ``@odata.nextLink`` is followed directly with no extra
            request, while a link-omitting server costs one trailing empty request
            per collection.
            """
            raw = ((table_options or {}).get("pagination") or "auto").strip().lower()
            if raw not in _PAGINATION_MODES:
                raise ValueError(
                    f"Invalid pagination={raw!r}. Expected one of: " f"{sorted(_PAGINATION_MODES)}."
                )
            return raw

        def _fetch_pages_with_links(self, url: str) -> Iterator[tuple[list[dict], str | None]]:
            """Page-aware fetch: yields ``(page_rows, next_url)`` per response,
            where ``next_url`` resumes the next page (``None`` at the end).

            The yielded ``next_url`` is an opaque resume checkpoint — callers
            park it to continue across batches without reconstructing query
            state. What it *is* depends on ``pagination`` (``self._pagination``,
            default ``nextlink``):

            * ``nextlink`` — the server's resolved ``@odata.nextLink`` (its own
              opaque skiptoken). Spec-compliant default.
            * ``keyset`` / ``skip`` / ``auto`` — a connector-built URL (a
              ``(k gt last)`` seek on the ``$orderby`` key set, or ``$top`` +
              ``$skip``), for servers that page-limit a response but omit the
              continuation link. See :meth:`_client_paginate_pages`.

            Under ``auto``, when the server has emitted no ``@odata.nextLink`` the
            walk keeps seeking past a short link-less page until empty, so a server
            that page-limits below ``$top`` while suppressing the continuation link
            is still fully drained.
            """
            mode = getattr(self, "_pagination", "nextlink")
            if mode != "nextlink":
                yield from self._client_paginate_pages(url, mode)
                return
            session = self._get_session()
            next_url: str | None = url
            # No-progress guard: a server that hands back a self-referential or
            # cyclic ``@odata.nextLink`` would loop forever. Stop if the resolved
            # link points back at the URL we just fetched, or if a non-empty page
            # repeats the one before it.
            prev_fp: int | None = None
            while next_url:
                resp, payload = self._fetch_page_payload(session, next_url)
                page_rows = [
                    {k: v for k, v in item.items() if not k.startswith("@odata.")}
                    for item in payload.get("value", [])
                ]
                fp = _pg_page_fingerprint(page_rows)
                if page_rows and prev_fp is not None and fp == prev_fp:
                    _LOG.warning(
                        "pagination=nextlink made no progress on %r: the server "
                        "returned an identical page (cyclic @odata.nextLink). "
                        "Stopping to avoid an infinite loop; some rows may be "
                        "unread.",
                        next_url,
                    )
                    return
                prev_fp = fp
                raw_next = payload.get("@odata.nextLink")
                new_next = self._resolve_next_link(resp.url, raw_next) if raw_next else None
                if new_next is not None and new_next == next_url:
                    _LOG.warning(
                        "pagination=nextlink: server returned a self-referential "
                        "@odata.nextLink for %r; stopping to avoid an infinite loop.",
                        next_url,
                    )
                    yield page_rows, None
                    return
                yield page_rows, new_next
                next_url = new_next

        def _client_paginate_pages(
            self, url: str, mode: str
        ) -> Iterator[tuple[list[dict], str | None]]:
            """Client-driven pagination for servers that don't (always) emit
            ``@odata.nextLink``. Yields ``(page_rows, next_url)`` like
            :meth:`_fetch_pages_with_links`, where ``next_url`` is a
            connector-built resume URL (``None`` at the end):

            * ``keyset`` — seek the next page with a ``(k gt last)`` predicate
              on the ``$orderby`` key set, rebuilt from the original URL each
              page (so a same-collection walk never accumulates seeks). Commits
              to ``$skip`` for the rest of the collection if a boundary value is
              null (no comparable seek).
            * ``skip`` — ``$top`` + ``$skip`` offset paging, continuing from any
              ``$skip`` already on the URL (so a parked checkpoint resumes at
              the right offset).
            * ``auto`` — trust ``@odata.nextLink`` whenever the server emits it;
              when a page arrives with no link, fall back to a keyset (when the
              ``$orderby`` has keys) or skip continuation and keep seeking until an
              empty page — so a server that page-limits below the requested
              ``$top`` while omitting the link is still drained fully.

            Termination (all client-driven modes, ``auto`` included): a continuation
            that returns an **empty** page means done — NOT a short non-empty one.
            A server may page-limit a response below the ``$top`` we request while
            omitting ``@odata.nextLink`` (e.g. ``SUPPRESS_NEXTLINK_WITH_TOP``), so a
            short page is not proof of exhaustion; the walk keeps seeking until
            empty. Cost: one trailing empty request per collection that genuinely
            ends on a short page. ``auto`` still short-circuits to the server's
            ``@odata.nextLink`` whenever one is present, so a spec-compliant server
            never incurs the extra request.

            ``$top`` must be present (callers force a default ``page_size``). A
            no-progress guard stops the walk if a continuation returns a page
            identical to the one it continued from (server ignoring the
            seek/``$skip``) or a self-referential ``@odata.nextLink`` — either
            would otherwise loop forever.
            """
            session = self._get_session()
            top = _pg_parse_top(url)
            order_keys = _pg_orderby_keys(url)
            can_keyset = mode in ("keyset", "auto") and bool(order_keys)
            base_skip = int(_pg_get_query(url, "$skip") or _pg_get_query(url, "%24skip") or 0)
            # Stable base $filter for keyset seeks — recovered from the private
            # __pgbase marker on a resume URL, so each new seek REPLACES the prior
            # one rather than AND-ing onto it across cap-resume batches (which
            # would grow the URL unboundedly). See _pg_keyset_seek_url.
            base_filter = _pg_base_filter(url)
            fetched = 0
            cur_url: str | None = url
            # No-progress guard, shared across all client-driven steps: a server
            # that ignores our seek/$skip (keyset/skip) or hands back a cyclic
            # @odata.nextLink (auto) would loop forever. Stop when a non-empty page
            # repeats the previous one — those rows were already emitted, so the
            # duplicate is dropped rather than re-yielded.
            prev_fp: int | None = None
            # ``auto`` only: did the server emit an @odata.nextLink at any point in
            # this walk? A server either drives pagination via the link or it
            # doesn't — mixing isn't a real pattern. So once we've seen a link, a
            # later page with no link means the collection genuinely ended (stop, no
            # probe). If we've NEVER seen one, a link-less page is ambiguous (could
            # be a server that page-limits below $top while suppressing the link),
            # so auto falls back to the keyset/skip drain like the explicit modes.
            # This keeps spec-compliant nextLink flows free of any extra trailing
            # request while still draining link-omitting servers fully.
            saw_next_link = False
            while cur_url is not None:
                resp, payload = self._fetch_page_payload(session, cur_url)
                page_rows = [
                    {k: v for k, v in item.items() if not k.startswith("@odata.")}
                    for item in payload.get("value", [])
                ]
                fp = _pg_page_fingerprint(page_rows)
                if page_rows and prev_fp is not None and fp == prev_fp:
                    _LOG.warning(
                        "pagination=%s made no progress on %r: an identical page "
                        "came back (server ignoring the seek/$skip, or a cyclic "
                        "@odata.nextLink). Stopping this collection to avoid an "
                        "infinite loop; some rows may be unread. Use "
                        "pagination=nextlink if the server pages correctly.",
                        mode,
                        cur_url,
                    )
                    return
                prev_fp = fp
                fetched += len(page_rows)
                raw_next = payload.get("@odata.nextLink")
                if mode == "auto" and raw_next:
                    # Server is paginating — defer to its link for this step.
                    saw_next_link = True
                    nxt = self._resolve_next_link(resp.url, raw_next)
                    if nxt == cur_url:
                        # Self-referential link (catches the empty-page case the
                        # fingerprint guard skips). Emit this page, then stop.
                        _LOG.warning(
                            "pagination=auto: server returned a self-referential "
                            "@odata.nextLink for %r; stopping to avoid an infinite "
                            "loop.",
                            cur_url,
                        )
                        yield page_rows, None
                        return
                    yield page_rows, nxt
                    cur_url = nxt
                    continue
                if not page_rows:
                    # Empty page ⇒ collection exhausted.
                    yield page_rows, None
                    return
                if top is None:
                    # No $top to drive client paging, so take the one page. (This
                    # branch is only reachable for a caller that didn't size the
                    # request; the modes that need client paging force a $top.)
                    yield page_rows, None
                    return
                if mode == "auto" and saw_next_link and len(page_rows) < top and fetched < top:
                    # The server drove this walk with @odata.nextLink and this SHORT
                    # page carried none, *before* our $top budget was reached — a
                    # spec-compliant pager signalling the genuine end of the
                    # collection. Don't probe further (no trailing request); trust
                    # the absent link.
                    #
                    # The ``fetched < top`` guard is essential: if the chain instead
                    # terminated at exactly the budget (``fetched >= top``), the
                    # absent link may signal $top exhaustion, NOT end-of-collection.
                    # OData ``$top`` is a TOTAL-result limit (§11.2.5.3), and a
                    # server may propagate the remaining budget through its skiptoken
                    # nextLinks — e.g. Northwind: ``$top=1000`` → page 1's link
                    # carries ``$top=500`` → after 1000 rows no further link, though
                    # the collection has more. Trusting the short final page there
                    # silently caps the table at ``$top`` rows. So we fall through to
                    # the keyset/$skip seek below, which resumes past the budget and
                    # drains the rest (each re-budgeted seek ends on a trailing empty
                    # page). A *full* no-link page after we've seen links is likewise
                    # ambiguous and falls through.
                    yield page_rows, None
                    return
                # auto (never saw a link) / keyset / skip: do NOT stop on a short
                # non-empty page — the server's page size may be below the $top we
                # requested while it omits @odata.nextLink (SUPPRESS_NEXTLINK_WITH_TOP
                # servers),
                # so a short page is not proof of exhaustion. Keep seeking until an
                # EMPTY page. ``auto`` already deferred to @odata.nextLink above
                # whenever the server emitted one; reaching here means it didn't, so
                # auto issues the same confirming seek/$skip as keyset/skip (one
                # trailing empty request per genuinely-ended collection). The
                # no-progress guard above bounds a server that ignores the
                # seek/$skip — auto then stops with this page's rows, exactly as the
                # old short-page default did, minus the dropped duplicate.
                if can_keyset:
                    seek = _pg_keyset_filter(order_keys, page_rows[-1])
                    if seek is not None:
                        nxt = _pg_keyset_seek_url(url, base_filter, seek)
                    else:
                        # Null boundary value — no comparable keyset seek;
                        # commit to offset paging for the rest of this walk so
                        # keyset and skip positions can't interleave.
                        can_keyset = False
                        nxt = _pg_set_query(url, "$skip", str(base_skip + fetched))
                else:
                    nxt = _pg_set_query(url, "$skip", str(base_skip + fetched))
                yield page_rows, nxt
                cur_url = nxt

        def _resolve_next_link(self, request_url: str, raw_next: str) -> str:
            """Resolve an ``@odata.nextLink`` against the request URL.

            Absolute links, root-absolute links (leading ``/``) and bare
            query references (``?...``) all resolve correctly with a plain
            ``urljoin`` against the request URL. The trap is a **relative
            path** nextLink on a contained-collection request: some servers
            (Hexagon SCApi, SAP Gateway, …) return it relative to the
            **service root** — ``Top(key)/Child(key)/Leaf?$skiptoken=...`` —
            rather than the current resource. Naively ``urljoin``-ing that
            against the deep request URL **duplicates the ancestor path**
            (``.../Leaf/Top(key)/Child(key)/Leaf?...``), so the next page
            404s and the read silently stops after page one — only visible
            on multi-page collections such as a full contained snapshot.

            Detect that form — the relative link restates the entity set
            that immediately follows the service root in the request URL —
            and resolve it against the service root instead. Genuinely
            resource-relative links (e.g. flat ``Customers?$skiptoken=...``
            or leaf-only ``Leaf?$skiptoken=...``) fall through to the
            standard request-URL resolution.
            """
            parsed = urlparse(raw_next)
            if parsed.scheme or raw_next.startswith("/") or raw_next.startswith("?"):
                return urljoin(request_url, raw_next)

            def _first_seg(path: str) -> str:
                seg = path.lstrip("/").split("/", 1)[0]
                # Strip any key predicate and query so ``Top(key)?x`` → ``Top``.
                return seg.split("(", 1)[0].split("?", 1)[0]

            root = self.service_url if self.service_url.endswith("/") else self.service_url + "/"
            root_path = urlparse(root).path
            req_path = urlparse(request_url).path
            after_root = req_path[len(root_path) :] if req_path.startswith(root_path) else req_path
            if after_root and _first_seg(raw_next) == _first_seg(after_root):
                # Service-root-relative: resolve against the root so the
                # ancestor path isn't doubled.
                return urljoin(root, raw_next)
            return urljoin(request_url, raw_next)

        def _fetch_page_payload(
            self, session: requests.Session, url: str
        ) -> tuple[requests.Response, dict]:
            """GET one page + decode JSON, retrying on truncated/malformed
            response bodies.

            ``_http_get`` already retries on transport-layer transients
            (TCP reset, timeout, 429/503). Some upstream sources additionally
            emit **200 responses with corrupt JSON bodies** under load —
            observed with Hexagon SCApi, which sometimes truncates response
            bodies mid-serialization for large contained-collection
            responses. Each outer attempt issues a fresh ``_http_get``, so
            the retry composes cleanly with the transport-layer retries
            already inside ``_http_get``. After ``max_retries`` exhausted
            JSON decode attempts, raises the enriched JSONDecodeError with
            the URL + truncated body in the message so the operator can
            escalate to the upstream owner.
            """
            # Drop the connector-private keyset base marker before it can reach
            # the server (it only exists to carry the stable base $filter across
            # cap-resume batches; see _pg_keyset_seek_url).
            url = _pg_strip_query(url, "__pgbase")
            attempts = self.max_retries + 1
            for attempt in range(attempts):
                resp = self._http_get(session, url)
                _raise_for_status_with_body(resp, url)
                try:
                    return resp, _decode_json_with_body(resp, url)
                except json.JSONDecodeError as exc:
                    if attempt >= self.max_retries:
                        _LOG.error(
                            "OData JSON decode failed after %d attempts on GET %s — %s",
                            attempt + 1,
                            url,
                            exc.msg,
                        )
                        raise
                    _LOG.warning(
                        "OData JSON decode failed on GET %s (%s) — retrying (%d/%d)",
                        url,
                        exc.msg,
                        attempt + 1,
                        self.max_retries,
                    )
                    time.sleep(self._backoff_delay(attempt))
            # Defensive: the loop above always returns or raises.
            raise RuntimeError(  # pragma: no cover
                f"Exhausted retries decoding JSON for {url!r}."
            )

        def _http_get(
            self, session: requests.Session, url: str, method: str = "GET", **kwargs: Any
        ) -> requests.Response:
            """GET (or other ``method``) with auth-aware 401/403 handling + transient-failure retry.

            ``method`` defaults to ``GET``; a ``POST`` (with ``json=``) routes the
            ``$batch`` endpoint through the same throttle/transient/token-refresh
            retry path as every read.

            Outer loop retries on two classes of transient failure, both
            capped by ``retry_max_delay_seconds`` per attempt:

            * **HTTP 429 / 503** — throttling or service unavailable.
              Honours the ``Retry-After`` header when present (integer
              seconds or HTTP-date), otherwise exponential backoff
              (1, 2, 4, 8, 16 s …). After ``max_retries`` attempts, raises
              :class:`RuntimeError` with the last response truncated into
              the message.
            * **Connection-level exceptions** —
              :class:`requests.ConnectionError`,
              :class:`requests.Timeout`,
              :class:`requests.ChunkedEncodingError`. The server didn't
              finish sending an HTTP response (TCP reset, remote disconnect,
              read/connect timeout, half-closed mid-body), so there's no
              ``Retry-After`` to honour — pure exponential backoff. After
              ``max_retries`` attempts, re-raises the original exception
              type with the attempt count appended; ``__cause__`` preserves
              the original traceback for triage.

            Inner per-attempt logic (see ``_http_get_once``):

            1. **Pre-emptive token refresh** — when the OAuth ``expires_in``
               clock is past the recorded deadline (60 s safety buffer),
               swap the bearer header *before* sending. Avoids a wasted
               round-trip on long paginated reads straddling an expiry
               boundary.
            2. **Reactive token refresh** — 401 from the source + OAuth
               refresh path is available → mint a fresh token and retry
               once. A second 401 means the access token reached the server
               but the principal lacks access (raise
               :class:`PermissionError` immediately, no further retry).
            3. **Actionable no-refresh-path failure** — 401 or 403 with no
               automatic refresh configured (bearer, basic, api_key, or
               OAuth without a refresh-issuing token endpoint). Raise
               :class:`PermissionError` whose message names the specific
               connection options the operator should check.

            Retries happen between attempts of the inner logic, so a token
            refresh and a throttle backoff compose cleanly: refresh →
            request → 429 → sleep → next attempt's pre-emptive refresh
            check picks up where we left off.
            """
            attempts = self.max_retries + 1
            for attempt in range(attempts):
                try:
                    resp = self._http_get_once(session, url, method=method, **kwargs)
                except _TRANSIENT_NETWORK_ERRORS as exc:
                    # Server closed the TCP connection / DNS failed / read
                    # timed out — no HTTP response, so no Retry-After to
                    # consult. Pure exponential backoff. Preserve the
                    # original exception type so callers that catch
                    # ConnectionError specifically still match.
                    if attempt >= self.max_retries:
                        raise type(exc)(
                            f"{exc} (after {attempt + 1} attempts on {url!r}; "
                            f"raise 'max_retries' on the connection if the "
                            f"source needs more retries)"
                        ) from exc
                    _LOG.warning(
                        "OData transient %s on %s %s — retrying (%d/%d)",
                        type(exc).__name__,
                        method,
                        url,
                        attempt + 1,
                        self.max_retries,
                    )
                    time.sleep(self._backoff_delay(attempt))
                    continue
                if resp.status_code in _RETRYABLE_HTTP_STATUSES:
                    if attempt >= self.max_retries:
                        raise RuntimeError(
                            self._transient_status_exhausted_error(resp, url, attempt + 1)
                        )
                    _LOG.warning(
                        "OData %d on %s %s — retrying (%d/%d)",
                        resp.status_code,
                        method,
                        url,
                        attempt + 1,
                        self.max_retries,
                    )
                    time.sleep(self._retry_after_delay(resp, attempt))
                    continue
                return resp
            # Defensive: the loop always returns or raises before exiting.
            raise RuntimeError(  # pragma: no cover
                f"Exhausted retries for {url!r} without producing a response."
            )

        def _log_http_request(self, method: str, url: str) -> None:
            """Emit a one-line INFO log for the outgoing request when
            ``verbose_http_logging`` is enabled. No-op otherwise so the
            hot path stays free of formatting work."""
            if self.verbose_http_logging:
                _LOG.info("OData %s %s", method, url)

        def _log_http_response(self, method: str, url: str, resp: requests.Response) -> None:
            """Emit a one-line INFO log for the response when
            ``verbose_http_logging`` is enabled. Includes the status code,
            ``Content-Length``, and the first ``verbose_http_log_body_chars``
            chars of the body. **Source data ends up in the log stream**
            when this is on — that's the point — so don't enable it for
            steady-state pipelines."""
            if not self.verbose_http_logging:
                return
            body_snippet = _truncate(resp.text or "", self.verbose_http_log_body_chars)
            _LOG.info(
                "OData %s %s → %d (%s bytes); body: %s",
                method,
                url,
                resp.status_code,
                resp.headers.get("Content-Length", "?"),
                body_snippet or "(empty)",
            )

        def _backoff_delay(self, attempt: int) -> float:
            """Exponential backoff capped at ``retry_max_delay_seconds``.

            Used for transient network failures where the server never
            sent a response, so there's no ``Retry-After`` to honour (the
            429/503 path prefers the server hint via
            ``_retry_after_delay``).
            """
            return min(float(2**attempt), float(self.retry_max_delay_seconds))

        def _http_get_once(
            self, session: requests.Session, url: str, method: str = "GET", **kwargs: Any
        ) -> requests.Response:
            """One auth-aware request attempt; throttle handling lives in `_http_get`."""
            if self._should_preemptively_refresh():
                session.headers["Authorization"] = f"Bearer {self._oauth2_token()}"
            self._log_http_request(method, url)
            resp = session.request(method, url, timeout=self.timeout, **kwargs)
            self._log_http_response(method, url, resp)
            if resp.status_code == 401 and self._has_oauth_refresh_path():
                session.headers["Authorization"] = f"Bearer {self._oauth2_token()}"
                self._log_http_request(method, url)
                resp = session.request(method, url, timeout=self.timeout, **kwargs)
                self._log_http_response(method, url, resp)
                if resp.status_code == 401:
                    # We just minted a token straight from the OAuth provider
                    # and the source still rejected it — the access token isn't
                    # the problem. Most likely the principal lacks read access
                    # to this entity set, the scope is insufficient, or the
                    # tenant is mis-mapped. Surface that explicitly so the user
                    # doesn't chase a non-existent token issue.
                    raise PermissionError(
                        f"OData service returned 401 for {url!r} even after "
                        f"refreshing the OAuth2 access token. The new token "
                        f"reached the server, so the access token itself is "
                        f"not the problem. Check that the OAuth principal has "
                        f"read access to this entity set, that 'oauth2_scope' "
                        f"grants the right permissions, and that any "
                        f"tenant/instance identifier in 'service_url' or "
                        f"'extra_headers' matches the credentials. Server "
                        f"response: {_truncate(resp.text, 300)}"
                    )
                return resp
            if resp.status_code in (401, 403):
                raise PermissionError(self._no_refresh_auth_error(resp, url))
            return resp

        def _retry_after_delay(self, resp: requests.Response, attempt: int) -> float:
            """Pick the sleep duration before the next retry.

            Priority:
              1. ``Retry-After`` header — integer seconds or HTTP-date.
              2. Exponential backoff: ``2**attempt`` seconds (1, 2, 4, 8,
                 16 …).

            Either way the value is capped at ``retry_max_delay_seconds``.
            """
            cap = float(self.retry_max_delay_seconds)
            header = resp.headers.get("Retry-After")
            if header is not None:
                parsed = _parse_retry_after(header)
                if parsed is not None:
                    return min(parsed, cap)
            return min(float(2**attempt), cap)

        def _transient_status_exhausted_error(
            self, resp: requests.Response, url: str, attempts: int
        ) -> str:
            """Message for the post-retry-budget RuntimeError when the
            server kept returning a retryable 4xx/5xx
            (``_RETRYABLE_HTTP_STATUSES``)."""
            status = resp.status_code
            retry_after = resp.headers.get("Retry-After", "<none>")
            if status in (429, 503):
                symptom = "server is throttling or temporarily unavailable"
            elif status == 500:
                symptom = (
                    "server returned an internal error on every attempt — likely a "
                    "request shape the source can't handle (e.g. ``$top`` above its "
                    "per-page cap) or a deterministic upstream bug; check the "
                    "response body and lower ``page_size`` / narrow the request "
                    "before retrying"
                )
            else:  # 502, 504
                symptom = "upstream gateway returned a transient error on every attempt"
            return (
                f"OData service returned {status} for {url!r} after "
                f"{attempts} attempts ({symptom}). Last Retry-After header: "
                f"{retry_after}. Raise 'max_retries' (current: {self.max_retries}) "
                f"or 'retry_max_delay_seconds' (current: "
                f"{self.retry_max_delay_seconds}) on the connection if the source "
                f"needs longer cooldowns; reduce read concurrency via the "
                f"per-table 'num_partitions' option if the failure is "
                f"concurrency-driven. Server response: {_truncate(resp.text, 300)}"
            )

        def _no_refresh_auth_error(self, resp: requests.Response, url: str) -> str:
            """Construct an actionable auth-failure message for the no-refresh path.

            Different auth modes have very different failure modes — bearer
            tokens expire, OAuth scopes can be too narrow, basic creds rot —
            and bundling them all into one generic "401 Unauthorized" makes
            triage from a pipeline log nearly impossible. This method picks
            the relevant remediation hints based on which auth mode is
            active on the connection.
            """
            status = resp.status_code
            body = _truncate(resp.text, 300) or "(empty body)"
            auth = (self.options.get("auth_type") or "").lower().strip()
            if not auth and self.options.get("token"):
                auth = "bearer"
            prefix = (
                f"OData service returned {status} for {url!r} and no "
                f"automatic token-refresh path is configured. "
            )
            if auth == "bearer":
                return (
                    f"{prefix}"
                    f"With auth_type=bearer the pre-acquired access token cannot "
                    f"be refreshed by the connector — either it has expired "
                    f"(typical lifetime ~1 h), or the principal that issued it "
                    f"lacks read access to this entity set. Fixes: replace "
                    f"'token' on the connection with a fresh one; or switch to "
                    f"auth_type=oauth2 with 'oauth2_client_id' + "
                    f"'oauth2_client_secret' so the connector mints and "
                    f"refreshes tokens automatically. For Microsoft Graph "
                    f"high-privilege endpoints (identityProviders, auditLogs, "
                    f"etc.), ensure the token carries the required scope and "
                    f"admin consent. Server response: {body}"
                )
            if auth == "basic":
                return (
                    f"{prefix}"
                    f"With auth_type=basic the credentials are sent on every "
                    f"request unchanged. Check 'username' and 'password' on "
                    f"the connection — the password may have expired or been "
                    f"rotated — and confirm the user has read access to this "
                    f"entity set at the source. Server response: {body}"
                )
            if auth == "api_key":
                return (
                    f"{prefix}"
                    f"With auth_type=api_key the key is sent on every request "
                    f"unchanged. Check 'api_key' (may have been rotated or "
                    f"revoked) and 'api_key_header' (some services expect a "
                    f"non-default header name). Confirm the key's scope "
                    f"includes this entity set. Server response: {body}"
                )
            if auth == "oauth2":
                return (
                    f"{prefix}"
                    f"With auth_type=oauth2 but no refresh path available "
                    f"(missing 'oauth2_client_id' / 'oauth2_client_secret' "
                    f"for client-credentials, and no 'oauth2_refresh_token' "
                    f"for user-flow refresh), the connector can't mint a "
                    f"fresh access token. Provide one of those pairs, or "
                    f"replace 'oauth2_access_token' with a fresh value. "
                    f"Also confirm 'oauth2_scope' grants read on this entity "
                    f"set. Server response: {body}"
                )
            return (
                f"{prefix}"
                f"No authentication is configured on this connection but the "
                f"OData service requires it. Set 'auth_type' to one of: "
                f"bearer, basic, api_key, oauth2 (with the matching parameter "
                f"set). Server response: {body}"
            )

        def _should_preemptively_refresh(self) -> bool:
            """True iff a known-expiry token has hit its 60 s safety window."""
            if self._access_token_expires_at is None:
                return False
            return time.monotonic() >= self._access_token_expires_at

        def _has_oauth_refresh_path(self) -> bool:
            """True iff `_oauth2_token()` can mint a fresh access token.

            Either a refresh token is on hand (user flow) or
            ``oauth2_client_id`` + ``oauth2_client_secret`` are present
            for the client-credentials grant.
            """
            if self.options.get("oauth2_refresh_token"):
                return True
            return bool(
                self.options.get("oauth2_client_id") and self.options.get("oauth2_client_secret")
            )

        # ------------------------------------------------------------------
        # Auth session
        # ------------------------------------------------------------------

        def _get_session(self) -> requests.Session:
            if self._session is not None:
                return self._session

            session = requests.Session()
            session.headers.update(
                {
                    "Accept": "application/json",
                    "OData-Version": "4.0",
                    "OData-MaxVersion": "4.0",
                }
            )
            extra_headers = self.options.get("extra_headers")
            if extra_headers:
                for pair in extra_headers.split(","):
                    if ":" in pair:
                        k, v = pair.split(":", 1)
                        session.headers[k.strip()] = v.strip()

            auth_type = (self.options.get("auth_type") or "").lower().strip()
            if not auth_type and self.options.get("token"):
                auth_type = "bearer"

            if auth_type == "bearer":
                session.headers["Authorization"] = f"Bearer {_require(self.options, 'token')}"
            elif auth_type == "basic":
                session.auth = HTTPBasicAuth(
                    _require(self.options, "username"),
                    _require(self.options, "password"),
                )
            elif auth_type == "api_key":
                header = self.options.get("api_key_header", "x-api-key")
                session.headers[header] = _require(self.options, "api_key")
            elif auth_type == "oauth2":
                # Two sub-modes share this branch:
                #  * **User flow** — `oauth2_refresh_token` is set. A
                #    pre-supplied `oauth2_access_token` is used as-is if
                #    present (avoids an unnecessary round-trip); otherwise
                #    `_oauth2_token()` runs the refresh-token grant to
                #    mint one. Expired tokens mid-run are caught in
                #    `_http_get` and refreshed once.
                #  * **Client-credentials flow** — no refresh token; the
                #    connector mints a fresh access token via
                #    `client_credentials` at session start.
                initial_token = self.options.get("oauth2_access_token") or self._oauth2_token()
                session.headers["Authorization"] = f"Bearer {initial_token}"
            elif auth_type:
                raise ValueError(
                    f"Unknown auth_type {auth_type!r}. "
                    f"Expected one of: bearer, basic, api_key, oauth2."
                )

            self._session = session
            return session

        def _oauth2_token(self) -> str:
            """Mint an OAuth2 access token.

            Picks the grant type from what's available in `self.options`:
              * `oauth2_refresh_token` present -> `refresh_token` grant
                (user-flow refresh). Client id/secret are required so the
                token endpoint can authenticate the client.
              * Otherwise -> `client_credentials` grant (server-to-server).

            Some providers issue a rotated refresh token in the response;
            when that happens, the new value is written back into
            `self.options` so the next refresh uses it.
            """
            refresh_token = self.options.get("oauth2_refresh_token")
            if refresh_token:
                data = {
                    "grant_type": "refresh_token",
                    "refresh_token": refresh_token,
                    "client_id": _require(self.options, "oauth2_client_id"),
                    "client_secret": _require(self.options, "oauth2_client_secret"),
                }
            else:
                data = {
                    "grant_type": "client_credentials",
                    "client_id": _require(self.options, "oauth2_client_id"),
                    "client_secret": _require(self.options, "oauth2_client_secret"),
                }
            scope = self.options.get("oauth2_scope")
            if scope:
                data["scope"] = scope
            token_url = _require(self.options, "oauth2_token_url")
            resp = requests.post(
                token_url,
                data=data,
                timeout=self.timeout,
            )
            # Surface a precise, actionable error when the token endpoint
            # itself rejects the request. raise_for_status() would otherwise
            # produce a terse "401 Client Error: Unauthorized for url ..."
            # that doesn't tell the user *which* credential is the problem.
            if resp.status_code in (400, 401):
                grant = data["grant_type"]
                hint = _extract_oauth_error_hint(resp)
                if grant == "refresh_token":
                    raise ValueError(
                        f"OAuth2 token endpoint returned {resp.status_code} when "
                        f"refreshing the access token. The refresh token may be "
                        f"expired, revoked, or paired with a different OAuth "
                        f"client. Check that 'oauth2_refresh_token' was issued by "
                        f"the same 'oauth2_client_id' configured on this "
                        f"connection, and re-run the authorization-code flow if "
                        f"needed. Server response: {hint}"
                    ) from None
                raise ValueError(
                    f"OAuth2 token endpoint returned {resp.status_code} for the "
                    f"client_credentials grant. Check 'oauth2_client_id', "
                    f"'oauth2_client_secret', 'oauth2_token_url', and "
                    f"'oauth2_scope' on this connection. Server response: {hint}"
                ) from None
            resp.raise_for_status()
            payload = _decode_json_with_body(resp, token_url)
            token = payload.get("access_token")
            if not token:
                raise RuntimeError("OAuth2 token endpoint did not return access_token.")
            rotated_refresh = payload.get("refresh_token")
            if rotated_refresh:
                self.options["oauth2_refresh_token"] = rotated_refresh
            # Track wall-clock deadline so `_http_get` can refresh the token
            # *before* the source returns 401. Subtract a 60 s safety margin
            # to cover clock skew + in-flight request latency. Absent
            # `expires_in` means the provider didn't tell us — fall back to
            # the lazy 401-retry path.
            expires_in = payload.get("expires_in")
            if expires_in is not None:
                try:
                    self._access_token_expires_at = time.monotonic() + int(expires_in) - 60
                except (TypeError, ValueError):
                    self._access_token_expires_at = None
            else:
                self._access_token_expires_at = None
            return token

        # ------------------------------------------------------------------
        # $metadata caching + parsing
        # ------------------------------------------------------------------

        def _metadata_root(self) -> ET.Element:
            """Convenience accessor — returns the parsed root from the
            cached bundle. Most callers want lookups against the index;
            reach for ``self._metadata_state()`` directly when so."""
            return self._metadata_state().root

        def _metadata_state(self) -> _MetadataState:
            """Return the bundled parsed-CSDL state for this instance,
            fetching + parsing + indexing on first call only.

            Four cache layers, checked in order:

            1. Instance ``self._metadata`` — re-used across every downstream
               lookup; the per-instance memos hang off this bundle so all
               the lookup methods see the same cached root + index.
            2. Module ``_METADATA_CACHE`` keyed by ``service_url`` — shared
               across all connector instances in the same Python process.
               Stores ``(xml_text, root, index)`` so the index isn't
               rebuilt per instance either.
            3. On-disk pickle at ``_metadata_cache_path(service_url)`` —
               shared across forked ``pyspark.daemon`` workers (PySpark
               forks one per ``.load()`` schema inference). The pickle
               stores ``(xml_text, root)``; each fork rebuilds the index
               from the unpickled root (one tree walk, ~50 ms).
            4. Network — the actual ``GET $metadata``, taken only when no
               cache has it.
            """
            if self._metadata is not None:
                return self._metadata
            cached = _METADATA_CACHE.get(self.service_url)
            if cached is not None:
                xml_text, root, index = cached
                self._metadata = _MetadataState(root=root, index=index)
                # ``xml_text`` is only needed for the write path; once
                # cached, we don't carry it on the bundle.
                del xml_text
                return self._metadata
            file_cached = self._read_metadata_file_cache()
            if file_cached is not None:
                xml_text, root = file_cached
                index = _build_csdl_index(root)
                self._metadata = _MetadataState(root=root, index=index)
                _METADATA_CACHE[self.service_url] = (xml_text, root, index)
                return self._metadata
            session = self._get_session()
            url = _join_url(self.service_url, "$metadata")
            resp = self._http_get(session, url, headers={"Accept": "application/xml"})
            _raise_for_status_with_body(resp, url)
            xml_text = resp.text
            root = ET.fromstring(xml_text)
            index = _build_csdl_index(root)
            self._metadata = _MetadataState(root=root, index=index)
            _METADATA_CACHE[self.service_url] = (xml_text, root, index)
            self._write_metadata_file_cache(xml_text, root)
            return self._metadata

        def _read_metadata_file_cache(self) -> tuple[str, ET.Element] | None:
            """Return the cached ``(xml_text, parsed_root)`` from the
            on-disk pickle if it exists and is within the TTL. Returns
            ``None`` for any miss (missing, expired, unreadable,
            unpicklable). All failures are silent — the caller falls
            through to the network."""
            if self.metadata_cache_ttl_seconds <= 0:
                return None
            path = _metadata_cache_path(self.service_url)
            try:
                mtime = os.path.getmtime(path)
            except OSError:
                return None
            if time.time() - mtime > self.metadata_cache_ttl_seconds:
                return None
            try:
                with open(path, "rb") as fh:
                    payload = pickle.load(fh)
            except (OSError, pickle.UnpicklingError, EOFError, ValueError):
                return None
            # Defensive shape check — a corrupt or wrong-shape pickle
            # shouldn't crash the connector.
            if (
                not isinstance(payload, tuple)
                or len(payload) != 2
                or not isinstance(payload[0], str)
                or not isinstance(payload[1], ET.Element)
            ):
                return None
            return payload

        def _write_metadata_file_cache(self, xml_text: str, root: ET.Element) -> None:
            """Best-effort write of ``(xml_text, parsed_root)`` to the
            on-disk pickle. Uses atomic rename so a concurrent reader
            either sees the old file or the fully-written new one, never
            a torn write."""
            if self.metadata_cache_ttl_seconds <= 0:
                return
            path = _metadata_cache_path(self.service_url)
            tmp_path = f"{path}.{os.getpid()}.tmp"
            try:
                with open(tmp_path, "wb") as fh:
                    pickle.dump((xml_text, root), fh, protocol=pickle.HIGHEST_PROTOCOL)
                os.replace(tmp_path, path)
            except (OSError, pickle.PicklingError):
                # File cache is purely an optimization. If anything goes
                # wrong (read-only tempdir, disk full, pickling failure)
                # the connector still works — just slower.
                try:
                    os.remove(tmp_path)
                except OSError:
                    pass

        def _entity_set_index(self) -> list[tuple[str, str]]:
            """All (schema_namespace, entity_set_name) pairs declared in $metadata."""
            return self._metadata_state().index.entity_set_pairs

        def _entity_type_for(self, table_name: str, namespace: str | None = None) -> ET.Element:
            """Resolve flat names or contained paths (segment-by-segment via
            contained nav props on the base-type chain)."""
            state = self._metadata_state()
            cache_key = (table_name, namespace)
            cached = state.entity_type.get(cache_key)
            if cached is not None:
                return cached
            segments = _parse_contained_path(table_name) or [table_name]
            et = self._flat_entity_type_for(segments[0], namespace)
            for idx, child_segment in enumerate(segments[1:], start=1):
                nav_props = self._all_contained_nav_props(et)
                target_ref = next((r for n, r in nav_props if n == child_segment), None)
                if target_ref is None:
                    walked = _CONTAINED_PATH_SEP.join(segments[:idx])
                    raise ValueError(
                        f"{child_segment!r} is not a contained-collection navigation "
                        f"property on {walked!r}. Available contained collections: "
                        f"{sorted(n for n, _ in nav_props)}"
                    )
                target_et = self._resolve_type_ref(target_ref)
                if target_et is None:
                    raise ValueError(
                        f"Contained navigation target {target_ref!r} (referenced by "
                        f"{child_segment!r} on {segments[idx - 1]!r}) not found in $metadata."
                    )
                et = target_et
            state.entity_type[cache_key] = et
            return et

        def _flat_entity_type_for(self, table_name: str, namespace: str | None = None) -> ET.Element:
            """Resolve a top-level entity-set name to its EntityType element."""
            index = self._metadata_state().index
            candidates = index.entity_set_by_name.get(table_name) or []
            if namespace is not None:
                matches = [(ns, ref) for ns, ref in candidates if ns == namespace]
            else:
                matches = list(candidates)
            if not matches:
                if namespace is not None:
                    hint = sorted(index.entity_set_names_by_ns.get(namespace, []))
                    if not hint:
                        # The requested namespace has zero entity sets — common
                        # confusion when the user picks a type-only schema
                        # (e.g. one declaring BaseType references) instead of
                        # the schema whose <EntityContainer> declares the sets.
                        raise ValueError(
                            f"Entity set {table_name!r} not found in namespace "
                            f"{namespace!r}. Namespace {namespace!r} declares "
                            f"no entity sets (probably a type-only schema). "
                            f"Namespaces with entity sets: {sorted(index.namespaces_with_sets)}."
                        )
                    raise ValueError(
                        f"Entity set {table_name!r} not found in namespace "
                        f"{namespace!r}. Available in this namespace: {hint}"
                    )
                raise ValueError(
                    f"Entity set {table_name!r} not found in $metadata. "
                    f"Available: {sorted({n for _, n in index.entity_set_pairs})}"
                )
            if len(matches) > 1:
                namespaces = sorted({m[0] for m in matches})
                raise ValueError(
                    f"Entity set {table_name!r} is declared in multiple namespaces: "
                    f"{namespaces}. Set 'namespace' in table_options to disambiguate."
                )
            schema_ns, type_ref = matches[0]
            et = self._resolve_type_ref(type_ref)
            if et is None:
                raise ValueError(
                    f"EntityType {type_ref!r} (referenced by entity set "
                    f"{table_name!r} in schema {schema_ns!r}) not found in $metadata."
                )
            return et

        def _schema_alias_map(self) -> dict[str, str]:
            """``{namespace_or_alias → canonical_namespace}``.

            Kept as a public-shape method so callers reading the source
            for OData spec context still find it; internally it's a
            direct index lookup. CSDL allows each ``<Schema>`` to declare
            both a ``Namespace`` and a shorter ``Alias``; downstream
            ``BaseType`` / ``EntityType`` references can use either.
            Microsoft Graph for instance declares
            ``Namespace="microsoft.graph" Alias="graph"`` and then writes
            ``BaseType="graph.directoryObject"``.
            """
            return self._metadata_state().index.alias_to_namespace

        def _resolve_type_ref(self, type_ref: str) -> ET.Element | None:
            """Find the ``<EntityType>`` element for a qualified type reference.

            Accepts both fully-qualified namespace references
            (``microsoft.graph.user``) and alias-based references
            (``graph.user``). Returns ``None`` if no matching declaration
            exists — callers decide whether that's a hard error or worth
            falling back to a shallower lookup.
            """
            if "." not in type_ref:
                return None
            prefix, type_name = type_ref.rsplit(".", 1)
            index = self._metadata_state().index
            target_ns = index.alias_to_namespace.get(prefix)
            if target_ns is None:
                return None
            return index.entity_type_by_qname.get(f"{target_ns}.{type_name}")

        def _resolve_base_chain(self, et: ET.Element) -> list[ET.Element]:
            """Walk the ``BaseType`` chain starting at ``et``.

            Returns ``[et, parent, grandparent, …]`` until ``BaseType`` is
            absent or unresolvable. OData v4 §8.4: derived entity types
            inherit Keys and Properties from their base. Real-world
            services (Microsoft Graph, Microsoft Dataverse, most SAP
            deployments) lean on this heavily — Graph's ``user`` extends
            ``directoryObject`` extends ``entity``, and ``entity`` is the
            type that actually declares ``<Key>id</Key>``.

            Cycles are guarded against (cyclic CSDL is malformed but won't
            crash the connector).
            """
            state = self._metadata_state()
            cache_key = id(et)
            cached = state.base_chain.get(cache_key)
            if cached is not None:
                return cached
            chain = [et]
            current = et
            seen: set[str] = set()
            while True:
                base_ref = current.get("BaseType")
                if not base_ref or base_ref in seen:
                    break
                seen.add(base_ref)
                parent = self._resolve_type_ref(base_ref)
                if parent is None:
                    break
                chain.append(parent)
                current = parent
            state.base_chain[cache_key] = chain
            return chain

        def _fields_for(self, table_name: str, namespace: str | None = None) -> list[StructField]:
            state = self._metadata_state()
            cache_key = (table_name, namespace)
            cached = state.fields.get(cache_key)
            if cached is not None:
                return cached
            segments = _parse_contained_path(table_name) or [table_name]
            own_fields = self._own_fields_for_et(self._entity_type_for(table_name, namespace))
            if len(segments) == 1:
                state.fields[cache_key] = own_fields
                return own_fields
            # Every non-leaf ancestor contributes FK columns (OData v4
            # §13.4.3 — contained-entity keys are unique within parent only).
            fk_columns = self._resolve_fk_columns(segments, namespace)
            fk_fields: list[StructField] = []
            for idx in range(len(segments) - 1):
                seg = segments[idx]
                if not any(k[0] == seg for k in fk_columns):
                    continue
                ancestor_et = self._entity_type_for(
                    _CONTAINED_PATH_SEP.join(segments[: idx + 1]), namespace
                )
                own = {f.name: f.dataType for f in self._own_fields_for_et(ancestor_et)}
                for pk in self._own_primary_keys_for_et(ancestor_et):
                    fk_fields.append(
                        StructField(
                            fk_columns[(seg, pk)],
                            own.get(pk, StringType()),
                            False,
                        )
                    )
            result = fk_fields + own_fields
            state.fields[cache_key] = result
            return result

        def _own_fields_for_et(self, et: ET.Element) -> list[StructField]:
            """Property fields on ``et`` and its base chain. Walks root → leaf
            so inherited fields appear before leaf's own additions; de-dupes
            by name with closest-to-root winning (spec forbids redeclaration)."""
            state = self._metadata_state()
            cache_key = id(et)
            cached = state.own_fields.get(cache_key)
            if cached is not None:
                return cached
            fields: list[StructField] = []
            seen: set[str] = set()
            for type_el in reversed(self._resolve_base_chain(et)):
                for prop in type_el.findall(f"{_NS_EDM}Property"):
                    name = prop.get("Name")
                    if name in seen:
                        continue
                    seen.add(name)
                    fields.append(
                        StructField(
                            name,
                            _EDM_TO_SPARK.get(prop.get("Type", "Edm.String"), StringType()),
                            prop.get("Nullable", "true").lower() != "false",
                        )
                    )
            state.own_fields[cache_key] = fields
            return fields

        def _primary_keys_for(self, table_name: str, namespace: str | None = None) -> list[str]:
            state = self._metadata_state()
            cache_key = (table_name, namespace)
            cached = state.primary_keys.get(cache_key)
            if cached is not None:
                return cached
            segments = _parse_contained_path(table_name) or [table_name]
            leaf_pks = self._own_primary_keys_for_et(self._entity_type_for(table_name, namespace))
            if len(segments) == 1:
                state.primary_keys[cache_key] = leaf_pks
                return leaf_pks
            # Composite: every ancestor's FK columns + leaf's own PKs.
            fk_columns = self._resolve_fk_columns(segments, namespace)
            composite: list[str] = []
            for idx in range(len(segments) - 1):
                seg = segments[idx]
                if not any(k[0] == seg for k in fk_columns):
                    continue
                ancestor_et = self._entity_type_for(
                    _CONTAINED_PATH_SEP.join(segments[: idx + 1]), namespace
                )
                for pk in self._own_primary_keys_for_et(ancestor_et):
                    composite.append(fk_columns[(seg, pk)])
            composite.extend(leaf_pks)
            state.primary_keys[cache_key] = composite
            return composite

        def _own_primary_keys_for_et(self, et: ET.Element) -> list[str]:
            """Primary-key property names (OData v4 §8.4: derived types inherit
            Keys; closest-to-leaf Key wins where multiple levels redeclare)."""
            state = self._metadata_state()
            cache_key = id(et)
            cached = state.own_pks.get(cache_key)
            if cached is not None:
                return cached
            result: list[str] = []
            for type_el in self._resolve_base_chain(et):
                key = type_el.find(f"{_NS_EDM}Key")
                if key is not None:
                    result = [ref.get("Name") for ref in key.findall(f"{_NS_EDM}PropertyRef")]
                    break
            state.own_pks[cache_key] = result
            return result

        # ------------------------------------------------------------------
        # Cursor filter formatting
        # ------------------------------------------------------------------

        def _cursor_filter(self, cursor_field: str, since: Any) -> str | None:
            """Build the `$filter` clause for an incremental fetch.

            Strict `cursor gt since` once the offset has advanced; `None` on
            the very first call so the server returns the natural start of
            the table. `max_records_per_batch` is the per-call cap — there
            is no wall-clock ceiling, which is what makes continuous polling
            work and what keeps the connector type-agnostic over the cursor
            column.
            """
            if since is None:
                return None
            return f"{cursor_field} gt {_odata_literal(since)}"

        def _cursor_max_end_offset(self, cursors: list, since: Any) -> dict:
            """End offset for a natural-completion cursor batch: ``{"cursor": max}``
            over the batch's effective (non-null) cursor values, falling back to the
            carried ``since`` and then ``{}``.

            Shared by the flat (``_read_incremental``) and contained leaf-cursor
            (``_read_contained_incremental_leaf_cursor``) reads. ``{"cursor": None}``
            must never be committed — it would advance ``{}`` → ``{"cursor": None}``
            on an all-null-cursor batch and then loop the no-progress guard — so a
            null-only batch yields ``since`` (if carried) or ``{}``."""
            if cursors:
                return {"cursor": max(cursors)}
            if since is not None:
                return {"cursor": since}
            return {}

        def _parse_cursor_lookback(self, table_options: dict[str, str] | None):
            """Parse the ``cursor_lookback_seconds`` table option.

            Returns the mode: the string ``"auto"`` (default), or a non-negative
            ``int`` of explicit seconds (``0`` disables the overlap).

            The overlap re-reads a window behind the committed watermark on each
            incremental ``expand_contained=true`` batch, so rows inserted *during*
            a long (non-atomic) walk — which land with a cursor below the walk's
            final max and would otherwise be skipped by ``cursor gt <max>`` — are
            re-scanned and captured on the next progressing batch (deduped at the
            destination by ``apply_changes`` MERGE).

            * ``auto`` (default): size the window from the measured duration of
              the previous completed walk (persisted in the offset), times a
              safety factor, clamped to a ceiling. Self-tuning; no manual guess.
              A no-op outside the expand-cursor path and for non-timestamp
              cursors, so defaulting it on is safe.
            * an explicit integer: a fixed window in cursor units (seconds for a
              timestamp cursor). Set it at or above the worst-case walk duration.
            * ``0`` / ``off``: disabled (exact prior behaviour).
            """
            raw = (table_options or {}).get("cursor_lookback_seconds")
            if raw is None or str(raw).strip() == "":
                return "auto"
            norm = str(raw).strip().lower()
            if norm == "auto":
                return "auto"
            if norm == "off":
                return 0
            try:
                val = int(norm)
            except ValueError as exc:
                raise ValueError(
                    f"Invalid cursor_lookback_seconds={raw!r}; expected 'auto', "
                    f"'off', or a non-negative integer (seconds)."
                ) from exc
            if val < 0:
                raise ValueError(f"cursor_lookback_seconds must be >= 0; got {val}.")
            return val

        def _parse_cursor_lookback_factor(self, table_options: dict[str, str] | None) -> float:
            """Parse ``cursor_lookback_factor`` — the ``auto`` safety multiplier
            applied to the max recent walk duration (default 1.5). Must be > 0;
            values < 1 risk under-covering the overlap (dropped rows)."""
            raw = (table_options or {}).get("cursor_lookback_factor")
            if raw is None or str(raw).strip() == "":
                return _LOOKBACK_AUTO_DEFAULT_FACTOR
            try:
                val = float(str(raw).strip())
            except ValueError as exc:
                raise ValueError(
                    f"Invalid cursor_lookback_factor={raw!r}; expected a positive number."
                ) from exc
            if val <= 0:
                raise ValueError(f"cursor_lookback_factor must be > 0; got {val}.")
            return val

        def _parse_cursor_lookback_ceiling(self, table_options: dict[str, str] | None) -> int:
            """Parse ``cursor_lookback_max_seconds`` — the ``auto`` ceiling clamp
            (runaway backstop) on the overlap window (default 3600). Must be > 0."""
            raw = (table_options or {}).get("cursor_lookback_max_seconds")
            if raw is None or str(raw).strip() == "":
                return _LOOKBACK_AUTO_DEFAULT_CEILING_SECONDS
            try:
                val = int(str(raw).strip())
            except ValueError as exc:
                raise ValueError(
                    f"Invalid cursor_lookback_max_seconds={raw!r}; expected a positive integer."
                ) from exc
            if val <= 0:
                raise ValueError(f"cursor_lookback_max_seconds must be > 0; got {val}.")
            return val

        def _resolve_active_lookback(self, start_offset: dict | None) -> float:
            """Seconds to subtract from the committed watermark for THIS read.

            Static mode → the configured integer. ``auto`` → the **max** walk
            duration over the last ``_LOOKBACK_AUTO_WINDOW`` completed walks
            (``lb_history`` in the offset) × ``cursor_lookback_factor``, clamped
            to ``cursor_lookback_max_seconds``; ``0`` until the first walk has
            been measured. Held on ``self`` for the read so
            ``_apply_cursor_lookback`` can read it without threading the offset
            through ``_cursor_expand_clause``.

            The ``auto`` value keeps **sub-second (down to nanosecond) precision**
            — a fast walk only needs a fast overlap, and the mid-walk-arrival
            window is itself sub-second on a small/fast source, so flooring to
            whole seconds would collapse a 0.3s walk's window to a useless 0 and
            strand rows that landed a few ms below the watermark. ``timedelta`` (in
            ``_apply_cursor_lookback``) accepts the float directly."""
            mode = getattr(self, "_cursor_lookback", "auto")
            if mode != "auto":
                return int(mode)
            history = (start_offset or {}).get("lb_history") or []
            if not history:
                return 0
            factor = getattr(self, "_cursor_lookback_factor", _LOOKBACK_AUTO_DEFAULT_FACTOR)
            ceiling = getattr(
                self, "_cursor_lookback_max_seconds", _LOOKBACK_AUTO_DEFAULT_CEILING_SECONDS
            )
            return min(round(max(history) * factor, 9), ceiling)

        def _attach_lookback_state(
            self, out_offset: dict, start_offset: dict | None, in_flight: bool, elapsed: float
        ) -> dict:
            """Maintain the ``auto`` walk-duration history on the returned offset.
            No-op for static/off modes (nothing to measure).

            ``lb_history`` is a rolling list of the last ``_LOOKBACK_AUTO_WINDOW``
            completed-walk durations (seconds, down to nanosecond precision);
            ``_resolve_active_lookback`` sizes the window from its max.

            * In-flight (the walk spans more cap-resume batches): carry the prior
              history unchanged so the read floor stays stable until completion.
            * Idled (``out_offset is start_offset`` — quiescent overlap re-read):
              keep the prior history; a quiescent walk only re-reads the small
              overlap and would under-represent a real walk.
            * Completed a progressing walk: append this batch's wall-clock
              ``elapsed`` (rounded to nanoseconds, capped to the last N).
              Sub-second walks ARE recorded — on a small/fast source the
              mid-walk-arrival window is itself sub-second, so a sub-second
              overlap is exactly what recovers rows that landed just below the
              committed watermark; the old whole-second rounding floored those to
              a zero window and stranded them. Idle/empty batches never reach
              here (``out_offset is start_offset``), so only real walks are
              captured — never a no-op zero.
            """
            if getattr(self, "_cursor_lookback", "auto") != "auto":
                return out_offset
            if out_offset is start_offset:
                return out_offset
            history = list((start_offset or {}).get("lb_history") or [])
            if not in_flight:
                measured = round(elapsed, 9)
                if measured > 0:
                    history.append(measured)
                    history = history[-_LOOKBACK_AUTO_WINDOW:]
            if not history:
                return out_offset
            return {**out_offset, "lb_history": history}

        def _apply_cursor_lookback(self, since: Any) -> Any:
            """Return the read floor: ``since`` minus the active lookback window.

            Unchanged when the active window is 0 or ``since`` is ``None`` (the
            first read stays unfiltered). For a positive window the cursor must be
            a timestamp — ISO-8601 string or ``datetime``; the result is a
            tz-aware ``datetime`` that ``_odata_literal`` renders to an OData
            timestamp literal, so the server compares datetimes regardless of the
            rendered format. The committed watermark is never floored — only the
            read filter is — so the offset still advances to the true max seen.

            A non-timestamp cursor under ``auto`` is a no-op (auto is the default
            and must not break such tables); under an explicit window it raises."""
            seconds = getattr(self, "_active_lookback_seconds", 0)
            if not seconds or since is None:
                return since
            dt = since
            if isinstance(since, str):
                try:
                    dt = datetime.fromisoformat(since.replace("Z", "+00:00"))
                except ValueError as exc:
                    if getattr(self, "_cursor_lookback", "auto") == "auto":
                        return since
                    raise ValueError(
                        f"cursor_lookback_seconds={seconds} requires a timestamp "
                        f"cursor_field, but the cursor value {since!r} is not "
                        f"ISO-8601. Unset cursor_lookback_seconds or pick a "
                        f"timestamp cursor."
                    ) from exc
            if not isinstance(dt, datetime):
                if getattr(self, "_cursor_lookback", "auto") == "auto":
                    return since
                raise ValueError(
                    f"cursor_lookback_seconds={seconds} requires a datetime/"
                    f"timestamp cursor; got {type(since).__name__} {since!r}."
                )
            # Return the OData timestamp LITERAL (``...Z``), not a datetime: the
            # leaf-cursor walk compares it client-side against the rows' own
            # cursor strings (``rec_cursor <= chain_since``), which would raise on
            # a str-vs-datetime mix. The string renders bare in the URL exactly as
            # the datetime did, so the expand path's wire filter is unchanged.
            return _odata_literal(dt - timedelta(seconds=seconds))

        # ------------------------------------------------------------------
        # Null-cursor policy (``cursor_nulls``)
        # ------------------------------------------------------------------

        _DEFAULT_COALESCE_FLOOR_YEAR = 2000

        def _parse_cursor_nulls(self, table_options: dict[str, str] | None) -> tuple[str, int]:
            """Parse the ``cursor_nulls`` option into ``(mode, floor_year)``.

            Forms: ``coalesce`` (default), ``error``, ``ignore``, and
            ``coalesce:<YYYY>`` to override the temporal synthetic floor year
            (default ``2000``). The year suffix is only valid with
            ``coalesce``. Raises on an unrecognised mode or a malformed year.
            """
            raw = (table_options or {}).get("cursor_nulls", "coalesce").strip().lower()
            mode, _, floor = raw.partition(":")
            mode = mode.strip()
            if mode not in ("coalesce", "error", "ignore"):
                raise ValueError(
                    f"cursor_nulls mode must be one of 'coalesce', 'error', 'ignore'; got {mode!r}."
                )
            floor_year = self._DEFAULT_COALESCE_FLOOR_YEAR
            if floor:
                floor = floor.strip()
                if mode != "coalesce":
                    raise ValueError(
                        f"cursor_nulls floor year is only valid with 'coalesce'; got {raw!r}."
                    )
                if not (floor.isdigit() and len(floor) == 4):
                    raise ValueError(
                        f"cursor_nulls floor must be a 4-digit year (e.g. 'coalesce:1990'); "
                        f"got {floor!r}."
                    )
                floor_year = int(floor)
            return mode, floor_year

        def _cursor_floor(
            self,
            table_name: str,
            namespace: str | None,
            cursor_field: str,
            floor_year: int = _DEFAULT_COALESCE_FLOOR_YEAR,
        ) -> tuple[Any, str]:
            """Deterministic floor used to substitute a null cursor under
            ``cursor_nulls=coalesce``. Returns ``(floor, kind)`` where the
            floor sorts below every real value of the cursor's type, so a
            later ``cursor gt <floor>`` never skips a real row. ``kind`` is
            ``datetime`` (sub-second room for a per-row PK offset), ``date``,
            ``int``, ``num`` or ``str`` (constant floor — distinct synthetic
            values aren't representable, so same-floor nulls fall back to the
            complete-cohort handling).

            Temporal floors use ``<floor_year>-01-01`` (default ``2000``,
            configurable via ``cursor_nulls=coalesce:<YYYY>``) rather than the
            EDM minimum: modification/created timestamps are comfortably after
            it, every OData server parses it cleanly, and it keeps the
            synthetic watermark readable. (A real cursor value *before* the
            floor only matters if a synthetic floor is ever committed as the
            watermark — i.e. a batch with no real-cursor rows — which doesn't
            arise for the modification-timestamp cursors this targets; lower
            the year if your data predates it.)

            Raises ``ValueError`` for cursor types with no well-defined floor
            (boolean/binary/etc.); pick ``cursor_nulls=ignore``/``error`` or a
            different cursor for those.
            """
            et = self._entity_type_for(table_name, namespace)
            dtype = next(
                (f.dataType for f in self._own_fields_for_et(et) if f.name == cursor_field), None
            )
            if isinstance(dtype, TimestampType):
                return f"{floor_year:04d}-01-01T00:00:00", "datetime"
            if isinstance(dtype, DateType):
                return f"{floor_year:04d}-01-01", "date"
            if isinstance(dtype, (IntegerType, LongType)):
                return -(2**63), "int"
            if isinstance(dtype, (DecimalType, DoubleType, FloatType)):
                return -1.0e308, "num"
            if isinstance(dtype, StringType):
                return "", "str"
            raise ValueError(
                f"cursor_nulls=coalesce cannot synthesise a floor for cursor_field "
                f"{cursor_field!r} of type {type(dtype).__name__ if dtype else 'unknown'} "
                f"on {table_name!r}. Use cursor_nulls=ignore (skip null-cursor rows), "
                f"cursor_nulls=error, or pick a temporal/numeric/string cursor."
            )

        def _make_cursor_resolver(
            self,
            table_name: str,
            namespace: str | None,
            cursor_field: str,
            table_options: dict[str, str] | None,
        ):
            """Return ``(skip_null, effective)`` for a cursor read.

            ``effective(row)`` is the value used for filtering, the same-cursor
            boundary trim and the watermark — **never** written back into the
            row, so the emitted column keeps its real ``null``:

            * ``coalesce`` (default) — a null cursor resolves to a synthetic
              floor (``datetime`` floors carry a per-PK sub-second offset so
              distinct nulls don't collapse into one cohort). The watermark
              always advances, so null-cursor rows are ingested once on the
              seed pass and the stream converges.
            * ``error`` — ``effective`` is the raw value (``None`` for nulls);
              a null-only batch can't advance the watermark and surfaces the
              shared no-progress ``RuntimeError``.
            * ``ignore`` — ``skip_null`` is True; null-cursor rows are dropped
              (never emitted), so they don't block watermark progress.
            """
            mode, floor_year = self._parse_cursor_nulls(table_options)
            if mode == "ignore":
                return True, (lambda row: row.get(cursor_field))
            if mode == "error":
                return False, (lambda row: row.get(cursor_field))
            try:
                floor, kind = self._cursor_floor(table_name, namespace, cursor_field, floor_year)
            except ValueError:
                # No synthesisable floor for this cursor type. ``coalesce`` is
                # the default, so silently fall back to ``error`` behaviour
                # rather than break a previously-working pipeline — unless the
                # user asked for ``coalesce`` explicitly, in which case the
                # type error is theirs to see.
                if "cursor_nulls" in (table_options or {}):
                    raise
                return False, (lambda row: row.get(cursor_field))
            pk_names = self._own_primary_keys_for_et(self._entity_type_for(table_name, namespace))

            def effective(row: dict) -> Any:
                value = row.get(cursor_field)
                if value is not None:
                    return value
                if kind == "datetime":
                    return f"{floor}.{_synthetic_pk_ordinal(row, pk_names):06d}Z"
                return floor

            return False, effective


    # ---------------------------------------------------------------------------
    # Helpers (module-level, no class state — easier to unit-test)
    # ---------------------------------------------------------------------------


    def _synthetic_pk_ordinal(row: dict, pk_names: list[str]) -> int:
        """Deterministic 0..999999 ordinal from a row's primary key, used to
        spread synthetic datetime floors for null cursors across the
        sub-second range so they don't form one same-cursor cohort. Hash, so
        it's stable across runs and works for any PK type; collisions only
        cost cohort granularity, never correctness (the destination MERGE
        keys on the real PK)."""
        key = "\x1f".join(str(row.get(p)) for p in pk_names) if pk_names else repr(sorted(row.items()))
        return int(hashlib.sha1(key.encode("utf-8")).hexdigest()[:8], 16) % 1_000_000


    def _extract_oauth_error_hint(resp: requests.Response) -> str:
        """Pull the most informative error description out of an OAuth2 response.

        Token endpoints conventionally return JSON with ``error`` (machine code,
        e.g. ``invalid_grant``) and often ``error_description`` (human-readable).
        Fall back to the raw body when the response isn't JSON, and truncate so
        we never dump a 50 KB error page into a user-facing message.
        """
        try:
            payload = resp.json()
        except ValueError:
            return _truncate(resp.text, 300) or "Unauthorized"
        if isinstance(payload, dict):
            description = payload.get("error_description")
            code = payload.get("error")
            if description and code:
                return f"{code}: {description}"
            if description:
                return str(description)
            if code:
                return str(code)
        return _truncate(resp.text, 300) or "Unauthorized"


    def _parse_retry_after(header: str) -> float | None:
        """Parse an HTTP ``Retry-After`` header into seconds.

        Accepts the two formats RFC 7231 §7.1.3 allows:

          * Integer seconds (``"30"``) — most APIs (Microsoft Graph,
            Dataverse, S/4HANA Cloud) emit this.
          * HTTP-date (``"Wed, 21 Oct 2026 07:28:00 GMT"``) — older
            spec-conformant servers.

        Returns ``None`` for anything unparseable; the caller falls back
        to exponential backoff. Past-dated HTTP-dates clamp to 0 (retry
        immediately) rather than returning a negative sleep.
        """
        header = header.strip()
        try:
            seconds = float(header)
        except (TypeError, ValueError):
            seconds = None
        if seconds is not None:
            return max(0.0, seconds)
        try:
            dt = parsedate_to_datetime(header)
        except (TypeError, ValueError):
            return None
        if dt is None:
            return None
        if dt.tzinfo is None:
            dt = dt.replace(tzinfo=timezone.utc)
        delta = (dt - datetime.now(timezone.utc)).total_seconds()
        return max(0.0, delta)


    def _decode_json_with_body(resp: requests.Response, url: str):
        """Like ``resp.json()`` but enrich the error with URL + truncated
        body when the decoder fails.

        The bare ``requests.exceptions.JSONDecodeError`` exposes only the
        Python parser's "Expecting … at line X column Y" message —
        useless for diagnosing a source that returned a truncated or
        non-JSON body (an HTML error page, a partial response under load,
        an upstream proxy intercept, etc.). This wrapper catches the
        decoder error and re-raises with the offending URL and the first
        1000 chars of the body baked into the message, mirroring the
        pattern ``_raise_for_status_with_body`` uses for 4xx/5xx
        responses.

        Preserves the original exception type so any callers catching
        ``JSONDecodeError`` (or its ``requests`` subclass) specifically
        still match.
        """
        try:
            return resp.json()
        except json.JSONDecodeError as exc:
            body = _truncate((resp.text or "").strip(), 1000) or "(empty body)"
            msg = f"{exc.msg} (parsing response for url: {url}). Server response body: {body}"
            raise type(exc)(msg, exc.doc, exc.pos) from exc


    def _raise_for_status_with_body(resp: requests.Response, url: str) -> None:
        """Like ``resp.raise_for_status()`` but include the response body
        in the exception message.

        The bare ``requests.HTTPError`` message is just "400 Client Error:
        Bad Request for url ..." — useless for diagnosing OData services
        that put the actual error reason in the response body (e.g.
        ``{"error": {"message": "Page size 1000 exceeds maximum 500"}}``).
        Without the body, every 4xx from the source is opaque.

        Preserves the original :class:`requests.HTTPError` type so any
        callers catching that class specifically still match. The
        enriched message is what gets shown to operators in pipeline
        logs.
        """
        if resp.status_code < 400:
            return
        # Mirror requests' own format for the leading line so log filters
        # keyed off "<status> Client Error" / "Server Error" keep working.
        reason = resp.reason or ""
        family = "Client Error" if resp.status_code < 500 else "Server Error"
        body = _truncate((resp.text or "").strip(), 1000) or "(empty body)"
        msg = f"{resp.status_code} {family}: {reason} for url: {url}. " f"Server response body: {body}"
        raise requests.HTTPError(msg, response=resp)


    def _truncate(text: str, limit: int) -> str:
        """Cap a string at ``limit`` chars with a trailing ellipsis when clipped."""
        if text is None:
            return ""
        if len(text) <= limit:
            return text
        return text[:limit] + "..."


    def _require(options: dict[str, str], key: str) -> str:
        val = options.get(key)
        if not val:
            raise ValueError(f"Required option {key!r} is missing.")
        return val


    # Re-export base64/binary helper for any downstream caller that wants
    # to materialize Edm.Binary fields into Python bytes prior to Spark.
    def _decode_binary(value: str) -> bytes:
        return base64.b64decode(value)


    _max_or = max_or
    _trim_to_distinct_cursor_boundary = trim_to_distinct_cursor_boundary
    _trim_to_distinct_cursor_boundary = trim_to_distinct_cursor_boundary
    _CONTAINED_PATH_SEP = CONTAINED_PATH_SEP
    _DEFAULT_PAGE_SIZE = DEFAULT_PAGE_SIZE
    _combine_filters = combine_filters
    _join_url = join_url
    _odata_literal = odata_literal
    _parse_contained_path = parse_contained_path
    _resolve_segment_filters = resolve_segment_filters


    ########################################################
    # src/databricks/labs/community_connector/sparkpds/lakeflow_datasource.py
    ########################################################

    LakeflowConnectImpl = ODataLakeflowConnect
    # Constant option or column names
    METADATA_TABLE = "_community_table_metadata"
    NAMESPACES_TABLE = "_community_namespaces"
    TABLES_TABLE = "_community_tables"
    VIRTUAL_TABLES = (METADATA_TABLE, NAMESPACES_TABLE, TABLES_TABLE)
    TABLE_NAME = "tableName"
    TABLE_NAME_LIST = "tableNameList"
    TABLE_CONFIGS = "tableConfigs"
    IS_DELETE_FLOW = "isDeleteFlow"
    NAMESPACE_PREFIX = "namespacePrefix"
    NAMESPACE = "namespace"


    def _decode_list_of_str_option(option_name: str, value: str | None) -> list[str] | None:
        """Decode and validate a JSON-encoded ``list[str]`` Spark option.

        Returns ``None`` if the option is absent; otherwise the parsed list.
        Raises ``ValueError`` with the offending value if the JSON is malformed
        or the decoded value is not a list of strings.
        """
        if value is None:
            return None
        try:
            decoded = json.loads(value)
        except json.JSONDecodeError as e:
            raise ValueError(
                f"option '{option_name}' must be a JSON-encoded list[str]; "
                f"got non-JSON value: {value!r}"
            ) from e
        if not isinstance(decoded, list) or not all(isinstance(s, str) for s in decoded):
            raise ValueError(
                f"option '{option_name}' must be a JSON-encoded list[str]; "
                f"got: {decoded!r}"
            )
        return decoded


    def _decode_dict_option(option_name: str, value: str | None) -> dict:
        """Decode and validate a JSON-encoded ``dict`` Spark option."""
        if value is None:
            return {}
        try:
            decoded = json.loads(value)
        except json.JSONDecodeError as e:
            raise ValueError(
                f"option '{option_name}' must be a JSON-encoded dict; "
                f"got non-JSON value: {value!r}"
            ) from e
        if not isinstance(decoded, dict):
            raise ValueError(
                f"option '{option_name}' must be a JSON-encoded dict; got: {decoded!r}"
            )
        return decoded


    # PySpark's DataSource API requires camelCase method names and inherits
    # semantics from the parent class, so per-method docstrings are redundant.
    # pylint: disable=invalid-name,missing-function-docstring
    class LakeflowStreamReader(SimpleDataSourceStreamReader, SupportsTriggerAvailableNow):
        """
        Implements a data source stream reader for Lakeflow Connect.
        Currently, only the simpleStreamReader is implemented, which uses a
        more generic protocol suitable for most data sources that support
        incremental loading.
        """

        def __init__(
            self,
            options: dict[str, str],
            schema: StructType,
            lakeflow_connect: LakeflowConnect,
        ):
            self.options = options
            self.lakeflow_connect = lakeflow_connect
            self.schema = schema

        def initialOffset(self):
            return {}

        def read(self, start: dict) -> (Iterator[tuple], dict):
            is_delete_flow = self.options.get(IS_DELETE_FLOW) == "true"
            # Strip delete flow options before passing to connector
            table_options = {
                k: v for k, v in self.options.items() if k != IS_DELETE_FLOW
            }

            if is_delete_flow:
                records, offset = self.lakeflow_connect.read_table_deletes(
                    self.options[TABLE_NAME], start, table_options
                )
            else:
                records, offset = self.lakeflow_connect.read_table(
                    self.options[TABLE_NAME], start, table_options
                )
            rows = map(lambda x: parse_value(x, self.schema), records)
            return rows, offset

        def readBetweenOffsets(self, start: dict, end: dict) -> Iterator[tuple]:
            # TODO: This does not ensure the records returned are identical across repeated calls.
            # For append-only tables, the data source must guarantee that reading from the same
            # start offset will always yield the same set of records.
            # For tables ingested as incremental CDC, it is only necessary that no new changes
            # are missed in the returned records.
            return self.read(start)[0]

        def prepareForTriggerAvailableNow(self) -> None:
            # No need to do anything special here. Everything is handled in the __init__ method.
            pass


    class LakeflowPartitionedStreamReader(DataSourceStreamReader, SupportsTriggerAvailableNow):
        """Proxy that bridges SupportsPartitionedStream to PySpark's DataSourceStreamReader.

        Used when a connector implements the SupportsPartitionedStream mixin to
        support partitioned streaming reads across Spark executors.
        """

        def __init__(
            self,
            options: dict[str, str],
            schema: StructType,
            lakeflow_connect: LakeflowConnect,
        ):
            self.options = options
            self.schema = schema
            self.lakeflow_connect = lakeflow_connect
            self.table_name = options[TABLE_NAME]
            self.table_options = {k: v for k, v in options.items() if k != IS_DELETE_FLOW}

        def initialOffset(self):
            return {}

        def getDefaultReadLimit(self):
            # Admission control is the connector's responsibility (e.g. via
            # window_days, max_records_per_batch), not the engine's.  Always
            # ask the engine for ReadAllAvailable.
            return ReadAllAvailable()

        def latestOffset(self, start: dict, limit) -> dict:
            # We declared ReadAllAvailable via getDefaultReadLimit; the engine
            # must respect it.  Anything else means admission-control expectations
            # we do not support — fail loudly rather than silently ignore.
            if not isinstance(limit, ReadAllAvailable):
                raise ValueError(
                    f"LakeflowPartitionedStreamReader only supports ReadAllAvailable; "
                    f"got {type(limit).__name__}. Micro-batch sizing must be controlled "
                    f"by the connector implementation (table_options), not the engine."
                )
            return self.lakeflow_connect.latest_offset(
                self.table_name, self.table_options, start
            )

        def partitions(self, start: dict, end: dict):
            partition_descs = self.lakeflow_connect.get_partitions(
                self.table_name, self.table_options, start, end
            )
            return [InputPartition(json.dumps(p)) for p in partition_descs]

        def read(self, partition: InputPartition):
            partition_desc = json.loads(partition.value)
            records = self.lakeflow_connect.read_partition(
                self.table_name, partition_desc, self.table_options
            )
            return map(lambda x: parse_value(x, self.schema), records)

        def prepareForTriggerAvailableNow(self) -> None:
            # No need to do anything special here. Everything is handled in the __init__ method.
            pass


    class LakeflowBatchReader(DataSourceReader):
        def __init__(
            self,
            options: dict[str, str],
            schema: StructType,
            lakeflow_connect: LakeflowConnect,
        ):
            self.options = options
            self.schema = schema
            self.lakeflow_connect = lakeflow_connect
            self.table_name = options[TABLE_NAME]
            self._supports_partition = isinstance(lakeflow_connect, SupportsPartition)

        def partitions(self):
            if self._supports_partition and self.table_name not in VIRTUAL_TABLES:
                try:
                    partition_descs = self.lakeflow_connect.get_partitions(
                        self.table_name, self.options
                    )
                    return [InputPartition(json.dumps(p)) for p in partition_descs]
                except Exception:
                    self._supports_partition = False
            return [InputPartition(None)]

        def read(self, partition):
            if self.table_name == METADATA_TABLE:
                records = self._read_table_metadata()
            elif self.table_name == NAMESPACES_TABLE:
                records = self._read_namespaces()
            elif self.table_name == TABLES_TABLE:
                records = self._read_tables()
            elif self._supports_partition and partition.value is not None:
                partition_desc = json.loads(partition.value)
                records = self.lakeflow_connect.read_partition(
                    self.table_name, partition_desc, self.options
                )
            else:
                records, _ = self.lakeflow_connect.read_table(self.table_name, None, self.options)
            return map(lambda x: parse_value(x, self.schema), records)

        def _read_table_metadata(self):
            table_names = _decode_list_of_str_option(
                TABLE_NAME_LIST, self.options.get(TABLE_NAME_LIST)
            ) or []
            table_configs = _decode_dict_option(
                TABLE_CONFIGS, self.options.get(TABLE_CONFIGS)
            )
            all_records = []
            # Preserve caller-supplied table order — caller controls it.
            for table in table_names:
                metadata = self.lakeflow_connect.read_table_metadata(
                    table, table_configs.get(table, {})
                )
                all_records.append({TABLE_NAME: table, **metadata})
            return all_records

        def _read_namespaces(self):
            # Connectors without SupportsNamespaces are flat — no rows.
            if not isinstance(self.lakeflow_connect, SupportsNamespaces):
                return []
            prefix = _decode_list_of_str_option(
                NAMESPACE_PREFIX, self.options.get(NAMESPACE_PREFIX)
            )
            namespaces = self.lakeflow_connect.list_namespaces(prefix)
            # Sort framework-side for deterministic output regardless of
            # connector iteration order.
            return [{"namespace": ns} for ns in sorted(namespaces)]

        def _read_tables(self):
            namespace_supplied = NAMESPACE in self.options
            if isinstance(self.lakeflow_connect, SupportsNamespaces):
                if not namespace_supplied:
                    raise ValueError(
                        f"option '{NAMESPACE}' is required when reading "
                        f"'{TABLES_TABLE}' against a connector that implements "
                        f"SupportsNamespaces. Pass a JSON-encoded list[str] "
                        f"(use '[]' for root-level tables; walk the tree via "
                        f"'{NAMESPACES_TABLE}' to enumerate every namespace)."
                    )
                namespace = _decode_list_of_str_option(
                    NAMESPACE, self.options[NAMESPACE]
                )
                tables = self.lakeflow_connect.list_tables_in_namespace(namespace)
                return [
                    {"namespace": namespace, TABLE_NAME: tn}
                    for tn in sorted(tables)
                ]
            # Flat connector path. Reject a stray `namespace` option — the
            # caller probably mistook this connector for namespace-aware and
            # silently ignoring the option would mask the bug.
            if namespace_supplied:
                raise ValueError(
                    f"option '{NAMESPACE}' was supplied but the connector does "
                    f"not implement SupportsNamespaces. Either omit the option "
                    f"or use a namespace-aware connector."
                )
            return [
                {"namespace": [], TABLE_NAME: tn}
                for tn in sorted(self.lakeflow_connect.list_tables())
            ]


    class LakeflowSource(DataSource):
        """
        PySpark DataSource base for Lakeflow Connect.

        Two ways the connector implementation is bound:

        - Per-source subclass (wheel / multi-file deployment): subclass and set
          ``_lakeflow_connect_cls``::

              class GmailDataSource(LakeflowSource):
                  _lakeflow_connect_cls = GmailLakeflowConnect

              spark.dataSource.register(GmailDataSource)

        - Merged single-file deployment (SDP): ``_lakeflow_connect_cls`` is left
          ``None`` and the connector is taken from the module-level
          ``LakeflowConnectImpl`` placeholder, which the merge script substitutes
          with the actual implementation class.
        """

        # Per-source subclasses set this. Left ``None`` on the base so the merged
        # single-file path falls back to the ``LakeflowConnectImpl`` placeholder.
        _lakeflow_connect_cls = None

        # Spark format name. Defaults to "lakeflow_connect" because Unity Catalog
        # connection-option injection looks for that exact string. A per-source
        # subclass may override this with its source name once it no longer relies
        # on UC injection (see the commented override in each source's __init__.py).
        _format_name = "lakeflow_connect"

        def __init__(self, options):
            self.options = options
            table = options.get(TABLE_NAME)
            # Catch typos against the framework's reserved virtual-table namespace
            # early — falling through to the connector with an unknown
            # `_community_*` name yields a confusing per-connector error.
            if table and table.startswith("_community_") and table not in VIRTUAL_TABLES:
                raise ValueError(
                    f"unknown framework virtual table '{table}'. Valid framework "
                    f"virtual tables are: {', '.join(VIRTUAL_TABLES)}. "
                    f"For a regular source table, use a name that does not start "
                    f"with '_community_'."
                )
            # Per-source subclasses bind the implementation via _lakeflow_connect_cls.
            # The merged single-file path leaves it None and relies on the
            # LakeflowConnectImpl placeholder (substituted by the merge script).
            connect_cls = type(self)._lakeflow_connect_cls or LakeflowConnectImpl
            self.lakeflow_connect = connect_cls(options)  # pylint: disable=abstract-class-instantiated

        @classmethod
        def name(cls):
            return cls._format_name

        def schema(self):
            table = self.options[TABLE_NAME]
            if table == METADATA_TABLE:
                return StructType(
                    [
                        StructField(TABLE_NAME, StringType(), False),
                        StructField("primary_keys", ArrayType(StringType()), True),
                        StructField("cursor_field", StringType(), True),
                        StructField("ingestion_type", StringType(), True),
                    ]
                )
            if table == NAMESPACES_TABLE:
                return StructType(
                    [
                        StructField("namespace", ArrayType(StringType()), False),
                    ]
                )
            if table == TABLES_TABLE:
                return StructType(
                    [
                        StructField("namespace", ArrayType(StringType()), False),
                        StructField(TABLE_NAME, StringType(), False),
                    ]
                )
            return self.lakeflow_connect.get_table_schema(table, self.options)

        def reader(self, schema: StructType):
            return LakeflowBatchReader(self.options, schema, self.lakeflow_connect)

        def streamReader(self, schema: StructType):
            # Use the partitioned DataSourceStreamReader when the connector
            # implements SupportsPartitionedStream and the table opts in.
            # Otherwise, delegate to super() which raises PySparkNotImplementedError,
            # causing Spark to fall back to simpleStreamReader().
            if isinstance(self.lakeflow_connect, SupportsPartitionedStream):
                table = self.options[TABLE_NAME]
                if self.lakeflow_connect.is_partitioned(table):
                    return LakeflowPartitionedStreamReader(self.options, schema, self.lakeflow_connect)
            return super().streamReader(schema)

        def simpleStreamReader(self, schema: StructType):
            return LakeflowStreamReader(self.options, schema, self.lakeflow_connect)


    spark.dataSource.register(LakeflowSource)
